export default LoginView;

import React, { useState } from 'react';
import { User, SystemSettings } from '../types';
import { BACKEND_SCRIPT_TEMPLATE } from '../constants';

interface LoginViewProps {
  onLogin: (user: User) => void;
  appScriptUrl: string;
  setAppScriptUrl: (url: string) => void;
  settings: SystemSettings;
}

const LoginView: React.FC<LoginViewProps> = ({ onLogin, appScriptUrl, setAppScriptUrl, settings }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');
  const [showConfig, setShowConfig] = useState(!appScriptUrl); 
  const [showScriptModal, setShowScriptModal] = useState(false);
  const [isRegistering, setIsRegistering] = useState(false);
  const [fullName, setFullName] = useState('');
  const [position, setPosition] = useState('');
  const [isCopying, setIsCopying] = useState(false);
  const [logoError, setLogoError] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!appScriptUrl || !appScriptUrl.startsWith('https://script.google.com')) {
      setError("Please provide a valid Google Apps Script URL.");
      setShowConfig(true);
      return;
    }
    setError('');
    setIsLoading(true);

    try {
      const payload = isRegistering 
        ? { action: 'register_user', username, password, name: fullName, position: position, role: 'SuperAdmin' }
        : { action: 'login', username, password };

      const response = await fetch(appScriptUrl, {
        method: 'POST',
        body: JSON.stringify(payload)
      });

      const result = await response.json();

      if (result.status === 'success') {
          if (isRegistering) {
              setError("System Owner created! Please log in.");
              setIsRegistering(false);
              setFullName('');
              setPosition('');
              setPassword('');
          } else {
              const rawUser = result.user;
              let safeRole: User['role'] = 'Inspector';
              const rawRole = rawUser.role ? String(rawUser.role).trim().toLowerCase() : '';

              if (rawRole === 'superadmin') safeRole = 'SuperAdmin';
              else if (rawRole === 'admin') safeRole = 'Admin';
              else if (rawRole === 'operations') safeRole = 'Operations';
              else if (rawRole === 'maintenance') safeRole = 'Maintenance';
              else if (rawRole === 'secretary') safeRole = 'Secretary';
              else if (rawRole === 'other') safeRole = 'Other';
              else safeRole = 'Inspector';

              onLogin({ ...rawUser, role: safeRole, position: rawUser.position || '' });
          }
      } else if (result.code === 'NO_USERS') {
          setError("New Database detected. Create the System Owner account.");
          setIsRegistering(true);
      } else {
          setError(result.message || "Authentication failed.");
      }

    } catch (err) {
      setError("Connection failed. Ensure the script URL is correct and public.");
    } finally {
      setIsLoading(false); 
    }
  };

  const copyScript = () => {
      navigator.clipboard.writeText(BACKEND_SCRIPT_TEMPLATE);
      setIsCopying(true);
      setTimeout(() => setIsCopying(false), 2000);
  };

  return (
    <div className="min-h-screen w-full bg-white flex flex-col md:flex-row font-sans text-slate-700">

      {/* BRANDING HERO SECTION */}
      <div className="w-full md:w-[40%] lg:w-[35%] bg-emerald-950 p-8 md:p-12 lg:p-16 flex flex-col justify-between relative overflow-hidden shrink-0 border-b md:border-b-0 md:border-r border-emerald-900/50">
        {/* Dynamic Background Accents */}
        <div className="absolute top-0 left-0 w-full h-full pointer-events-none">
            <div className="absolute -top-24 -left-24 w-96 h-96 bg-emerald-700/20 rounded-full blur-[100px]"></div>
            <div className="absolute bottom-10 right-0 w-64 h-64 bg-blue-900/10 rounded-full blur-[80px]"></div>
        </div>

        <div className="relative z-10">
          <div className="bg-white p-3 rounded-2xl inline-block shadow-2xl mb-6 md:mb-10 transform transition-transform hover:rotate-2">
             {settings.companyLogo && !logoError ? (
                <img src={settings.companyLogo} alt="Logo" className="h-10 md:h-14 w-auto object-contain" onError={() => setLogoError(true)} />
             ) : (
                <div className="flex items-center gap-2">
                    <svg className="w-8 h-8 md:w-10 md:h-10 text-emerald-900" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z" />
                    </svg>
                    <span className="font-black text-emerald-950 text-xl tracking-tighter">SAFETYPRO</span>
                </div>
             )}
          </div>

          <h1 className="text-3xl md:text-5xl font-black text-white leading-tight tracking-tighter">
            {settings.companyName || 'SafetyCheck Pro'}
          </h1>
          <p className="text-emerald-400 font-bold mt-2 uppercase tracking-[0.2em] text-[10px] md:text-xs">Professional Fleet Portal</p>
        </div>

        <div className="relative z-10 mt-10 md:mt-0">
          <div className="space-y-4 hidden md:block">
            <div className="flex items-center gap-4 text-emerald-100/60">
              <div className="w-10 h-10 rounded-xl bg-white/5 flex items-center justify-center border border-white/10 shrink-0">
                <svg className="w-5 h-5 text-emerald-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z"></path></svg>
              </div>
              <p className="text-sm font-medium">Compliance-first inspection checklists</p>
            </div>
            <div className="flex items-center gap-4 text-emerald-100/60">
              <div className="w-10 h-10 rounded-xl bg-white/5 flex items-center justify-center border border-white/10 shrink-0">
                <svg className="w-5 h-5 text-emerald-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z"></path></svg>
              </div>
              <p className="text-sm font-medium">Automated cloud data synchronization</p>
            </div>
          </div>

          <div className="mt-8 md:mt-12 pt-8 border-t border-white/10 flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="w-2.5 h-2.5 rounded-full bg-emerald-500 animate-pulse shadow-[0_0_10px_rgba(16,185,129,0.5)]"></div>
              <span className="text-xs text-emerald-100/80 font-bold uppercase tracking-widest">Server: Healthy</span>
            </div>
            <span className="text-[10px] text-emerald-500 font-black">v2.4.7</span>
          </div>
        </div>
      </div>

      {/* FORM INTERACTION AREA */}
      <div className="flex-1 flex flex-col bg-slate-50 relative min-h-0">
        <div className="flex-1 overflow-y-auto px-6 py-12 md:px-12 lg:px-24 flex items-center justify-center">
          <div className="w-full max-w-[440px] animate-fadeIn">

            {/* Maintenance Logic */}
            {settings.maintenanceMode && (
              <div className="mb-10 p-5 rounded-2xl bg-amber-50 border border-amber-200 shadow-sm flex items-start gap-4">
                <div className="bg-amber-100 p-2.5 rounded-xl text-amber-700 shrink-0">
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z"></path></svg>
                </div>
                <div>
                  <h4 className="text-sm font-black text-amber-900 uppercase tracking-tight">System Restricted</h4>
                  <p className="text-xs text-amber-700 font-medium mt-1 leading-relaxed">
                    A maintenance event is active. Only authorized SuperAdmins may proceed with login.
                  </p>
                </div>
              </div>
            )}

            <div className="mb-10 text-center md:text-left">
