export default LoginView;

import React, { useState } from 'react';
import { User, SystemSettings } from '../types';
import { BACKEND_SCRIPT_TEMPLATE } from '../constants';

interface LoginViewProps {
  onLogin: (user: User) => void;
  appScriptUrl: string;
  setAppScriptUrl: (url: string) => void;
  settings: SystemSettings;
}

const LoginView: React.FC<LoginViewProps> = ({ onLogin, appScriptUrl, setAppScriptUrl, settings }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');
  const [showConfig, setShowConfig] = useState(!appScriptUrl); 
  const [showScriptModal, setShowScriptModal] = useState(false);
  const [isRegistering, setIsRegistering] = useState(false);
  const [fullName, setFullName] = useState('');
  const [position, setPosition] = useState('');
  const [isCopying, setIsCopying] = useState(false);
  const [logoError, setLogoError] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!appScriptUrl || !appScriptUrl.startsWith('https://script.google.com')) {
      setError("Please provide a valid Google Apps Script URL.");
      setShowConfig(true);
      return;
    }
    setError('');
    setIsLoading(true);

    try {
      const payload = isRegistering 
        ? { action: 'register_user', username, password, name: fullName, position: position, role: 'SuperAdmin' }
        : { action: 'login', username, password };

      const response = await fetch(appScriptUrl, {
        method: 'POST',
        body: JSON.stringify(payload)
      });

      const result = await response.json();

      if (result.status === 'success') {
          if (isRegistering) {
              setError("System Owner created! Please log in.");
              setIsRegistering(false);
              setFullName('');
              setPosition('');
              setPassword('');
          } else {
              const rawUser = result.user;
              let safeRole: User['role'] = 'Inspector';
              const rawRole = rawUser.role ? String(rawUser.role).trim().toLowerCase() : '';

              if (rawRole === 'superadmin') safeRole = 'SuperAdmin';
              else if (rawRole === 'admin') safeRole = 'Admin';
              else if (rawRole === 'operations') safeRole = 'Operations';
              else if (rawRole === 'maintenance') safeRole = 'Maintenance';
              else if (rawRole === 'secretary') safeRole = 'Secretary';
              else if (rawRole === 'other') safeRole = 'Other';
              else safeRole = 'Inspector';

              onLogin({ ...rawUser, role: safeRole, position: rawUser.position || '' });
          }
      } else if (result.code === 'NO_USERS') {
          setError("New Database detected. Create the System Owner account.");
          setIsRegistering(true);
      } else {
          setError(result.message || "Authentication failed.");
      }

    } catch (err) {
      setError("Connection failed. Ensure the script URL is correct.");
    } finally {
      setIsLoading(false); 
    }
  };

  const copyScript = () => {
      navigator.clipboard.writeText(BACKEND_SCRIPT_TEMPLATE);
      setIsCopying(true);
      setTimeout(() => setIsCopying(false), 2000);
  };

  return (
    <div className="min-h-screen w-full bg-slate-50 flex flex-col md:flex-row font-sans text-slate-700 overflow-x-hidden">

      {/* BRANDING HERO SECTION - Adaptive Layout */}
      <div className="w-full md:w-[35%] lg:w-[30%] bg-emerald-950 p-6 md:p-12 flex flex-col justify-between relative overflow-hidden shrink-0 border-b md:border-b-0 md:border-r border-emerald-900/50">
        {/* Dynamic Background Accents - Positioned to never trigger scroll */}
        <div className="absolute top-0 left-0 w-full h-full pointer-events-none overflow-hidden">
            <div className="absolute -top-12 -left-12 w-64 h-64 bg-emerald-700/10 rounded-full blur-[60px]"></div>
            <div className="absolute bottom-0 right-0 w-48 h-48 bg-blue-900/10 rounded-full blur-[40px]"></div>
        </div>

        <div className="relative z-10 flex md:block items-center justify-between">
          <div className="bg-white p-2.5 rounded-xl inline-block shadow-2xl transform transition-transform hover:rotate-2">
             {settings.companyLogo && !logoError ? (
                <img src={settings.companyLogo} alt="Logo" className="h-8 md:h-12 w-auto object-contain" onError={() => setLogoError(true)} />
             ) : (
                <div className="flex items-center gap-2">
                    <svg className="w-6 h-6 md:w-8 md:h-8 text-emerald-900" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z" />
                    </svg>
                    <span className="font-black text-emerald-950 text-base md:text-lg tracking-tighter">SAFETYPRO</span>
                </div>
             )}
          </div>

          <div className="md:mt-8">
            <h1 className="text-xl md:text-3xl font-black text-white leading-tight tracking-tight">
                {settings.companyName || 'SafetyCheck Pro'}
            </h1>
            <p className="text-emerald-400 font-bold uppercase tracking-widest text-[9px] md:text-[10px]">Fleet Portal Access</p>
          </div>
        </div>

        {/* Feature List - Hidden on mobile to keep form "above the fold" */}
        <div className="relative z-10 mt-10 md:mt-0 hidden md:block">
          <div className="space-y-5">
            <div className="flex items-start gap-3 text-emerald-100/60">
              <div className="w-8 h-8 rounded-lg bg-white/5 flex items-center justify-center border border-white/10 shrink-0">
                <svg className="w-4 h-4 text-emerald-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z"></path></svg>
              </div>
              <p className="text-xs font-medium leading-relaxed">Secure, compliance-verified vehicle checklists</p>
            </div>
          </div>

          <div className="mt-8 pt-6 border-t border-white/10 flex items-center justify-between">
            <div className="flex items-center gap-2">
              <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse shadow-[0_0_8px_rgba(16,185,129,0.5)]"></div>
              <span className="text-[10px] text-emerald-100/60 font-bold uppercase tracking-widest">Network Live</span>
            </div>
            <span className="text-[9px] text-emerald-500 font-black">v2.4.8</span>
          </div>
        </div>
      </div>

      {/* FORM AREA - Clean, Center-Aligned, Fluid */}
      <div className="flex-1 flex flex-col bg-white relative">
        <div className="flex-1 overflow-y-auto px-4 py-8 md:px-12 lg:px-24 flex items-center justify-center">
          <div className="w-full max-w-sm mx-auto animate-fadeIn">

            {/* Maintenance Logic */}
            {settings.maintenanceMode && (
              <div className="mb-6 p-4 rounded-xl bg-amber-50 border border-amber-200 shadow-sm flex items-start gap-3">
                <div className="bg-amber-100 p-2 rounded-lg text-amber-700 shrink-0">
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z"></path></svg>
                </div>
                <div>
                  <h4 className="text-xs font-black text-amber-900 uppercase tracking-tight">System Restricted</h4>
                  <p className="text-[10px] text-amber-700 font-medium mt-0.5 leading-relaxed">
                    Maintenance in progress. SuperAdmin access only.
                  </p>
                </div>
              </div>
            )}

            <div className="mb-8 text-center md:text-left">
              <h2 className="text-3xl font-black text-slate-900 tracking-tight">
                {isRegistering ? 'Setup Owner' : 'Authorize'}
              </h2>
              <p className="text-slate-500 text-sm mt-1 font-medium">
                {isRegistering ? 'Configure your administrative account.' : 'Please sign in to continue.'}
              </p>
            </div>

            {error && (
              <div className={`mb-6 p-4 rounded-xl text-xs font-bold flex items-center gap-3 border animate-fadeIn
                ${error.includes("created") ? 'bg-green-50 text-green-700 border-green-200' : 'bg-red-50 text-red-700 border-red-200'}`}>
                <div className={`w-2.5 h-2.5 rounded-full shrink-0 ${error.includes("created") ? 'bg-green-500' : 'bg-red-500'}`}></div>
                <span className="flex-1 leading-tight">{error}</span>
              </div>
            )}

            <form onSubmit={handleSubmit} className="space-y-5">

              {isRegistering && (
                <div className="space-y-4 animate-fadeIn bg-slate-50 p-5 rounded-2xl border border-slate-100">
                  <div className="flex items-center gap-2 border-b border-slate-200 pb-3 mb-1">
                      <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Master Identity</h3>
                  </div>
                  <div>
                      <label className="block text-[10px] font-black text-slate-400 uppercase mb-1 tracking-widest ml-1">Full Name</label>
                      <input type="text" required className="w-full px-4 py-3 bg-white border border-slate-200 rounded-xl focus:border-emerald-600 focus:ring-4 focus:ring-emerald-600/5 outline-none transition-all text-slate-900 text-base font-bold" value={fullName} onChange={e => setFullName(e.target.value)} placeholder="e.g. John Doe" />
                  </div>
