export default LoginView;

import React, { useState } from 'react';
import { User, SystemSettings } from '../types';
import { BACKEND_SCRIPT_TEMPLATE } from '../constants';

interface LoginViewProps {
  onLogin: (user: User) => void;
  appScriptUrl: string;
  setAppScriptUrl: (url: string) => void;
  settings: SystemSettings;
}

const LoginView: React.FC<LoginViewProps> = ({ onLogin, appScriptUrl, setAppScriptUrl, settings }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');
  const [showConfig, setShowConfig] = useState(!appScriptUrl); 
  const [showScriptModal, setShowScriptModal] = useState(false);
  const [isRegistering, setIsRegistering] = useState(false);
  const [fullName, setFullName] = useState('');
  const [position, setPosition] = useState('');
  const [isCopying, setIsCopying] = useState(false);
  const [logoError, setLogoError] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!appScriptUrl || !appScriptUrl.startsWith('https://script.google.com')) {
      setError("Provide a valid Google Script Link.");
      setShowConfig(true);
      return;
    }
    setError('');
    setIsLoading(true);

    try {
      const payload = isRegistering 
        ? { action: 'register_user', username, password, name: fullName, position: position, role: 'SuperAdmin' }
        : { action: 'login', username, password };

      const response = await fetch(appScriptUrl, {
        method: 'POST',
        body: JSON.stringify(payload)
      });

      const result = await response.json();

      if (result.status === 'success') {
          if (isRegistering) {
              setError("Admin created! Log in below.");
              setIsRegistering(false);
              setFullName('');
              setPosition('');
              setPassword('');
          } else {
              const rawUser = result.user;
              let safeRole: User['role'] = 'Inspector';
              const rawRole = rawUser.role ? String(rawUser.role).trim().toLowerCase() : '';

              if (rawRole === 'superadmin') safeRole = 'SuperAdmin';
              else if (rawRole === 'admin') safeRole = 'Admin';
              else if (rawRole === 'operations') safeRole = 'Operations';
              else if (rawRole === 'maintenance') safeRole = 'Maintenance';
              else if (rawRole === 'secretary') safeRole = 'Secretary';
              else if (rawRole === 'other') safeRole = 'Other';
              else safeRole = 'Inspector';

              onLogin({ ...rawUser, role: safeRole, position: rawUser.position || '' });
          }
      } else if (result.code === 'NO_USERS') {
          setError("No database found. Create the first Admin account.");
          setIsRegistering(true);
      } else {
          setError(result.message || "Login failed.");
      }

    } catch (err) {
      setError("Cannot connect. Check your internet or Script Link.");
    } finally {
      setIsLoading(false); 
    }
  };

  const copyScript = () => {
      navigator.clipboard.writeText(BACKEND_SCRIPT_TEMPLATE);
      setIsCopying(true);
      setTimeout(() => setIsCopying(false), 2000);
  };

  return (
    <div className="min-h-screen w-full bg-slate-50 flex flex-col md:flex-row font-sans text-slate-700 overflow-x-hidden">

      {/* BRANDING HEADER / SIDEBAR */}
      <div className="w-full md:w-[35%] lg:w-[30%] bg-emerald-950 p-6 md:p-12 flex flex-col justify-between relative overflow-hidden shrink-0 border-b md:border-b-0 border-emerald-900">
        <div className="absolute top-0 left-0 w-full h-full pointer-events-none opacity-20">
            <div className="absolute -top-10 -left-10 w-64 h-64 bg-emerald-400 rounded-full blur-[80px]"></div>
        </div>

        <div className="relative z-10 flex md:block items-center justify-between">
          <div className="bg-white p-2 rounded-lg inline-block shadow-lg">
             {settings.companyLogo && !logoError ? (
                <img src={settings.companyLogo} alt="Logo" className="h-8 md:h-12 w-auto object-contain" onError={() => setLogoError(true)} />
             ) : (
                <div className="flex items-center gap-2 px-1">
                    <svg className="w-6 h-6 text-emerald-900" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z" />
                    </svg>
                    <span className="font-black text-emerald-950 text-base md:text-xl tracking-tight">SAFETYPRO</span>
                </div>
             )}
          </div>

          <div className="md:mt-8 text-right md:text-left">
            <h1 className="text-xl md:text-3xl font-black text-white leading-tight">
                {settings.companyName || 'SafetyCheck Pro'}
            </h1>
            <p className="text-emerald-400 font-bold uppercase tracking-widest text-[9px]">Fleet Portal</p>
          </div>
        </div>

        <div className="relative z-10 mt-10 hidden md:block border-t border-white/10 pt-6">
            <div className="flex items-center gap-3">
              <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></div>
              <span className="text-[10px] text-emerald-100/60 font-bold uppercase tracking-widest">System Ready</span>
            </div>
        </div>
      </div>

      {/* LOGIN FORM */}
      <div className="flex-1 flex flex-col bg-white">
        <div className="flex-1 overflow-y-auto px-6 py-8 md:px-12 flex items-center justify-center">
          <div className="w-full max-w-sm mx-auto">

            {settings.maintenanceMode && (
              <div className="mb-6 p-4 rounded-xl bg-amber-50 border border-amber-200 flex items-start gap-3">
                <svg className="w-5 h-5 text-amber-600 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z"></path></svg>
                <p className="text-[11px] text-amber-800 font-bold leading-tight">System Lockdown: Maintenance in progress. Only Admins can log in.</p>
