                  <input 
                    type="password" 
                    required 
                    className="w-full px-4 py-3.5 bg-slate-50 border border-slate-200 rounded-lg focus:bg-white focus:border-emerald-500 outline-none font-light text-base transition-all" 
                    value={password} 
                    onChange={e => setPassword(e.target.value)} 
                    placeholder="••••••••"
                  />
                </div>
              </div>

              <div className="pt-4">
                <button 
                  type="submit" 
                  disabled={isLoading} 
                  className={`w-full py-4 rounded-xl font-bold text-white shadow-lg transition-all text-sm uppercase tracking-widest active:scale-[0.98]
