          </div>
        </div>

        <div className="relative z-10 mt-5 space-y-4">
            {/* SYSTEM STATUS INDICATOR - ULTRA COMPACT & DYNAMIC POSITIONING */}
            <div className="flex items-center gap-2.5 animate-fadeIn">
                <div className={`w-[2px] h-5 rounded-full transition-all duration-500 
                    ${isLoading ? 'bg-blue-400 animate-pulse shadow-[0_0_8px_rgba(96,165,250,0.5)]' : 
                      isUrlValid ? 'bg-emerald-500 shadow-sm' : 
                      'bg-red-500'}`}
                ></div>
                <div className="flex flex-col">
                    <span className={`text-[9px] font-black tracking-wider leading-none uppercase transition-colors 
                        ${isLoading ? 'text-blue-200' : isUrlValid ? 'text-white' : 'text-red-100'}`}
                    >
                        {isLoading ? 'Syncing System' : isUrlValid ? 'System Connected' : 'System Offline'}
                    </span>
                    <span className={`text-[7px] font-bold tracking-[0.1em] mt-1 uppercase transition-colors 
                        ${isLoading ? 'text-blue-400/80' : isUrlValid ? 'text-emerald-500/70' : 'text-red-400/60'}`}
