                            <svg className="w-3.5 h-3.5 text-slate-300 ml-2 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z"></path></svg>
                        )}
                    </div>
                    {subLabel && (
                        <span className={`text-[10px] font-medium leading-none mt-0.5 
                            ${isActive ? 'text-emerald-600/70' : 'text-slate-400 group-hover:text-slate-500'}`}>
                            {subLabel}
                        </span>
                    )}
                </div>
            </button>
        );
    };

