                                    <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4.354a4 4 0 110 5.292M15 21H3v-1a6 6 0 0112 0v1zm0 0h6v-1a6 6 0 00-9-5.197M13 7a4 4 0 11-8 0 4 4 0 018 0z"></path></svg>
                                    Users
                                </button>
                            </>
                        )}
                        <button 
                            onClick={() => { onSelectModule('support'); onClose(); }}
                            className={`flex items-center gap-2 px-2 py-1.5 rounded-md text-[11px] font-medium transition-all col-span-2
                                ${activeModule === 'support' ? 'bg-slate-100 text-slate-900' : 'text-slate-400 hover:bg-slate-50 hover:text-slate-700'}
                            `}
                        >
                            <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M18.364 5.636l-3.536 3.536m0 5.656l3.536 3.536M9.172 9.172L5.636 5.636m3.536 9.192l-3.536 3.536M21 12a9 9 0 11-18 0 9 9 0 0118 0zm-5 0a4 4 0 11-8 0 4 4 0 018 0z"></path></svg>
                            Help & Support
                        </button>
                    </div>

                    {/* Subscription Widget */}
                    {subscription && (
                        <div className="px-3 pb-2">
                            <div className={`flex items-center justify-between px-2.5 py-1.5 rounded-lg border border-slate-50 ${
                                subscription.status === 'Active' ? 'bg-white' : 'bg-red-50/30'
                            }`}>
                                <div className="flex items-center gap-2 min-w-0">
                                    <div className={`w-1 h-1 rounded-full shrink-0 ${subscription.status === 'Active' ? 'bg-emerald-400' : 'bg-red-400'}`} />
                                    <span className="text-[10px] font-medium text-slate-400 uppercase tracking-widest truncate">{subscription.plan}</span>
                                </div>
                                <span className={`text-[10px] font-medium ${subscription.daysRemaining <= 7 ? 'text-amber-500' : 'text-slate-300'}`}>
                                    {subscription.daysRemaining}d
                                </span>
                            </div>
                        </div>
                    )}

                    {/* Improved User Card & Logout */}
                    <div className="p-3 bg-slate-50/30 border-t border-slate-50">
                        <div className="flex items-center gap-3 px-2 py-2">
                            <div className="w-8 h-8 rounded-full bg-emerald-600 flex items-center justify-center text-[10px] font-bold text-white shrink-0">
                                {user?.name ? user.name.substring(0, 2).toUpperCase() : 'U'}
                            </div>
                            <div className="min-w-0 flex-1">
                                <div className="text-[12px] font-light text-slate-900 truncate leading-none">
                                    {user?.name || 'User'}
                                </div>
                                <div className="text-[9px] font-medium text-slate-400 truncate mt-1 uppercase tracking-tighter">
                                    {user?.role || 'Guest'}
                                </div>
                            </div>
                        </div>
                        <button
                            onClick={onLogout}
                            className="w-full mt-1 flex items-center justify-center gap-2 py-2 text-[11px] font-bold text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-all group"
                        >
                            <svg className="w-4 h-4 transition-transform group-hover:-translate-x-0.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H5a3 3-0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1"></path></svg>
                            LOGOUT
                        </button>
                    </div>
                </div>
            </aside>
        </>
    );
};

export default Sidebar;

import React, { useState, useEffect } from 'react';
import { INITIAL_DATA, InspectionData, User } from './types';
import { 
    SHEET_HEADERS, PETROLEUM_HEADERS, PETROLEUM_V2_HEADERS, ACID_HEADERS,
    INSPECTION_ITEMS, PETROLEUM_INSPECTION_ITEMS, PETROLEUM_V2_ITEMS, ACID_INSPECTION_ITEMS
} from './constants';

// Hooks
import { useAuth } from './hooks/useAuth';
import { useSettings } from './hooks/useSettings';
import { useNotifications } from './hooks/useNotifications';
import { useHistory } from './hooks/useHistory';
import { useOfflineSync } from './hooks/useOfflineSync';
import { useSubscription } from './hooks/useSubscription';

// UI Components
import Toast from './components/ui/Toast';
import Sidebar from './components/layout/Sidebar';
import ReportViewerModal from './components/ui/ReportViewerModal';
import SubmissionOverlay from './components/ui/SubmissionOverlay';
import ProfileModal from './components/ui/ProfileModal';
import NotificationCenter from './components/ui/NotificationCenter'; 
import UpgradeModal from './components/ui/UpgradeModal';
import InspectionStartModal from './components/ui/InspectionStartModal';
import SubscriptionAlert from './components/ui/SubscriptionAlert';
import MaintenanceOverlay from './components/ui/MaintenanceOverlay';
import RequestInspectionModal from './components/ui/RequestInspectionModal'; 
import OnboardingWizard from './components/ui/OnboardingWizard'; 
import SystemTour from './components/ui/SystemTour'; 
import InstallPwaPrompt from './components/ui/InstallPwaPrompt';

// Views
import LoginView from './views/LoginView';
import SettingsView from './views/SettingsView';
import GeneralDashboard from './views/GeneralDashboard';
import PetroleumDashboard from './views/PetroleumDashboard';
import PetroleumV2Dashboard from './views/PetroleumV2Dashboard';
import AcidDashboard from './views/AcidDashboard';
import UserManagementView from './views/UserManagementView';
import OverviewDashboard from './views/OverviewDashboard';
import InspectionFormView from './views/InspectionFormView';
import SupportView from './views/SupportView';
import MaintenanceView from './views/MaintenanceView';
import RequestTrackingView from './views/RequestTrackingView';

// Report Components
import PrintableGeneralReport from './components/reports/PrintableGeneralReport';
import PrintablePetroleumReport from './components/reports/PrintablePetroleumReport';
import PrintablePetroleumV2Report from './components/reports/PrintablePetroleumV2Report';
import PrintableAcidReport from './components/reports/PrintableAcidReport';

const App = () => {
  const { currentUser, setCurrentUser, handleLogin, handleLogout, sessionExpired, setSessionExpired } = useAuth();
  const { settings, setSettings, appScriptUrl, setAppScriptUrl, isSavingSettings, handleSaveSettings } = useSettings();
  const { subscription } = useSubscription(appScriptUrl, currentUser);

  const [activeModule, setActiveModule] = useState('overview'); 
  const [viewMode, setViewMode] = useState<'dashboard' | 'form'>('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isProfileModalOpen, setIsProfileModalOpen] = useState(false);
  const [toast, setToast] = useState<{message: string, type: 'success' | 'error' | 'info' | 'warning'} | null>(null);
  const [isRequestModalOpen, setIsRequestModalOpen] = useState(false);

  const { historyList, isLoadingHistory, validationLists, stats, fetchHistory } = useHistory(appScriptUrl, activeModule, currentUser);

  const showToast = (message: string, type: 'success' | 'error' | 'info' | 'warning') => {
      setToast({ message, type });
      setTimeout(() => setToast(null), 4000);
  };

  useEffect(() => {
      if (sessionExpired === 'idle') showToast("Session expired due to inactivity.", 'warning');
      else if (sessionExpired === 'max_duration') showToast("Session limit reached. Log in again.", 'info');
      if (sessionExpired) setSessionExpired(null);
  }, [sessionExpired]);

  const { submissionStatus, setSubmissionStatus, isSyncing } = useOfflineSync(appScriptUrl, showToast, () => fetchHistory(true));
  const { notifications, handleMarkNotificationRead, handleDismissNotification, handleClearAllNotifications } = useNotifications(appScriptUrl, currentUser, showToast);

  const [isReportModalOpen, setIsReportModalOpen] = useState(false);
  const [selectedReportData, setSelectedReportData] = useState<InspectionData | null>(null);
  const [formInitialData, setFormInitialData] = useState<InspectionData>(INITIAL_DATA);

  const isSuperAdmin = currentUser?.role === 'SuperAdmin';
  const showMaintenance = settings.maintenanceMode && currentUser && !isSuperAdmin;

  const startFreshInspection = (module: string, prefill?: Partial<InspectionData>) => {
      setFormInitialData({ ...INITIAL_DATA, timestamp: new Date().toISOString(), inspectedBy: currentUser?.name || '', ...prefill });
      setViewMode('form');
  };

  const handleExitForm = (savedData?: InspectionData) => setViewMode('dashboard');

  const handleGoogleSheetSubmit = async (formData: InspectionData) => {
    setSubmissionStatus('submitting');
    setSubmissionStatus('success');
    setTimeout(() => setViewMode('dashboard'), 2000);
  };

  const handleViewReport = (item: InspectionData | null) => {
    setSelectedReportData(item);
    setIsReportModalOpen(true);
  };

  if (!currentUser) {
      return (
          <>
            <InstallPwaPrompt />
            {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
            <LoginView 
                onLogin={handleLogin} 
                appScriptUrl={appScriptUrl}
                setAppScriptUrl={setAppScriptUrl}
                settings={settings}
            />
          </>
      );
  }

  if (showMaintenance) {
      return (
        <>
           <MaintenanceOverlay isActive={true} message={settings.maintenanceMessage || ''} onLogout={() => handleLogout()} />
           {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
        </>
      );
  }

  return (
    <div className="min-h-screen bg-white font-sans text-gray-900 relative">
      <SubmissionOverlay status={submissionStatus} />
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

      {isProfileModalOpen && (
          <ProfileModal 
            user={currentUser} 
            appScriptUrl={appScriptUrl} 
            onClose={() => setIsProfileModalOpen(false)} 
            showToast={showToast} 
            onUpdateSuccess={(u) => setCurrentUser(u)} 
          />
      )}

      <RequestInspectionModal
          isOpen={isRequestModalOpen}
          onClose={() => setIsRequestModalOpen(false)}
          onSubmit={() => {}}
          validationLists={validationLists}
          currentUserRole={currentUser.role}
      />

      <div className="relative z-10 min-h-screen">
          <Sidebar 
            isOpen={isSidebarOpen} 
            onClose={() => setIsSidebarOpen(false)} 
            activeModule={activeModule}
            onSelectModule={(m) => { setActiveModule(m); setViewMode('dashboard'); }}
            settings={settings}
            user={currentUser}
            onLogout={() => handleLogout()}
            onEditProfile={() => setIsProfileModalOpen(true)}
            subscription={subscription} 
          />

          <div className="lg:pl-64 min-h-screen flex flex-col">
            <SubscriptionAlert subscription={subscription} user={currentUser} onManage={() => setActiveModule('settings')} />

            {/* REFINED HEADER - ALISTAIR STYLE */}
            <header className="bg-white border-b border-gray-100 sticky top-0 z-40 px-4 py-2 flex items-center justify-between h-14">
                <div className="flex items-center gap-2">
                    <button id="sidebar-toggle" onClick={() => setIsSidebarOpen(true)} className="lg:hidden p-2 text-slate-400 hover:text-slate-600 transition-colors">
                        <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M4 6h16M4 12h16M4 18h16"></path></svg>
                    </button>
                    <div className="hidden lg:flex items-center gap-1.5">
                        <button onClick={() => setActiveModule('overview')} title="Inspection History" className="p-1.5 text-indigo-400 hover:text-indigo-600 transition-colors">
                            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
                        </button>
                        <button id="sync-status-btn" onClick={() => fetchHistory(true)} title="Sync System" className={`p-1.5 transition-colors ${isLoadingHistory ? 'text-blue-600 animate-spin' : 'text-blue-400 hover:text-blue-600'}`}>
                             <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15"></path></svg>
                        </button>
                    </div>
                </div>

                <div className="flex flex-col items-center">
                    <h1 className="text-xl font-black text-slate-900 tracking-tighter leading-none uppercase">
                        {settings.companyName || 'ALISTAIR'}
                    </h1>
                    <span className="text-[7px] font-bold text-slate-400 tracking-[0.3em] mt-1 uppercase">Fleet Management</span>
                </div>

                <div className="flex items-center gap-1">
                    <NotificationCenter 
                        notifications={notifications}
                        onMarkAsRead={(id) => handleMarkNotificationRead(id)}
                        onDismiss={handleDismissNotification}
                        onClearAll={handleClearAllNotifications}
                    />
                    <button onClick={() => setActiveModule('settings')} className="p-2 text-slate-400 hover:text-slate-600 transition-colors hidden sm:block">
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z"></path><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z"></path></svg>
                    </button>
                </div>
            </header>

            <main className="flex-1 p-4 md:p-8 w-full max-w-7xl mx-auto">
                {viewMode === 'form' ? (
                    <InspectionFormView 
                        initialData={formInitialData}
                        activeModule={activeModule}
                        validationLists={validationLists}
                        settings={settings}
                        onSaveDraft={handleExitForm} 
                        onExit={() => setViewMode('dashboard')} 
                        onSubmit={handleGoogleSheetSubmit}
                        submissionStatus={submissionStatus}
                        onViewReport={handleViewReport}
                    />
                ) : (
                    <div className="animate-fadeIn">
                        {activeModule === 'overview' && <OverviewDashboard appScriptUrl={appScriptUrl} onNavigate={setActiveModule} userRole={currentUser.role} />}
                        {activeModule === 'settings' && <SettingsView settings={settings} setSettings={setSettings} appScriptUrl={appScriptUrl} setAppScriptUrl={setAppScriptUrl} handleSaveSettings={handleSaveSettings} isSavingSettings={isSavingSettings} showToast={showToast} user={currentUser} />}
                        {activeModule === 'maintenance' && isSuperAdmin && <MaintenanceView user={currentUser} appScriptUrl={appScriptUrl} settings={settings} onSettingsUpdate={(s) => setSettings(p => ({...p, ...s}))} showToast={showToast} />}
                        {activeModule === 'general' && <GeneralDashboard stats={stats} startNewInspection={() => startFreshInspection('general')} fetchHistory={fetchHistory} isLoadingHistory={isLoadingHistory} historyList={historyList} onViewReport={handleViewReport} onPrint={() => {}} />}
                        {activeModule === 'petroleum' && <PetroleumDashboard stats={stats} startNewInspection={() => startFreshInspection('petroleum')} fetchHistory={fetchHistory} isLoadingHistory={isLoadingHistory} historyList={historyList} onViewReport={handleViewReport} onPrint={() => {}} />}
                        {activeModule === 'petroleum_v2' && <PetroleumV2Dashboard stats={stats} startNewInspection={() => startFreshInspection('petroleum_v2')} fetchHistory={fetchHistory} isLoadingHistory={isLoadingHistory} historyList={historyList} onViewReport={handleViewReport} onPrint={() => {}} />}
                        {activeModule === 'acid' && <AcidDashboard stats={stats} startNewInspection={() => startFreshInspection('acid')} fetchHistory={fetchHistory} isLoadingHistory={isLoadingHistory} historyList={historyList} onViewReport={handleViewReport} onPrint={() => {}} />}
                        {activeModule === 'users' && <UserManagementView currentUser={currentUser} appScriptUrl={appScriptUrl} showToast={showToast} validationLists={validationLists} settings={settings} />}
                        {activeModule === 'support' && <SupportView appScriptUrl={appScriptUrl} currentUser={currentUser} showToast={showToast} settings={settings} validationLists={validationLists} />}
                        {activeModule === 'track_requests' && <RequestTrackingView appScriptUrl={appScriptUrl} currentUser={currentUser} showToast={showToast} />}
                    </div>
                )}
            </main>
          </div>
      </div>

      {isReportModalOpen && selectedReportData && (
          <ReportViewerModal 
            onClose={() => setIsReportModalOpen(false)} 
            onPrint={() => window.print()}
            title={`Report_${selectedReportData.id || 'Draft'}`}
          >
              {activeModule === 'petroleum' ? (
                  <PrintablePetroleumReport data={selectedReportData} settings={settings} />
              ) : activeModule === 'petroleum_v2' ? (
                  <PrintablePetroleumV2Report data={selectedReportData} settings={settings} />
              ) : activeModule === 'acid' ? (
                  <PrintableAcidReport data={selectedReportData} settings={settings} />
              ) : (
                  <PrintableGeneralReport data={selectedReportData} settings={settings} />
              )}
          </ReportViewerModal>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { SystemSettings, User, SubscriptionDetails } from '../../types';

interface SidebarProps {
  isOpen: boolean;
  onClose: () => void;
  activeModule: string;
  onSelectModule: (m: string) => void;
  settings: SystemSettings;
  user?: User; 
  onLogout?: () => void;
  onEditProfile?: () => void; 
  onLockedItemClick?: (featureName: string) => void;
  subscription?: SubscriptionDetails | null;
  onRequestInspection?: () => void; 
}

const Sidebar: React.FC<SidebarProps> = ({ isOpen, onClose, activeModule, onSelectModule, settings, user, onLogout, onEditProfile, onLockedItemClick, subscription, onRequestInspection }) => {

    const roleStr = user?.role ? String(user.role).toLowerCase() : '';
    const isAdmin = roleStr === 'admin' || roleStr === 'superadmin';

    const canRequestInspection = isAdmin || ['operations', 'maintenance', 'secretary', 'other', 'clerk'].includes(roleStr);

    const [logoError, setLogoError] = useState(false);

    useEffect(() => {
        setLogoError(false);
    }, [settings.companyLogo]);

    const NavItem = ({ id, label, icon, isLocked = false, isDanger = false, onClickCustom }: { id: string, label: string, icon: React.ReactNode, isLocked?: boolean, isDanger?: boolean, onClickCustom?: () => void }) => {
        const isActive = activeModule === id;

        return (
            <button
                onClick={() => { 
                    if (onClickCustom) {
                        onClickCustom();
                        return;
                    }
                    if (isLocked && onLockedItemClick) {
                        onLockedItemClick(label);
                        onClose();
                    } else {
                        onSelectModule(id); 
                        onClose(); 
                    }
                }}
                className={`w-full group relative flex items-center gap-2.5 px-3 py-1 rounded-md transition-all duration-150
                    ${isActive 
                        ? (isDanger ? 'bg-red-50 text-red-700' : 'bg-slate-100 text-slate-900 shadow-sm')
                        : isLocked 
                            ? 'text-slate-300 cursor-not-allowed opacity-50' 
                            : isDanger 
                                ? 'text-red-500 hover:bg-red-50'
                                : 'text-slate-500 hover:bg-slate-50 hover:text-slate-800'
                    }
                `}
            >
                {isActive && (
                    <div className={`absolute left-0 top-1.5 bottom-1.5 w-1 rounded-r-full ${isDanger ? 'bg-red-600' : 'bg-indigo-600'}`}></div>
                )}

                <span className={`shrink-0 transition-colors ${isActive ? (isDanger ? 'text-red-500' : 'text-indigo-600') : 'text-slate-400 group-hover:text-slate-600'}`}>
                    {React.cloneElement(icon as React.ReactElement<{ className?: string }>, { className: "w-4 h-4" })}
                </span>

                <span className={`text-[13px] font-normal tracking-tight truncate flex-1 text-left
                    ${isActive ? (isDanger ? 'text-red-800' : 'text-slate-900 font-medium') 
                               : isLocked ? 'text-slate-300' 
                               : 'text-slate-600 group-hover:text-slate-900'}`}>
                    {label}
                </span>

                {isLocked && (
                    <svg className="w-3 h-3 text-slate-200" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z"></path></svg>
                )}
            </button>
        );
    };

    return (
        <>
            {isOpen && (
                <div className="fixed inset-0 z-[55] bg-slate-900/10 backdrop-blur-[1px] lg:hidden transition-opacity" onClick={onClose}></div>
            )}

            <aside className={`fixed inset-y-0 left-0 z-[60] w-64 bg-white border-r border-slate-100 transform transition-transform duration-300 ease-out ${isOpen ? 'translate-x-0' : '-translate-x-full'} lg:translate-x-0 flex flex-col shadow-sm`}>
                 {/* Compact Brand Header */}
                 <div className="px-5 py-4 border-b border-slate-50 shrink-0">
                        <div className="flex items-center gap-3">
                            <div className="w-8 h-8 rounded-lg bg-indigo-50 flex items-center justify-center text-indigo-600 shrink-0 overflow-hidden p-1">
                                {settings.companyLogo && !logoError ? (
                                    <img src={settings.companyLogo} alt="Logo" className="w-full h-full object-contain" onError={() => setLogoError(true)} />
                                ) : (
                                    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z" /></svg>
                                )}
                            </div>
                            <div className="min-w-0 flex-1">
                                <h1 className="text-sm font-black tracking-tight text-slate-900 leading-none truncate uppercase">
                                    {settings.companyName || 'SafetyPro'}
                                </h1>
                                <p className="text-[9px] font-bold text-slate-300 uppercase tracking-widest mt-1">Management Portal</p>
                            </div>
                            <button onClick={onClose} className="lg:hidden text-slate-300 hover:text-slate-500">
                                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12"></path></svg>
                            </button>
                        </div>
                </div>

                {/* Compact Navigation */}
                <div className="flex-1 overflow-y-auto scrollbar-hide px-2 py-3 space-y-0.5">
                     <NavItem 
                        id="overview" 
                        label="Overview" 
                        icon={<svg fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 6a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2H6a2 2 0 01-2-2V6zM14 6a2 2 0 012-2h2a2 2 0 01-2 2h-2a2 2 0 01-2-2V6zM4 16a2 2 0 012-2h2a2 2 0 01-2 2H6a2 2 0 01-2-2v-2zM14 16a2 2 0 012-2h2a2 2 0 01-2 2h-2a2 2 0 01-2-2v-2z"></path></svg>} 
                     />

                     <div className="h-px bg-slate-50 my-2 mx-2" />

                     <NavItem 
