                    {badgeCount > 0 && (
                        <div className={`absolute -top-3 -right-3 ${badgeColor} text-white text-[10px] font-black px-1.5 py-0.5 rounded-full border-2 border-white shadow-sm animate-bounce`}>
                            {badgeCount}
                        </div>
                    )}
