                                                <div className="text-[9px] text-slate-400 font-bold uppercase tracking-tighter">{item.trailerNo || 'NO TRAILER'}</div>
                                            </td>
                                            <td className="px-6 py-4 text-slate-500 tabular-nums font-medium">
                                                {new Date(item.timestamp).toLocaleDateString()}
                                            </td>
                                            <td className="px-6 py-4">
                                                <span className={`inline-flex items-center gap-1.5 px-2 py-0.5 rounded font-black text-[9px] border
                                                    ${Number(item.rate) >= 4 ? 'bg-emerald-50 text-emerald-700 border-emerald-100' : 'bg-red-50 text-red-700 border-red-100'}
                                                `}>
                                                    {item.rate}/5
                                                </span>
                                            </td>
                                            <td className="px-6 py-4 text-right">
                                                <button 
                                                    onClick={() => onViewReport(item)}
                                                    className="text-indigo-600 hover:text-indigo-800 font-black tracking-tighter text-[10px] uppercase border-b border-transparent hover:border-indigo-200 transition-all"
                                                >
                                                    View
                                                </button>
                                            </td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    )}
                </div>
                <div className="mt-6 text-center">
                    <button 
                        onClick={() => onNavigate('general')}
                        className="text-[9px] font-black text-slate-300 hover:text-slate-900 tracking-[0.3em] uppercase transition-all flex items-center justify-center gap-2 mx-auto"
                    >
                        Access Archive
                        <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M17 8l4 4m0 0l-4 4m4-4H3"></path></svg>
                    </button>
                </div>
            </div>
        </div>
    );
};

