                    />

                    {/* 7. Enterprise Suite */}
                    <LauncherTile 
                        id="enterprise_suite" 
                        label="Enterprise" 
                        isLocked={true}
                        icon={<IconWrapper color="#94a3b8"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><path d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10"></path></svg></IconWrapper>}
