                        label="Support Hub" 
                        icon={<IconWrapper color="#eab308"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><path d="M18.364 5.636l-3.536 3.536m0 5.656l3.536 3.536M9.172 9.172L5.636 5.636m3.536 9.192l-3.536 3.536M21 12a9 9 0 11-18 0 9 9 0 0118 0zm-5 0a4 4 0 11-8 0 4 4 0 018 0z"></path></svg></IconWrapper>}
