import React, { useState } from 'react';
import { User, SystemSettings } from '../../types';

interface ProfileModalProps {
    user: User;
    settings: SystemSettings;
    appScriptUrl: string;
    onClose: () => void;
    showToast: (msg: string, type: 'success' | 'error' | 'info') => void;
    onUpdateSuccess: (newUser: User) => void;
    onLogout: () => void;
    onForceSync: () => void;
    isSyncing?: boolean;
}

const ProfileModal: React.FC<ProfileModalProps> = ({ 
    user, 
    settings, 
    appScriptUrl, 
    onClose, 
    showToast, 
    onUpdateSuccess, 
    onLogout,
    onForceSync,
    isSyncing = false
}) => {
    // Split name for display
    const nameParts = (user.name || '').split(' ');
    const firstName = nameParts[0] || '';
    const lastName = nameParts.slice(1).join(' ') || '';

    // Password State
    const [password, setPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');
    const [isUpdatingPassword, setIsUpdatingPassword] = useState(false);

    // Options Mock State (Visual only as per request style)
    const [showScrollbars, setShowScrollbars] = useState(false);
    const [closeOnExit, setCloseOnExit] = useState(false);
    const [language, setLanguage] = useState('English');

    const handlePasswordChange = async () => {
        if (!password) {
            showToast("Please enter a new password.", "warning");
            return;
        }
        if (password !== confirmPassword) {
            showToast("Passwords do not match.", "error");
            return;
        }

        setIsUpdatingPassword(true);
        try {
            const response = await fetch(appScriptUrl, {
                method: 'POST',
                body: JSON.stringify({
                    action: 'update_user',
                    originalUsername: user.username,
                    password: password
                })
            });
            const result = await response.json();

            if (result.status === 'success') {
                showToast("Password updated successfully!", 'success');
                setPassword('');
                setConfirmPassword('');
            } else {
                showToast(result.message || "Failed to update password.", 'error');
            }
        } catch (e) {
            showToast("Connection failed.", 'error');
        } finally {
            setIsUpdatingPassword(false);
        }
    };

    return (
        <div className="fixed inset-0 z-[100] bg-white flex flex-col animate-fadeIn overflow-y-auto">
            {/* Minimalist Header */}
            <div className="sticky top-0 bg-white border-b border-gray-100 px-4 py-3 flex items-center shrink-0 z-10 shadow-sm">
                <button 
                    onClick={onClose}
                    className="p-2 text-blue-500 hover:bg-blue-50 rounded-full transition-all"
                >
                    <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path strokeLinecap="round" strokeLinejoin="round" d="M15 19l-7-7 7-7"></path></svg>
                </button>
                <h1 className="flex-1 text-center font-medium text-slate-700 text-sm">Forms On Fire</h1>
                <div className="w-10"></div> {/* Spacer for symmetry */}
            </div>

            <div className="max-w-2xl mx-auto w-full px-6 py-10 space-y-12 pb-24">

                {/* 1. YOUR DETAILS */}
                <section className="space-y-4">
                    <h3 className="text-lg font-bold text-slate-800 border-b border-gray-100 pb-2">Your Details</h3>
                    <div className="space-y-3">
                        <div className="flex justify-between items-center text-sm py-1">
                            <span className="font-bold text-slate-700">Company</span>
                            <span className="text-slate-500">{settings.companyName || 'Alistair Group'}</span>
                        </div>
                        <div className="flex justify-between items-center text-sm py-1">
                            <span className="font-bold text-slate-700">First Name</span>
                            <span className="text-slate-500">{firstName}</span>
                        </div>
                        <div className="flex justify-between items-center text-sm py-1">
                            <span className="font-bold text-slate-700">Last Name</span>
                            <span className="text-slate-500">{lastName}</span>
                        </div>
                        <div className="flex justify-between items-center text-sm py-1">
                            <span className="font-bold text-slate-700">Email or Login ID</span>
                            <span className="text-slate-500">{user.username}</span>
                        </div>
                    </div>
                </section>

                {/* 2. CHANGE PASSWORD */}
                <section className="space-y-4">
                    <div className="flex items-center gap-2 border-b border-gray-100 pb-2">
                        <h3 className="text-lg font-bold text-slate-800">Change Password</h3>
                        <svg className="w-4 h-4 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8.228 9c.549-1.165 2.03-2 3.772-2 2.21 0 4 1.343 4 3 0 1.4-1.278 2.575-3.006 2.907-.542.104-.994.54-.994 1.093m0 3h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
                    </div>
                    <div className="space-y-4">
                        <div className="relative">
                            <input 
                                type="password" 
                                placeholder="Password"
                                className="w-full p-3 border border-gray-200 rounded-lg text-sm bg-gray-50 focus:bg-white focus:ring-2 focus:ring-blue-100 outline-none transition-all pr-10"
                                value={password}
                                onChange={(e) => setPassword(e.target.value)}
                            />
                            <svg className="w-4 h-4 absolute right-3 top-1/2 -translate-y-1/2 text-slate-400" fill="currentColor" viewBox="0 0 24 24"><path d="M12 15a3 3 0 100-6 3 3 0 000 6z"/><path fillRule="evenodd" d="M1.323 11.447C2.811 6.976 7.028 3.75 12.001 3.75c4.97 0 9.185 3.223 10.675 7.69.12.362.12.752 0 1.113-1.487 4.471-5.705 7.697-10.677 7.697-4.97 0-9.186-3.223-10.675-7.69a1.762 1.762 0 010-1.113zM17.25 12a5.25 5.25 0 11-10.5 0 5.25 5.25 0 0110.5 0z" clipRule="evenodd"/></svg>
                        </div>
                        <div className="relative">
                            <input 
                                type="password" 
                                placeholder="Confirm Password"
                                className="w-full p-3 border border-gray-200 rounded-lg text-sm bg-gray-50 focus:bg-white focus:ring-2 focus:ring-blue-100 outline-none transition-all pr-10"
                                value={confirmPassword}
                                onChange={(e) => setConfirmPassword(e.target.value)}
                            />
                            <svg className="w-4 h-4 absolute right-3 top-1/2 -translate-y-1/2 text-slate-400" fill="currentColor" viewBox="0 0 24 24"><path d="M12 15a3 3 0 100-6 3 3 0 000 6z"/><path fillRule="evenodd" d="M1.323 11.447C2.811 6.976 7.028 3.75 12.001 3.75c4.97 0 9.185 3.223 10.675 7.69.12.362.12.752 0 1.113-1.487 4.471-5.705 7.697-10.677 7.697-4.97 0-9.186-3.223-10.675-7.69a1.762 1.762 0 010-1.113zM17.25 12a5.25 5.25 0 11-10.5 0 5.25 5.25 0 0110.5 0z" clipRule="evenodd"/></svg>
                        </div>
                        <button 
                            onClick={handlePasswordChange}
                            disabled={isUpdatingPassword}
                            className="w-full py-4 bg-green-600 hover:bg-green-700 text-white font-bold rounded-lg shadow-md transition-all active:scale-95"
                        >
                            {isUpdatingPassword ? 'Updating...' : 'Change Password'}
                        </button>
                    </div>
                </section>

                {/* 3. OPTIONS */}
                <section className="space-y-4">
                    <h3 className="text-lg font-bold text-slate-800 border-b border-gray-100 pb-2">Options</h3>
                    <div className="space-y-4">
                        <label className="flex items-center gap-3 cursor-pointer group">
                            <div className={`w-6 h-6 border-2 rounded transition-all flex items-center justify-center ${showScrollbars ? 'bg-blue-600 border-blue-600' : 'bg-white border-gray-300'}`}>
                                {showScrollbars && <svg className="w-4 h-4 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path strokeLinecap="round" strokeLinejoin="round" d="M5 13l4 4L19 7"></path></svg>}
                                <input type="checkbox" className="sr-only" checked={showScrollbars} onChange={(e) => setShowScrollbars(e.target.checked)} />
                            </div>
                            <span className="text-sm font-medium text-slate-600">Show Scrollbars</span>
                        </label>
                        <label className="flex items-center gap-3 cursor-pointer group">
                            <div className={`w-6 h-6 border-2 rounded transition-all flex items-center justify-center ${closeOnExit ? 'bg-blue-600 border-blue-600' : 'bg-white border-gray-300'}`}>
                                {closeOnExit && <svg className="w-4 h-4 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path strokeLinecap="round" strokeLinejoin="round" d="M5 13l4 4L19 7"></path></svg>}
                                <input type="checkbox" className="sr-only" checked={closeOnExit} onChange={(e) => setCloseOnExit(e.target.checked)} />
                            </div>
                            <span className="text-sm font-medium text-slate-600">Close Application on Exit</span>
                        </label>
                    </div>
                </section>

                {/* 4. DATA SYNC & STATUS */}
                <section className="space-y-4">
                    <h3 className="text-lg font-bold text-slate-800 border-b border-gray-100 pb-2">Data Sync & Status</h3>
                    <button 
                        onClick={onForceSync}
                        disabled={isSyncing}
                        className="w-full py-4 bg-green-600 hover:bg-green-700 text-white font-bold rounded-lg shadow-md transition-all flex items-center justify-center gap-3 active:scale-95"
                    >
                        <svg className={`w-5 h-5 ${isSyncing ? 'animate-spin' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15"></path></svg>
                        {isSyncing ? 'Syncing...' : 'Force Sync'}
                    </button>
                    <div className="text-[11px] text-slate-400 font-medium space-y-1">
                        <p>Last synced at {new Date().toLocaleString('en-GB', { day: '2-digit', month: '2-digit', year: 'numeric', hour: '2-digit', minute: '2-digit' })}</p>
                        <p>No uploads pending</p>
                    </div>
                </section>

                {/* 5. LANGUAGE */}
                <section className="space-y-4">
                    <h3 className="text-lg font-bold text-slate-800 border-b border-gray-100 pb-2">Language</h3>
                    <div className="relative">
                        <select 
                            className="w-full p-3 bg-white border border-gray-200 rounded-lg text-sm font-medium appearance-none focus:ring-2 focus:ring-blue-100 outline-none"
                            value={language}
                            onChange={(e) => setLanguage(e.target.value)}
                        >
                            <option value="English">English</option>
                            <option value="French">French</option>
                            <option value="Spanish">Spanish</option>
                        </select>
                        <svg className="w-4 h-4 absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7"></path></svg>
                    </div>
                </section>

                {/* 6. LOGOUT */}
                <section className="pt-8 border-t border-gray-100">
                    <button 
                        onClick={onLogout}
                        className="w-full py-4 bg-white border-2 border-red-500 text-red-600 hover:bg-red-50 font-black rounded-lg transition-all flex items-center justify-center gap-3 uppercase tracking-widest active:scale-95 shadow-sm"
                    >
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path strokeLinecap="round" strokeLinejoin="round" d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H5a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1"></path></svg>
                        Logout
                    </button>
                </section>
            </div>
        </div>
    );
};

