                    >
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path strokeLinecap="round" strokeLinejoin="round" d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z"></path><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z"></path></svg>
                    </button>
                </div>
            </header>

            <main className="flex-1 p-4 md:p-8 w-full max-w-7xl mx-auto">
                {viewMode === 'form' ? (
                    <InspectionFormView 
                        initialData={formInitialData}
                        activeModule={activeModule}
                        validationLists={validationLists}
                        settings={settings}
                        onSaveDraft={handleExitForm} 
                        onExit={() => setViewMode('dashboard')} 
                        onSubmit={handleGoogleSheetSubmit}
                        submissionStatus={submissionStatus}
                        onViewReport={handleViewReport}
                    />
                ) : (
                    <div className="animate-fadeIn">
                        {activeModule === 'overview' && (
                            <OverviewDashboard 
                                appScriptUrl={appScriptUrl} 
                                onNavigate={handleNavigate} 
