import React, { useState, useEffect } from 'react';
import { User, ValidationLists, SystemSettings } from '../types';
import AutocompleteInput from '../components/ui/AutocompleteInput';

interface UserManagementViewProps {
    currentUser: User;
    appScriptUrl: string;
    showToast: (msg: string, type: 'success' | 'error' | 'info' | 'warning') => void;
    validationLists: ValidationLists;
    settings?: SystemSettings;
}

const UserManagementView: React.FC<UserManagementViewProps> = ({ currentUser, appScriptUrl, showToast, validationLists, settings }) => {
    const [users, setUsers] = useState<(User & {password?: string})[]>([]);
    const [isLoading, setIsLoading] = useState(false);
    const [viewMode, setViewMode] = useState<'list' | 'form'>('list');
    const [isEditing, setIsEditing] = useState(false);
    const [originalUsername, setOriginalUsername] = useState('');

    const [formData, setFormData] = useState({
        name: '', username: '', password: '', role: 'Inspector' as any, position: ''
    });
    const [isSubmitting, setIsSubmitting] = useState(false);

    const isSuperAdmin = currentUser.role === 'SuperAdmin';

    useEffect(() => { fetchUsers(); }, []);

    const fetchUsers = async () => {
        if (!appScriptUrl) return;
        setIsLoading(true);
        try {
            const response = await fetch(appScriptUrl, { method: 'POST', body: JSON.stringify({ action: 'get_users' }) });
            const result = await response.json();
            if (result.status === 'success' && Array.isArray(result.users)) {
                let fetchedUsers = result.users;
                if (!isSuperAdmin) fetchedUsers = fetchedUsers.filter((u: User) => u.role !== 'SuperAdmin');
                setUsers(fetchedUsers);
            }
        } catch (e) { showToast("Failed to load users", 'error'); } finally { setIsLoading(false); }
    };

    const handleDelete = async (username: string) => {
        if (!window.confirm(`Remove user "${username}"?`)) return;
        setIsLoading(true);
        try {
            const response = await fetch(appScriptUrl, { method: 'POST', body: JSON.stringify({ action: 'delete_user', username }) });
            const result = await response.json();
            if (result.status === 'success') {
                showToast("User removed successfully", 'success');
                fetchUsers();
            } else { showToast(result.message || "Delete failed", 'error'); }
        } catch (e) { showToast("Connection failed", 'error'); } finally { setIsLoading(false); }
    };

    const handleEdit = (user: User) => {
        setFormData({ name: user.name, username: user.username, role: user.role as any, position: user.position || '', password: '' });
        setOriginalUsername(user.username);
        setIsEditing(true);
        setViewMode('form');
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!formData.name || !formData.username) { showToast("Please fill in required fields.", 'error'); return; }
        if (!isEditing && !formData.password) { showToast("Password is required for new users.", 'error'); return; }

        setIsSubmitting(true);
        try {
            const payload: any = { action: isEditing ? 'update_user' : 'register_user', ...formData };
            if (isEditing) payload.originalUsername = originalUsername;
            const response = await fetch(appScriptUrl, { method: 'POST', body: JSON.stringify(payload) });
            const result = await response.json();
            if (result.status === 'success') {
                showToast(isEditing ? "User updated successfully" : "User created successfully", 'success');
                setViewMode('list');
                fetchUsers();
            } else { showToast(result.message || "Operation failed", 'error'); }
        } catch (e) { showToast("Connection failed", 'error'); } finally { setIsSubmitting(false); }
    };

    const handleShareUser = async (user: User & {password?: string}) => {
        const text = `System Access:\nUser: ${user.username}\nRole: ${user.role}`;
        if (navigator.share) {
            try { await navigator.share({ title: "Credentials", text }); showToast("Shared successfully", 'success'); } catch (err) {}
        } else {
            navigator.clipboard.writeText(text).then(() => showToast("Copied to clipboard", 'success'));
        }
    };

    if (viewMode === 'form') {
        return (
            <div className="max-w-lg mx-auto animate-fadeIn py-4">
                <button onClick={() => setViewMode('list')} className="mb-4 text-xs font-bold text-gray-500 hover:text-gray-800">← Back to List</button>
                <div className="bg-white rounded-xl shadow-lg border border-gray-200 overflow-hidden p-6">
                    <h2 className="text-lg font-black text-slate-800 mb-6">{isEditing ? 'Edit User' : 'Create New User'}</h2>
                    <form onSubmit={handleSubmit} className="space-y-4">
                        <AutocompleteInput label="Full Name" value={formData.name} onChange={v => setFormData({...formData, name: v})} options={validationLists.inspectors} isTitleCase={true} />
                        <div className="grid grid-cols-2 gap-4">
                            <AutocompleteInput label="Position" value={formData.position} onChange={v => setFormData({...formData, position: v})} options={validationLists.positions} isTitleCase={true} />
                            <div>
                                <label className="block text-xs font-bold text-gray-500 uppercase mb-1.5">Role</label>
                                <select className="w-full p-3 bg-gray-50 border border-gray-200 rounded-lg text-sm font-medium" value={formData.role} onChange={e => setFormData({...formData, role: e.target.value as any})}>
                                    <option value="Inspector">Inspector</option>
                                    <option value="Operations">Operations</option>
                                    <option value="Maintenance">Maintenance</option>
                                    <option value="Admin">Admin</option>
                                    {isSuperAdmin && <option value="SuperAdmin">SuperAdmin</option>}
                                </select>
                            </div>
                        </div>
                        <div className="grid grid-cols-2 gap-4">
                            <input type="text" placeholder="Username" className="p-3 bg-gray-50 border border-gray-200 rounded-lg text-sm" value={formData.username} onChange={e => setFormData({...formData, username: e.target.value})} required />
                            <input type="password" placeholder="Password" className="p-3 bg-gray-50 border border-gray-200 rounded-lg text-sm" value={formData.password} onChange={e => setFormData({...formData, password: e.target.value})} required={!isEditing} />
                        </div>
                        <button type="submit" disabled={isSubmitting} className="w-full py-4 bg-blue-600 hover:bg-blue-700 text-white font-bold rounded-xl shadow-md flex items-center justify-center gap-2">
                            {isSubmitting ? (
                                <svg className="animate-spin h-5 w-5 text-white" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                            ) : null}
                            {isSubmitting ? 'Saving Data...' : isEditing ? 'Update User' : 'Create User'}
                        </button>
                    </form>
                </div>
            </div>
        );
    }

    return (
        <div className="max-w-6xl mx-auto space-y-6 animate-fadeIn">
            <div className="flex justify-between items-center">
                <h2 className="text-2xl font-bold text-gray-800">Staff Management</h2>
                <button onClick={() => { setFormData({ name: '', username: '', password: '', role: 'Inspector', position: '' }); setIsEditing(false); setViewMode('form'); }} className="px-6 py-2.5 bg-blue-600 hover:bg-blue-700 text-white font-bold rounded-lg shadow-md">Add Staff Member</button>
            </div>
            <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-x-auto">
                <table className="w-full text-left text-sm">
                    <thead className="bg-gray-50 text-xs font-bold text-gray-500 uppercase border-b border-gray-200">
                        <tr><th className="px-4 py-3">Name</th><th className="px-4 py-3">Role</th><th className="px-4 py-3 text-right">Actions</th></tr>
                    </thead>
                    <tbody className="divide-y divide-gray-100">
                        {users.map((u, i) => (
                            <tr key={i} className="hover:bg-gray-50">
                                <td className="px-4 py-3 font-bold text-gray-900">{u.name}</td>
                                <td className="px-4 py-3 text-xs uppercase font-bold text-blue-600">{u.role}</td>
                                <td className="px-4 py-3 text-right">
                                    <div className="flex justify-end gap-2">
                                        <button onClick={() => handleEdit(u)} className="p-2 text-blue-600 hover:bg-blue-50 rounded">Edit</button>
                                        <button onClick={() => handleDelete(u.username)} className="p-2 text-red-600 hover:bg-red-50 rounded">Delete</button>
                                    </div>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
        </div>
    );
};

