import React, { useState, useEffect } from 'react';
import { User, SystemSettings } from '../types';

interface MaintenanceViewProps {
    user: User;
    appScriptUrl: string;
    settings: SystemSettings;
    onSettingsUpdate: (newSettings: Partial<SystemSettings>) => void;
    showToast: (msg: string, type: 'success' | 'error' | 'info' | 'warning') => void;
}

const MaintenanceView: React.FC<MaintenanceViewProps> = ({ user, appScriptUrl, settings, onSettingsUpdate, showToast }) => {
    const [msgType, setMsgType] = useState<'info' | 'warning' | 'critical'>('info');
    const [msgBody, setMsgBody] = useState('');
    const [isSending, setIsSending] = useState(false);
    const [maintMode, setMaintMode] = useState(settings.maintenanceMode || false);
    const [maintMessage, setMaintMessage] = useState(settings.maintenanceMessage || 'System under scheduled maintenance.');
    const [isSavingMaint, setIsSavingMaint] = useState(false);

    useEffect(() => {
        setMaintMode(settings.maintenanceMode || false);
        setMaintMessage(settings.maintenanceMessage || 'System under scheduled maintenance.');
    }, [settings.maintenanceMode, settings.maintenanceMessage]);

    const handleBroadcast = async () => {
        if (!msgBody.trim()) { showToast("Please enter a message.", "error"); return; }
        setIsSending(true);
        try {
            await fetch(appScriptUrl, { method: 'POST', body: JSON.stringify({ action: 'broadcast', type: msgType, message: msgBody }), mode: 'no-cors' });
            showToast("Broadcast sent successfully!", "success");
            setMsgBody('');
        } catch (e) { showToast("Failed to send broadcast.", "error"); } finally { setIsSending(false); }
    };

    const handleSaveMaintenance = async () => {
        setIsSavingMaint(true);
        try {
            await fetch(appScriptUrl, {
                method: 'POST',
                body: JSON.stringify({
                    action: 'update_settings',
                    companyName: settings.companyName,
                    managerEmail: settings.managerEmail,
                    companyLogo: settings.companyLogo,
                    mobileApkLink: settings.mobileApkLink,
                    webAppUrl: settings.webAppUrl,
                    maintenanceMode: maintMode,
                    maintenanceMessage: maintMessage
                }),
                mode: 'no-cors'
            });
            const updatedSettings = { ...settings, maintenanceMode: maintMode, maintenanceMessage: maintMessage };
            localStorage.setItem('safetyCheck_settings', JSON.stringify(updatedSettings));
            onSettingsUpdate({ maintenanceMode: maintMode, maintenanceMessage: maintMessage });
            showToast(maintMode ? "SYSTEM LOCKDOWN ACTIVATED" : "System Access Restored", "success");
        } catch (e) { showToast("Failed to update status.", "error"); } finally { setIsSavingMaint(false); }
    };

    return (
        <div className="max-w-5xl mx-auto animate-fadeIn pb-12 space-y-8">
            <h1 className="text-3xl font-black text-slate-900">Security Control</h1>
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
                    <h3 className="font-bold text-slate-800 mb-4">Global Broadcast</h3>
                    <textarea className="w-full p-4 border rounded-xl mb-4 h-32" placeholder="Broadcast message..." value={msgBody} onChange={e => setMsgBody(e.target.value)}></textarea>
                    <button onClick={handleBroadcast} disabled={isSending} className="w-full py-3 bg-blue-600 text-white font-bold rounded-xl flex items-center justify-center gap-2">
                        {isSending ? <svg className="animate-spin h-5 w-5 text-white" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg> : null}
                        {isSending ? 'Broadcasting...' : 'Send Broadcast'}
                    </button>
                </div>
                <div className="bg-red-50 rounded-2xl border border-red-200 p-6">
                    <h3 className="font-bold text-red-800 mb-4">Lockdown System</h3>
                    <div className="flex items-center justify-between mb-4">
                        <span className="text-sm font-bold text-red-700">Maintenance Mode</span>
                        <button onClick={() => setMaintMode(!maintMode)} className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors ${maintMode ? 'bg-red-600' : 'bg-slate-200'}`}>
                            <span className={`inline-block h-4 w-4 transform rounded-full bg-white transition ${maintMode ? 'translate-x-6' : 'translate-x-1'}`} />
                        </button>
                    </div>
                    <button onClick={handleSaveMaintenance} disabled={isSavingMaint} className="w-full py-3 bg-red-600 text-white font-bold rounded-xl flex items-center justify-center gap-2">
                        {isSavingMaint ? <svg className="animate-spin h-5 w-5 text-white" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg> : null}
                        {isSavingMaint ? 'Updating System...' : 'Confirm System Status'}
                    </button>
                </div>
            </div>
        </div>
    );
};

