                            </div>
                        </div>

                        {!formData.name && (
                            <div className="p-3 bg-amber-50 rounded-lg border border-amber-100 flex items-start gap-2">
                                <svg className="w-4 h-4 text-amber-500 shrink-0 mt-0.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
                                <p className="text-[10px] text-amber-800 leading-tight">User will be prompted to set their Name and Password when they first log in with this email.</p>
