import React, { useState } from 'react';
import { User, UserPreferences } from '../../types';

interface OnboardingWizardProps {
    user: User;
    appScriptUrl: string;
    onComplete: (updatedUser: User) => void;
}

const OnboardingWizard: React.FC<OnboardingWizardProps> = ({ user, appScriptUrl, onComplete }) => {
    const [step, setStep] = useState(0); // 0: Name, 1: Password, 2: Notifications, 3: Success
    const [isLoading, setIsLoading] = useState(false);

    // Identity
    const [fullName, setFullName] = useState('');
    const [newPassword, setNewPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');
    const [error, setError] = useState('');

    // Notifications
    const [prefs, setPrefs] = useState<UserPreferences>({
        emailNotifications: true,
        notifyGeneral: true,
        notifyPetroleum: true,
        notifyPetroleumV2: true,
        notifyAcid: true
    });

    const nextStep = () => {
        setError('');
        setStep(prev => prev + 1);
    };

    const handleProfileSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (step === 0 && !fullName.trim()) { setError("Full Name is required."); return; }
        if (step === 1) {
            if (newPassword.length < 4) { setError("Password too short."); return; }
            if (newPassword !== confirmPassword) { setError("Passwords do not match."); return; }
        }
        nextStep();
    };

    const handleFinalize = async () => {
        setIsLoading(true);
        try {
            const payload = {
                action: 'update_user',
                originalUsername: user.username,
                name: fullName,
                password: newPassword,
                preferences: { ...prefs, hasCompletedTour: false }
            };

            const response = await fetch(appScriptUrl, {
                method: 'POST',
                body: JSON.stringify(payload)
            });
            const result = await response.json();

            if (result.status === 'success') {
                setStep(3);
            } else {
                setError(result.message || "Failed to save profile.");
            }
        } catch (err) {
            setError("Connection lost. Please try again.");
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className="fixed inset-0 z-[200] bg-slate-900 flex items-center justify-center p-4 animate-fadeIn">
            <div className="max-w-4xl w-full bg-white rounded-3xl shadow-2xl overflow-hidden flex flex-col md:flex-row min-h-[600px]">

                {/* Left Progress Bar */}
                <div className="md:w-5/12 bg-emerald-950 p-10 flex flex-col justify-between text-white relative">
                    <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')] opacity-10"></div>
                    <div className="relative z-10">
                        <div className="w-12 h-12 bg-emerald-500 rounded-2xl flex items-center justify-center mb-8 shadow-lg shadow-emerald-500/20">
                            <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7"></path></svg>
                        </div>
                        <h1 className="text-3xl font-black mb-2 uppercase tracking-tight leading-none">Security<br/>Onboarding</h1>
                        <p className="text-emerald-400 text-xs font-bold uppercase tracking-widest opacity-60">System Version 4.0.1</p>
                    </div>

                    <div className="relative z-10 space-y-6">
                        {[
                            { s: 0, l: 'Your Identity' },
