import React, { useState, useEffect } from 'react';
import { User, SystemSettings } from '../types';

interface LoginViewProps {
  onLogin: (user: User) => void;
  appScriptUrl: string;
  setAppScriptUrl: (url: string) => void;
  settings: SystemSettings;
}

const LoginView: React.FC<LoginViewProps> = ({ onLogin, appScriptUrl, setAppScriptUrl, settings }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [rememberMe, setRememberMe] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');
  const [isRegistering, setIsRegistering] = useState(false);
  const [fullName, setFullName] = useState('');
  const [position, setPosition] = useState('');
  const [logoError, setLogoError] = useState(false);

  // Load remembered credentials on mount
  useEffect(() => {
    const saved = localStorage.getItem('sc_remembered_creds');
    if (saved) {
      try {
        const { u, p } = JSON.parse(atob(saved));
        setUsername(u);
        setPassword(p);
        setRememberMe(true);
      } catch (e) {
        localStorage.removeItem('sc_remembered_creds');
      }
    }
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!appScriptUrl || !appScriptUrl.startsWith('https://script.google.com')) {
      setError("System connection not configured. Please contact your IT Administrator.");
      return;
    }

    setError('');
    setIsLoading(true);

    try {
      // Special logic: Regular login
      // Note: Backend handleLogin will allow empty password if user.name is empty (Invite mode)
      const payload = isRegistering 
        ? { action: 'register_user', username, password, name: fullName, position: position, role: 'SuperAdmin' }
        : { action: 'login', username, password };

      const response = await fetch(appScriptUrl, {
        method: 'POST',
        body: JSON.stringify(payload)
      });

      const result = await response.json();

      if (result.status === 'success') {
          const rawUser = result.user;

          if (rememberMe && password) {
            const creds = btoa(JSON.stringify({ u: username, p: password }));
            localStorage.setItem('sc_remembered_creds', creds);
          } else {
            localStorage.removeItem('sc_remembered_creds');
          }

          if (isRegistering) {
              setError("Admin account created. Log in now.");
              setIsRegistering(false);
              setFullName('');
              setPosition('');
              setPassword('');
          } else {
              let safeRole: User['role'] = 'Inspector';
              const rawRole = rawUser.role ? String(rawUser.role).trim().toLowerCase() : '';

              if (rawRole === 'superadmin') safeRole = 'SuperAdmin';
              else if (rawRole === 'admin') safeRole = 'Admin';
              else if (rawRole === 'operations') safeRole = 'Operations';
              else if (rawRole === 'maintenance') safeRole = 'Maintenance';
              else if (rawRole === 'secretary') safeRole = 'Secretary';
              else if (rawRole === 'other') safeRole = 'Other';

              onLogin({ 
                ...rawUser, 
                role: safeRole, 
                position: rawUser.position || '',
                // Flag onboarding if name is missing
                needsSetup: !rawUser.name
              });
          }
      } else if (result.code === 'NO_USERS') {
          setError("Initial setup needed. Create Master Admin.");
          setIsRegistering(true);
      } else {
          setError(result.message || "Authentication failed.");
      }

    } catch (err) {
      setError("Unable to reach server. Check connection.");
    } finally {
      setIsLoading(false); 
    }
  };

  const isUrlValid = appScriptUrl && appScriptUrl.startsWith('https://script.google.com');

  return (
    <div className="min-h-screen w-full bg-slate-50 flex flex-col md:flex-row font-sans text-slate-700 overflow-x-hidden">

      <div className="w-full md:w-[35%] lg:w-[30%] bg-emerald-950 p-6 md:p-12 flex flex-col justify-between relative overflow-hidden shrink-0 border-b md:border-b-0 border-emerald-900 shadow-xl z-10">
        <div className="absolute top-0 left-0 w-full h-full pointer-events-none opacity-10">
            <div className="absolute -top-10 -left-10 w-64 h-64 bg-emerald-400 rounded-full blur-[80px]"></div>
        </div>

        <div className="relative z-10 flex md:block items-center justify-between">
          <div className="bg-white p-2 rounded-xl inline-block shadow-lg">
             {settings.companyLogo && !logoError ? (
                <img src={settings.companyLogo} alt="Logo" className="h-8 md:h-12 w-auto object-contain" onError={() => setLogoError(true)} />
             ) : (
                <div className="flex items-center gap-2 px-1">
                    <svg className="w-6 h-6 text-emerald-900" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z" />
                    </svg>
                    <span className="font-black text-emerald-950 text-base md:text-xl tracking-tight uppercase">SafetyPro</span>
                </div>
             )}
          </div>

          <div className="md:mt-8 text-right md:text-left">
            <h1 className="text-xl md:text-3xl font-black text-white leading-tight uppercase">
                {settings.companyName || 'Alistair Group'}
            </h1>
            <p className="text-emerald-400 font-bold uppercase tracking-widest text-[9px] mt-1 opacity-60">Fleet Management Portal</p>
          </div>
        </div>

        <div className="relative z-10 mt-4 space-y-4">
            <div className="flex items-center gap-2 animate-fadeIn">
                <div className={`w-[2px] h-3.5 rounded-full transition-all duration-500 
                    ${isLoading ? 'bg-blue-400 animate-pulse' : isUrlValid ? 'bg-emerald-500 shadow-sm' : 'bg-red-500'}`}
                ></div>
                <div className="flex flex-col">
                    <span className={`text-[8px] font-black tracking-widest leading-none uppercase 
                        ${isLoading ? 'text-blue-200' : isUrlValid ? 'text-white' : 'text-red-100'}`}
                    >
                        {isLoading ? 'Processing' : isUrlValid ? 'Server Ready' : 'Server Disconnected'}
                    </span>
                </div>
            </div>
            <div className="hidden md:block border-t border-white/5 pt-4">
                <span className="text-[8px] text-emerald-100/30 font-medium uppercase tracking-[0.2em]">© SCBC FLEET SOLUTIONS 2026</span>
            </div>
        </div>
      </div>

      <div className="flex-1 flex flex-col bg-white">
        <div className="flex-1 overflow-y-auto px-6 py-10 md:px-12 flex items-center justify-center">
          <div className="w-full max-w-sm mx-auto">
            <div className="mb-8">
              <h2 className="text-2xl font-black text-slate-800 tracking-tight">
                {isRegistering ? 'Admin Setup' : 'Login'}
              </h2>
              <p className="text-slate-400 text-sm mt-1 font-medium">
                {isRegistering ? 'Create system owner account.' : 'Sign in to access inspections.'}
              </p>
            </div>

            {error && (
              <div className={`mb-6 p-4 rounded-lg text-xs font-medium border animate-fadeIn
                ${error.includes("created") ? 'bg-green-50 text-green-700 border-green-200' : 'bg-red-50 text-red-700 border-red-100'}`}>
                {error}
              </div>
            )}

            <form onSubmit={handleSubmit} className="space-y-5">
              {isRegistering && (
                <div className="space-y-4 bg-slate-50/50 p-5 rounded-xl border border-slate-100 mb-4">
                  <input type="text" required className="w-full px-4 py-3 bg-white border border-slate-200 rounded-lg outline-none text-sm font-bold" value={fullName} onChange={e => setFullName(e.target.value)} placeholder="Full Name" />
                  <input type="text" required className="w-full px-4 py-3 bg-white border border-slate-200 rounded-lg outline-none text-sm font-bold" value={position} onChange={e => setPosition(e.target.value)} placeholder="Job Title" />
                </div>
              )}

              <div className="space-y-4">
                <input 
                  type="email" 
                  required 
                  className="w-full px-4 py-3.5 bg-slate-50 border border-slate-200 rounded-lg focus:bg-white focus:border-emerald-500 outline-none font-bold text-sm" 
                  value={username} 
                  onChange={e => setUsername(e.target.value)} 
                  placeholder="Email Address"
                />
                {!isRegistering && (
                  <div className="space-y-1">
                    <input 
                      type="password" 
                      className="w-full px-4 py-3.5 bg-slate-50 border border-slate-200 rounded-lg focus:bg-white focus:border-emerald-500 outline-none font-bold text-sm" 
                      value={password} 
                      onChange={e => setPassword(e.target.value)} 
                      placeholder="Password"
                    />
                    <p className="text-[10px] text-slate-400 px-1">First-time login? Leave password blank if you were invited.</p>
                  </div>
                )}
                {isRegistering && (
                  <input type="password" required className="w-full px-4 py-3.5 bg-slate-50 border border-slate-200 rounded-lg outline-none font-bold text-sm" value={password} onChange={e => setPassword(e.target.value)} placeholder="Setup Password" />
                )}
              </div>

              <div className="flex items-center justify-between px-1">
                  <label className="flex items-center gap-2 cursor-pointer group select-none">
                      <input type="checkbox" className="w-4 h-4 rounded border-gray-300 text-emerald-600 focus:ring-emerald-500" checked={rememberMe} onChange={e => setRememberMe(e.target.checked)} />
                      <span className="text-xs text-slate-400 font-medium group-hover:text-slate-600">Stay signed in</span>
                  </label>
              </div>

              <div className="pt-4">
                <button 
                  type="submit" 
                  disabled={isLoading || !isUrlValid} 
                  className={`w-full h-[56px] rounded-xl font-bold text-white shadow-lg transition-all text-xs uppercase tracking-widest active:scale-[0.98] flex items-center justify-center gap-3
                    ${!isUrlValid ? 'bg-slate-200 cursor-not-allowed text-slate-400 shadow-none' : isLoading ? 'bg-emerald-900 cursor-wait' : 'bg-slate-900 hover:bg-black'}`}
                >
                  {isLoading ? (
                    <svg className="animate-spin h-5 w-5 text-emerald-400" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                  ) : null}
                  {isLoading ? 'Verifying...' : isRegistering ? 'Create Admin' : 'Sign In'}
                </button>
              </div>
            </form>
          </div>
        </div>
      </div>
    </div>
  );
};

export default LoginView;

import React, { useState, useEffect } from 'react';
import { INITIAL_DATA, InspectionData, User } from './types';
import { 
    SHEET_HEADERS, PETROLEUM_HEADERS, PETROLEUM_V2_HEADERS, ACID_HEADERS,
    INSPECTION_ITEMS, PETROLEUM_INSPECTION_ITEMS, PETROLEUM_V2_ITEMS, ACID_INSPECTION_ITEMS
} from './constants';

// Hooks
import { useAuth } from './hooks/useAuth';
import { useSettings } from './hooks/useSettings';
import { useNotifications } from './hooks/useNotifications';
import { useHistory } from './hooks/useHistory';
import { useOfflineSync } from './hooks/useOfflineSync';
import { useSubscription } from './hooks/useSubscription';

// UI Components
import Toast from './components/ui/Toast';
import Sidebar from './components/layout/Sidebar';
import ReportViewerModal from './components/ui/ReportViewerModal';
import SubmissionOverlay from './components/ui/SubmissionOverlay';
import ProfileModal from './components/ui/ProfileModal';
import NotificationCenter from './components/ui/NotificationCenter'; 
import UpgradeModal from './components/ui/UpgradeModal';
import InspectionStartModal from './components/ui/InspectionStartModal';
import SubscriptionAlert from './components/ui/SubscriptionAlert';
import MaintenanceOverlay from './components/ui/MaintenanceOverlay';
import RequestInspectionModal from './components/ui/RequestInspectionModal'; 
import OnboardingWizard from './components/ui/OnboardingWizard'; 
import SystemTour from './components/ui/SystemTour'; 
import InstallPwaPrompt from './components/ui/InstallPwaPrompt';

// Views
import LoginView from './views/LoginView';
import SettingsView from './views/SettingsView';
import GeneralDashboard from './views/GeneralDashboard';
import PetroleumDashboard from './views/PetroleumDashboard';
import PetroleumV2Dashboard from './views/PetroleumV2Dashboard';
import AcidDashboard from './views/AcidDashboard';
import UserManagementView from './views/UserManagementView';
import OverviewDashboard from './views/OverviewDashboard';
import InspectionFormView from './views/InspectionFormView';
import SupportView from './views/SupportView';
import MaintenanceView from './views/MaintenanceView';
import RequestTrackingView from './views/RequestTrackingView';

// Report Components
import PrintableGeneralReport from './components/reports/PrintableGeneralReport';
import PrintablePetroleumReport from './components/reports/PrintablePetroleumReport';
import PrintablePetroleumV2Report from './components/reports/PrintablePetroleumV2Report';
import PrintableAcidReport from './components/reports/PrintableAcidReport';

const App = () => {
  const { currentUser, setCurrentUser, handleLogin, handleLogout, sessionExpired, setSessionExpired } = useAuth();
  const { settings, setSettings, appScriptUrl, setAppScriptUrl, isSavingSettings, handleSaveSettings } = useSettings();
  const { subscription } = useSubscription(appScriptUrl, currentUser);

  const [activeModule, setActiveModule] = useState('overview'); 
  const [viewMode, setViewMode] = useState<'dashboard' | 'form'>('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isProfileModalOpen, setIsProfileModalOpen] = useState(false);
  const [toast, setToast] = useState<{message: string, type: 'success' | 'error' | 'info' | 'warning'} | null>(null);
  const [isRequestModalOpen, setIsRequestModalOpen] = useState(false);
  const [showTour, setShowTour] = useState(false);

  const { historyList, isLoadingHistory, validationLists, stats, fetchHistory } = useHistory(appScriptUrl, activeModule, currentUser);

  const showToast = (message: string, type: 'success' | 'error' | 'info' | 'warning') => {
      setToast({ message, type });
      setTimeout(() => setToast(null), 4000);
  };

  useEffect(() => {
      if (sessionExpired === 'idle') showToast("Session expired due to inactivity.", 'warning');
      else if (sessionExpired === 'max_duration') showToast("Session limit reached. Log in again.", 'info');
      if (sessionExpired) setSessionExpired(null);
  }, [sessionExpired]);

  const { submissionStatus, setSubmissionStatus, isSyncing } = useOfflineSync(appScriptUrl, showToast, () => fetchHistory(true));
  const { notifications, handleMarkNotificationRead, handleDismissNotification, handleClearAllNotifications, handleGlobalAcknowledge } = useNotifications(appScriptUrl, currentUser, showToast);

  const [isReportModalOpen, setIsReportModalOpen] = useState(false);
  const [selectedReportData, setSelectedReportData] = useState<InspectionData | null>(null);
  const [formInitialData, setFormInitialData] = useState<InspectionData>(INITIAL_DATA);

  const isSuperAdmin = currentUser?.role === 'SuperAdmin';
  const showMaintenance = settings.maintenanceMode && currentUser && !isSuperAdmin;

  // --- IDENTITY FLOW LOGIC ---
  const needsOnboarding = currentUser && (currentUser as any).needsSetup;

  const startFreshInspection = (module: string, prefill?: Partial<InspectionData>) => {
      setFormInitialData({ ...INITIAL_DATA, timestamp: new Date().toISOString(), inspectedBy: currentUser?.name || '', ...prefill });
      setViewMode('form');
  };

  const handleExitForm = (savedData?: InspectionData) => setViewMode('dashboard');

  const handleGoogleSheetSubmit = async (formData: InspectionData) => {
    setSubmissionStatus('submitting');
    // Simulated success for demo or real logic would go here
    setSubmissionStatus('success');
    setTimeout(() => setViewMode('dashboard'), 2000);
  };

  const handleRequestSubmit = async (data: any) => {
      if (!appScriptUrl) return;
      try {
          await fetch(appScriptUrl, {
              method: 'POST',
              body: JSON.stringify({
                  action: 'request_inspection',
                  requester: currentUser?.name,
                  role: currentUser?.role,
                  ...data
              }),
              mode: 'no-cors'
          });
          showToast("Inspection Request submitted successfully", "success");
      } catch (e) {
          showToast("Failed to submit request", "error");
      }
  };

  const handleViewReport = (item: InspectionData | null) => {
    setSelectedReportData(item);
    setIsReportModalOpen(true);
  };

  const handleNavigate = (module: string) => {
    if (module === 'request_inspection') {
        setIsRequestModalOpen(true);
    } else {
        setActiveModule(module);
        setViewMode('dashboard');
    }
  };

  const handleOnboardingComplete = (updatedUser: User) => {
      // Identity is set, name is present, password is changed.
      const userWithSetup = { ...updatedUser, needsSetup: false };
      setCurrentUser(userWithSetup);
      localStorage.setItem('safetyCheck_user', JSON.stringify(userWithSetup));
      showToast("Profile identity synchronized.", "success");
      setShowTour(true);
  };

  const isAtRoot = activeModule === 'overview';

  if (!currentUser) {
      return (
          <>
            <InstallPwaPrompt />
            {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
            <LoginView 
                onLogin={handleLogin} 
                appScriptUrl={appScriptUrl}
                setAppScriptUrl={setAppScriptUrl}
                settings={settings}
            />
          </>
      );
  }

  // --- TRIGGER ONBOARDING WIZARD IF SETUP REQUIRED ---
  if (needsOnboarding) {
      return (
          <OnboardingWizard 
            user={currentUser} 
            appScriptUrl={appScriptUrl} 
            onComplete={handleOnboardingComplete} 
          />
      );
  }

  if (showMaintenance) {
      return (
        <>
           <MaintenanceOverlay isActive={true} message={settings.maintenanceMessage || ''} onLogout={() => handleLogout()} />
           {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
        </>
      );
  }

  return (
    <div className="min-h-screen bg-white font-sans text-gray-900 relative">
      <SubmissionOverlay status={submissionStatus} />
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

      {showTour && <SystemTour onComplete={() => setShowTour(false)} />}

      {isProfileModalOpen && (
          <ProfileModal 
            user={currentUser} 
            settings={settings}
            appScriptUrl={appScriptUrl} 
            onClose={() => setIsProfileModalOpen(false)} 
            showToast={showToast} 
            onUpdateSuccess={(u) => setCurrentUser(u)} 
            onLogout={() => { setIsProfileModalOpen(false); handleLogout(); }}
          />
      )}

      <RequestInspectionModal
          isOpen={isRequestModalOpen}
          onClose={() => setIsRequestModalOpen(false)}
          onSubmit={handleRequestSubmit}
          validationLists={validationLists}
          currentUserRole={currentUser.role}
      />

      <div className="relative z-10 min-h-screen">
          <Sidebar 
            isOpen={isSidebarOpen} 
            onClose={() => setIsSidebarOpen(false)} 
            activeModule={activeModule}
            onSelectModule={handleNavigate}
            settings={settings}
            user={currentUser}
            onLogout={() => handleLogout()}
            onEditProfile={() => setIsProfileModalOpen(true)}
            subscription={subscription} 
          />

          <div className="lg:pl-64 min-h-screen flex flex-col">
            <SubscriptionAlert subscription={subscription} user={currentUser} onManage={() => setActiveModule('settings')} />

            <header className="bg-white border-b border-gray-100 sticky top-0 z-40 px-4 py-2 flex items-center justify-between h-14">
                <div className="flex items-center gap-1 sm:gap-2">
                    {!isAtRoot ? (
                        <button 
                            onClick={() => { setActiveModule('overview'); setViewMode('dashboard'); }}
                            title="Back to Overview"
                            className="p-2 text-slate-900 hover:bg-slate-50 rounded-lg transition-all flex items-center group"
                        >
                            <svg className="w-6 h-6 transition-transform group-hover:-translate-x-0.5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path strokeLinecap="round" strokeLinejoin="round" d="M15 19l-7-7 7-7"></path></svg>
                        </button>
                    ) : (
                        <button id="sidebar-toggle" onClick={() => setIsSidebarOpen(true)} className="lg:hidden p-2 text-slate-400 hover:text-slate-600 transition-colors">
                            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M4 6h16M4 12h16M4 18h16"></path></svg>
                        </button>
                    )}

                    <div className="hidden lg:flex items-center gap-1.5 ml-2 border-l border-slate-100 pl-2">
                        <button id="sync-status-btn" onClick={() => fetchHistory(true)} title="Sync System" className={`p-1.5 transition-colors ${isLoadingHistory ? 'text-blue-600 animate-spin' : 'text-blue-400 hover:text-blue-600'}`}>
                             <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15"></path></svg>
                        </button>
                    </div>
                </div>

                <button 
                    onClick={() => { setActiveModule('overview'); setViewMode('dashboard'); }}
                    className="flex flex-col items-center hover:opacity-70 transition-opacity"
                >
                    <h1 className="text-xl font-black text-slate-900 tracking-tighter leading-none uppercase">
                        {settings.companyName || 'Alistair Group'}
                    </h1>
                    <span className="text-[7px] font-bold text-slate-400 tracking-[0.3em] mt-1 uppercase">Fleet Management</span>
                </button>

                <div className="flex items-center gap-1">
                    <NotificationCenter 
                        id="notification-bell"
                        notifications={notifications}
                        onMarkAsRead={(id) => handleMarkNotificationRead(id)}
                        onDismiss={handleDismissNotification}
                        onClearAll={handleClearAllNotifications}
                        onAcknowledge={handleGlobalAcknowledge}
                        canAcknowledge={currentUser?.role === 'Admin' || currentUser?.role === 'SuperAdmin'}
                    />
                    <button 
                        onClick={() => setIsProfileModalOpen(true)} 
                        className={`p-2 transition-colors hidden sm:block ${isProfileModalOpen ? 'text-blue-600 bg-blue-50 rounded-full' : 'text-slate-400 hover:text-slate-600'}`}
                    >
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path strokeLinecap="round" strokeLinejoin="round" d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z"></path><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z"></path></svg>
                    </button>
                </div>
            </header>

            <main className="flex-1 p-4 md:p-8 w-full max-w-7xl mx-auto">
                {viewMode === 'form' ? (
                    <InspectionFormView 
                        initialData={formInitialData}
                        activeModule={activeModule}
                        validationLists={validationLists}
                        settings={settings}
                        onSaveDraft={handleExitForm} 
                        onExit={() => setViewMode('dashboard')} 
                        onSubmit={handleGoogleSheetSubmit}
                        submissionStatus={submissionStatus}
                        onViewReport={handleViewReport}
                    />
                ) : (
                    <div className="animate-fadeIn">
                        {activeModule === 'overview' && (
                            <OverviewDashboard 
                                appScriptUrl={appScriptUrl} 
                                onNavigate={handleNavigate} 
                                userRole={currentUser.role}
                                historyList={historyList}
                                isLoading={isLoadingHistory}
                                onViewReport={handleViewReport}
                                isMaintenanceActive={settings.maintenanceMode}
                                pendingAlertsCount={notifications.filter(n => !n.read && n.type === 'critical').length}
                            />
                        )}
                        {activeModule === 'settings' && <SettingsView settings={settings} setSettings={setSettings} appScriptUrl={appScriptUrl} setAppScriptUrl={setAppScriptUrl} handleSaveSettings={handleSaveSettings} isSavingSettings={isSavingSettings} showToast={showToast} user={currentUser} />}
                        {activeModule === 'maintenance' && isSuperAdmin && <MaintenanceView user={currentUser} appScriptUrl={appScriptUrl} settings={settings} onSettingsUpdate={(s) => setSettings(p => ({...p, ...s}))} showToast={showToast} />}
                        {activeModule === 'general' && <GeneralDashboard userRole={currentUser.role} stats={stats} startNewInspection={() => startFreshInspection('general')} fetchHistory={fetchHistory} isLoadingHistory={isLoadingHistory} historyList={historyList} onViewReport={handleViewReport} onPrint={() => {}} />}
                        {activeModule === 'petroleum' && <PetroleumDashboard userRole={currentUser.role} stats={stats} startNewInspection={() => startFreshInspection('petroleum')} fetchHistory={fetchHistory} isLoadingHistory={isLoadingHistory} historyList={historyList} onViewReport={handleViewReport} onPrint={() => {}} />}
                        {activeModule === 'petroleum_v2' && <PetroleumV2Dashboard userRole={currentUser.role} stats={stats} startNewInspection={() => startFreshInspection('petroleum_v2')} fetchHistory={fetchHistory} isLoadingHistory={isLoadingHistory} historyList={historyList} onViewReport={handleViewReport} onPrint={() => {}} />}
                        {activeModule === 'acid' && <AcidDashboard userRole={currentUser.role} stats={stats} startNewInspection={() => startFreshInspection('acid')} fetchHistory={fetchHistory} isLoadingHistory={isLoadingHistory} historyList={historyList} onViewReport={handleViewReport} onPrint={() => {}} />}
                        {activeModule === 'users' && <UserManagementView currentUser={currentUser} appScriptUrl={appScriptUrl} showToast={showToast} validationLists={validationLists} settings={settings} />}
                        {activeModule === 'support' && <SupportView appScriptUrl={appScriptUrl} currentUser={currentUser} showToast={showToast} settings={settings} validationLists={validationLists} />}
                        {activeModule === 'track_requests' && <RequestTrackingView appScriptUrl={appScriptUrl} currentUser={currentUser} showToast={showToast} onRequestNew={() => setIsRequestModalOpen(true)} />}
                    </div>
                )}
            </main>
          </div>
      </div>

      {isReportModalOpen && selectedReportData && (
          <ReportViewerModal 
            onClose={() => setIsReportModalOpen(false)} 
            onPrint={() => window.print()}
            title={`Report_${selectedReportData.id || 'Draft'}`}
          >
              {activeModule === 'petroleum' ? (
                  <PrintablePetroleumReport data={selectedReportData} settings={settings} />
              ) : activeModule === 'petroleum_v2' ? (
                  <PrintablePetroleumV2Report data={selectedReportData} settings={settings} />
              ) : activeModule === 'acid' ? (
                  <PrintableAcidReport data={selectedReportData} settings={settings} />
              ) : (
                  <PrintableGeneralReport data={selectedReportData} settings={settings} />
              )}
          </ReportViewerModal>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { User, ValidationLists, SystemSettings } from '../types';
import AutocompleteInput from '../components/ui/AutocompleteInput';

interface UserManagementViewProps {
    currentUser: User;
    appScriptUrl: string;
    showToast: (msg: string, type: 'success' | 'error' | 'info' | 'warning') => void;
    validationLists: ValidationLists;
    settings?: SystemSettings;
}

const UserManagementView: React.FC<UserManagementViewProps> = ({ currentUser, appScriptUrl, showToast, validationLists, settings }) => {
    const [users, setUsers] = useState<(User & {password?: string})[]>([]);
    const [isLoading, setIsLoading] = useState(false);
    const [viewMode, setViewMode] = useState<'list' | 'form'>('list');
    const [isEditing, setIsEditing] = useState(false);
    const [originalUsername, setOriginalUsername] = useState('');

    const [formData, setFormData] = useState({
        name: '', username: '', password: '', role: 'Inspector' as any, position: ''
    });
    const [isSubmitting, setIsSubmitting] = useState(false);

    const isSuperAdmin = currentUser.role === 'SuperAdmin';

    useEffect(() => { fetchUsers(); }, []);

    const fetchUsers = async () => {
        if (!appScriptUrl) return;
        setIsLoading(true);
        try {
            const response = await fetch(appScriptUrl, { method: 'POST', body: JSON.stringify({ action: 'get_users' }) });
            const result = await response.json();
            if (result.status === 'success' && Array.isArray(result.users)) {
                let fetchedUsers = result.users;
                if (!isSuperAdmin) fetchedUsers = fetchedUsers.filter((u: User) => u.role !== 'SuperAdmin');
                setUsers(fetchedUsers);
            }
        } catch (e) { showToast("Failed to load users", 'error'); } finally { setIsLoading(false); }
    };

    const handleDelete = async (username: string) => {
        if (!window.confirm(`Remove user "${username}"?`)) return;
        setIsLoading(true);
        try {
            const response = await fetch(appScriptUrl, { method: 'POST', body: JSON.stringify({ action: 'delete_user', username }) });
            const result = await response.json();
            if (result.status === 'success') {
                showToast("User removed successfully", 'success');
                fetchUsers();
            } else { showToast(result.message || "Delete failed", 'error'); }
        } catch (e) { showToast("Connection failed", 'error'); } finally { setIsLoading(false); }
    };

    const handleEdit = (user: User) => {
        setFormData({ name: user.name || '', username: user.username, role: user.role as any, position: user.position || '', password: '' });
        setOriginalUsername(user.username);
        setIsEditing(true);
        setViewMode('form');
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!formData.username) { showToast("Login Email is required.", 'error'); return; }

        setIsSubmitting(true);
        try {
            // Note: By leaving name/password blank, the user triggers the OnboardingWizard on first login
            const payload: any = { 
                action: isEditing ? 'update_user' : 'register_user', 
                ...formData,
                preferences: {
                    ... (isEditing ? {} : { mustChangePassword: true })
                }
            };

            if (isEditing) payload.originalUsername = originalUsername;

            const response = await fetch(appScriptUrl, { method: 'POST', body: JSON.stringify(payload) });
            const result = await response.json();

            if (result.status === 'success') {
                showToast(isEditing ? "Staff details updated" : "Invite sent to new staff member", 'success');
                setViewMode('list');
                fetchUsers();
            } else { 
                showToast(result.message || "Operation failed", 'error'); 
            }
        } catch (e) { 
            showToast("Connection failed", 'error'); 
        } finally { 
            setIsSubmitting(false); 
        }
    };

    if (viewMode === 'form') {
        return (
            <div className="max-w-lg mx-auto animate-fadeIn py-4">
                <button onClick={() => setViewMode('list')} className="mb-4 text-xs font-semibold text-gray-400 hover:text-gray-800 flex items-center gap-2 transition-colors group">
                    <svg className="w-4 h-4 group-hover:-translate-x-1 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M15 19l-7-7 7-7"></path></svg>
                    Back to Directory
                </button>
                <div className="bg-white rounded-3xl shadow-xl border border-gray-200 overflow-hidden p-8">
                    <h2 className="text-2xl font-bold text-slate-800 mb-2 uppercase tracking-tight">{isEditing ? 'Edit Profile' : 'Invite Staff'}</h2>
                    <p className="text-slate-400 text-xs font-medium mb-8 uppercase tracking-wider">Configure workspace permissions</p>

                    <form onSubmit={handleSubmit} className="space-y-5">
                        <div className="space-y-4">
                            <div>
                                <label className="block text-[10px] font-bold uppercase text-slate-400 mb-2 tracking-widest">Login Identity (Email) *</label>
                                <input 
                                    type="email" 
                                    required 
                                    className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition font-semibold" 
                                    value={formData.username} 
                                    onChange={e => setFormData({...formData, username: e.target.value})} 
                                    placeholder="e.g. staff@company.com" 
                                />
                            </div>

                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-[10px] font-bold uppercase text-slate-400 mb-2 tracking-widest">System Role</label>
                                    <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl text-sm font-semibold focus:ring-2 focus:ring-blue-500 outline-none" value={formData.role} onChange={e => setFormData({...formData, role: e.target.value as any})}>
                                        <option value="Inspector">Inspector</option>
                                        <option value="Operations">Operations</option>
                                        <option value="Maintenance">Maintenance</option>
                                        <option value="Admin">Admin</option>
                                        {isSuperAdmin && <option value="SuperAdmin">SuperAdmin</option>}
                                    </select>
                                </div>
                                <AutocompleteInput 
                                    label="Job Title" 
                                    value={formData.position} 
                                    onChange={v => setFormData({...formData, position: v})} 
                                    options={validationLists.positions} 
                                    isTitleCase={true} 
                                    placeholder="Optional"
                                />
                            </div>
                        </div>

                        {!isEditing && (
                            <div className="p-4 bg-blue-50 border border-blue-100 rounded-xl flex items-start gap-3">
                                <svg className="w-5 h-5 text-blue-500 shrink-0 mt-0.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
                                <p className="text-[10px] text-blue-800 font-medium leading-relaxed">
                                    <strong>Invite-Only Mode:</strong> By leaving the name and password blank, the staff member will be prompted to setup their identity and security credentials during their first session.
                                </p>
                            </div>
                        )}

                        {isEditing && (
                            <div className="pt-4 border-t border-slate-100">
                                <AutocompleteInput label="Full Name" value={formData.name} onChange={v => setFormData({...formData, name: v})} options={validationLists.inspectors} isTitleCase={true} />
                            </div>
                        )}

                        <button type="submit" disabled={isSubmitting} className="w-full py-4 bg-slate-900 hover:bg-black text-white font-bold rounded-2xl shadow-xl transition-all active:scale-95 flex items-center justify-center gap-3 mt-4 uppercase tracking-widest text-xs">
                            {isSubmitting ? (
                                <svg className="animate-spin h-5 w-5 text-blue-400" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                            ) : null}
                            {isSubmitting ? 'Syncing...' : isEditing ? 'Update User' : 'Issue Invite'}
                        </button>
                    </form>
                </div>
            </div>
        );
    }

    return (
        <div className="max-w-6xl mx-auto space-y-6 animate-fadeIn">
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 px-2">
                <div>
                    <h2 className="text-2xl font-bold text-slate-800 uppercase tracking-tight flex items-center gap-3">
                        Staff Directory
                    </h2>
                    <p className="text-sm text-slate-400 font-medium uppercase tracking-wider">Access Control Center</p>
                </div>
                <button onClick={() => { setFormData({ name: '', username: '', password: '', role: 'Inspector', position: '' }); setIsEditing(false); setViewMode('form'); }} className="px-6 py-3 bg-slate-900 hover:bg-black text-white font-bold rounded-2xl shadow-xl transition-all flex items-center gap-2 group text-xs uppercase tracking-widest">
                    <svg className="w-5 h-5 group-hover:rotate-90 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 4v16m8-8H4"></path></svg>
                    Add Team Member
                </button>
            </div>

            <div className="bg-white rounded-3xl shadow-sm border border-gray-100 overflow-x-auto">
                <table className="w-full text-left text-sm whitespace-nowrap">
                    <thead className="bg-slate-50 text-[10px] font-bold text-slate-400 uppercase tracking-[0.2em] border-b border-slate-100">
                        <tr>
                            <th className="px-8 py-5">Full Identity</th>
                            <th className="px-8 py-5">Permission Role</th>
                            <th className="px-8 py-5">Security Status</th>
                            <th className="px-8 py-5 text-right">Controls</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-50">
                        {users.map((u, i) => (
                            <tr key={i} className="hover:bg-slate-50/50 transition-colors group">
                                <td className="px-8 py-5">
                                    <div className="flex items-center gap-4">
                                        <div className="w-11 h-11 rounded-2xl bg-white border border-slate-200 shadow-sm flex items-center justify-center font-bold text-slate-300 text-sm italic">
                                            {u.name ? u.name.substring(0, 2).toUpperCase() : '??'}
                                        </div>
                                        <div>
                                            <div className="font-semibold text-slate-700">{u.name || 'Setup Pending'}</div>
                                            <div className="text-[11px] text-slate-400 font-medium">{u.username}</div>
                                        </div>
                                    </div>
                                </td>
                                <td className="px-8 py-5">
                                    <span className={`px-3 py-1.5 rounded-xl text-[10px] font-bold uppercase tracking-wider
                                        ${u.role === 'Admin' || u.role === 'SuperAdmin' ? 'bg-indigo-50 text-indigo-600 border border-indigo-100' : 'bg-slate-50 text-slate-500 border border-slate-100'}
                                    `}>
                                        {u.role}
                                    </span>
                                </td>
                                <td className="px-8 py-5">
                                    {u.name ? (
                                        <span className="flex items-center gap-2 text-emerald-500 font-bold text-[11px] uppercase tracking-widest">
                                            <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 shadow-[0_0_8px_rgba(16,185,129,0.4)]"></div>
                                            Verified
                                        </span>
                                    ) : (
                                        <span className="flex items-center gap-2 text-amber-500 font-bold text-[11px] uppercase tracking-widest animate-pulse">
                                            <div className="w-1.5 h-1.5 rounded-full bg-amber-500"></div>
                                            Invite Sent
                                        </span>
                                    )}
                                </td>
                                <td className="px-8 py-5 text-right">
                                    <div className="flex justify-end gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                                        <button onClick={() => handleEdit(u)} className="p-2.5 text-blue-500 hover:bg-blue-50 rounded-xl transition-all" title="Edit Profile">
                                            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z"></path></svg>
                                        </button>
                                        <button onClick={() => handleDelete(u.username)} className="p-2.5 text-red-400 hover:bg-red-50 rounded-xl transition-all" title="Remove User">
                                            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path></svg>
                                        </button>
                                    </div>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
        </div>
    );
};

