import React, { useState } from 'react';
import { User, UserPreferences } from '../../types';

interface OnboardingWizardProps {
    user: User;
    appScriptUrl: string;
    onComplete: (updatedUser: User) => void;
}

const OnboardingWizard: React.FC<OnboardingWizardProps> = ({ user, appScriptUrl, onComplete }) => {
    const [step, setStep] = useState(0); // 0: Name, 1: Password, 2: Notifications, 3: Success
    const [isLoading, setIsLoading] = useState(false);

    // Identity
    const [fullName, setFullName] = useState('');
    const [newPassword, setNewPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');
    const [error, setError] = useState('');

    // Notifications
    const [prefs, setPrefs] = useState<UserPreferences>({
        emailNotifications: true,
        notifyGeneral: true,
        notifyPetroleum: true,
        notifyPetroleumV2: true,
        notifyAcid: true
    });

    const nextStep = () => {
        setError('');
        setStep(prev => prev + 1);
    };

    const handleProfileSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (step === 0 && !fullName.trim()) { setError("Full Name is required."); return; }
        if (step === 1) {
            if (newPassword.length < 4) { setError("Password too short."); return; }
            if (newPassword !== confirmPassword) { setError("Passwords do not match."); return; }
        }
        nextStep();
    };

    const handleFinalize = async () => {
        setIsLoading(true);
        try {
            const payload = {
                action: 'update_user',
                originalUsername: user.username,
                name: fullName,
                password: newPassword,
                preferences: { ...prefs, hasCompletedTour: false }
            };

            const response = await fetch(appScriptUrl, {
                method: 'POST',
                body: JSON.stringify(payload)
            });
            const result = await response.json();

            if (result.status === 'success') {
                setStep(3);
            } else {
                setError(result.message || "Failed to save profile.");
            }
        } catch (err) {
            setError("Connection lost. Please try again.");
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className="fixed inset-0 z-[200] bg-slate-900 flex items-center justify-center p-4 animate-fadeIn">
            <div className="max-w-4xl w-full bg-white rounded-3xl shadow-2xl overflow-hidden flex flex-col md:flex-row min-h-[600px]">

                {/* Left Progress Bar */}
                <div className="md:w-5/12 bg-emerald-950 p-10 flex flex-col justify-between text-white relative">
                    <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')] opacity-10"></div>
                    <div className="relative z-10">
                        <div className="w-12 h-12 bg-emerald-500 rounded-2xl flex items-center justify-center mb-8 shadow-lg shadow-emerald-500/20">
                            <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7"></path></svg>
                        </div>
                        <h1 className="text-3xl font-black mb-2 uppercase tracking-tight leading-none">Security<br/>Onboarding</h1>
                        <p className="text-emerald-400 text-xs font-bold uppercase tracking-widest opacity-60">Fleet Ops v4.0.2</p>
                    </div>

                    <div className="relative z-10 space-y-6">
                        {[
                            { s: 0, l: 'Your Identity' },
                            { s: 1, l: 'Secure Access' },
                            { s: 2, l: 'Communication' }
                        ].map(item => (
                            <div key={item.s} className={`flex items-center gap-4 transition-all duration-500 ${step >= item.s ? 'opacity-100 translate-x-0' : 'opacity-20 -translate-x-2'}`}>
                                <div className={`w-10 h-10 rounded-full flex items-center justify-center border-2 ${step > item.s ? 'bg-emerald-500 border-emerald-500 text-white' : step === item.s ? 'border-emerald-400 text-emerald-400' : 'border-emerald-800 text-emerald-800'} font-bold text-sm transition-colors`}>
                                    {step > item.s ? '✓' : item.s + 1}
                                </div>
                                <span className="font-bold text-[11px] uppercase tracking-[0.2em]">{item.l}</span>
                            </div>
                        ))}
                    </div>
                </div>

                {/* Right Form Content */}
                <div className="md:w-7/12 p-8 md:p-14 bg-white flex flex-col justify-center relative overflow-y-auto">
                    {step === 0 && (
                        <div className="animate-fadeIn">
                            <h2 className="text-2xl font-bold text-slate-800 mb-2 uppercase tracking-tight">Setup Your Account</h2>
                            <p className="text-slate-500 text-sm mb-8 font-medium leading-relaxed">Enter your full legal name as it should appear on official inspection reports and documentation.</p>
                            <form onSubmit={handleProfileSubmit} className="space-y-6">
                                <div>
                                    <label className="block text-[10px] font-bold uppercase text-slate-400 mb-2 tracking-widest">Full Name</label>
                                    <input 
                                        type="text" 
                                        autoFocus 
                                        required
                                        className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none transition font-bold text-slate-800" 
                                        value={fullName} 
                                        onChange={e => setFullName(e.target.value.replace(/\b\w/g, c => c.toUpperCase()))} 
                                        placeholder="e.g. Johnathan Doe" 
                                    />
                                </div>
                                <button type="submit" className="w-full py-4 bg-slate-900 hover:bg-black text-white font-bold rounded-xl shadow-xl transition-all active:scale-95 flex items-center justify-center gap-2 uppercase tracking-widest text-xs">
                                    Continue to Security
                                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M14 5l7 7m0 0l-7 7m7-7H3"></path></svg>
                                </button>
                            </form>
                        </div>
                    )}

                    {step === 1 && (
                        <div className="animate-fadeIn">
                            <h2 className="text-2xl font-bold text-slate-800 mb-2 uppercase tracking-tight">Security Credentials</h2>
                            <p className="text-slate-500 text-sm mb-8 font-medium">Create a secure password to protect your access to the fleet database.</p>
                            <form onSubmit={handleProfileSubmit} className="space-y-6">
                                <div className="space-y-4">
                                    <input type="password" autoFocus required className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none font-bold text-slate-800" value={newPassword} onChange={e => setNewPassword(e.target.value)} placeholder="New Password" />
                                    <input type="password" required className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none font-bold text-slate-800" value={confirmPassword} onChange={e => setConfirmPassword(e.target.value)} placeholder="Confirm Password" />
                                </div>
                                {error && <div className="text-red-600 text-[10px] font-bold bg-red-50 p-3 rounded-lg border border-red-100 uppercase tracking-widest">{error}</div>}
                                <button type="submit" className="w-full py-4 bg-slate-900 hover:bg-black text-white font-bold rounded-xl shadow-xl transition-all active:scale-95 flex items-center justify-center gap-2 uppercase tracking-widest text-xs">
                                    Continue to Alerts
                                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M14 5l7 7m0 0l-7 7m7-7H3"></path></svg>
                                </button>
                            </form>
                        </div>
                    )}

                    {step === 2 && (
                        <div className="animate-fadeIn">
                            <h2 className="text-2xl font-bold text-slate-800 mb-2 uppercase tracking-tight">Stay Informed</h2>
                            <p className="text-slate-500 text-sm mb-8 font-medium">Select which automated inspection summaries you wish to receive via email.</p>

                            <div className="space-y-3 mb-8">
                                <label className={`flex items-center justify-between p-4 rounded-xl border-2 transition-all cursor-pointer ${prefs.emailNotifications ? 'bg-emerald-50 border-emerald-500' : 'bg-white border-slate-100'}`}>
                                    <div>
                                        <p className="text-sm font-bold text-slate-800 uppercase tracking-tight">Email Alerts Enabled</p>
                                        <p className="text-[10px] text-emerald-600 font-bold uppercase tracking-wide">Recommended for Compliance</p>
                                    </div>
                                    <input type="checkbox" className="w-6 h-6 rounded border-gray-300 text-emerald-600 focus:ring-emerald-500" checked={prefs.emailNotifications} onChange={() => setPrefs(p => ({...p, emailNotifications: !p.emailNotifications}))} />
                                </label>

                                <div className={`grid grid-cols-2 gap-3 transition-opacity ${!prefs.emailNotifications && 'opacity-30 pointer-events-none'}`}>
                                    {[
                                        { k: 'notifyGeneral', l: 'General' },
                                        { k: 'notifyPetroleum', l: 'Petro V1' },
                                        { k: 'notifyPetroleumV2', l: 'Petro V2' },
                                        { k: 'notifyAcid', l: 'Acid' }
                                    ].map(m => (
                                        <label key={m.k} className="flex items-center justify-between p-3 bg-slate-50 rounded-lg border border-slate-100 cursor-pointer hover:bg-slate-100">
                                            <span className="text-[10px] font-bold text-slate-500 uppercase tracking-wide">{m.l}</span>
                                            <input type="checkbox" className="w-4 h-4 rounded text-emerald-600" checked={prefs[m.k as keyof UserPreferences] as boolean} onChange={() => setPrefs(p => ({...p, [m.k]: !p[m.k as keyof UserPreferences]}))} />
                                        </label>
                                    ))}
                                </div>
                            </div>

                            {error && <div className="text-red-600 text-[10px] font-bold mb-4">{error}</div>}

                            <button onClick={handleFinalize} disabled={isLoading} className="w-full py-4 bg-emerald-600 hover:bg-emerald-700 text-white font-bold rounded-xl shadow-xl transition-all active:scale-95 flex items-center justify-center gap-2 uppercase tracking-widest text-xs">
                                {isLoading ? (
                                    <svg className="animate-spin h-5 w-5 text-white" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                                ) : (
                                    <>
                                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7"></path></svg>
                                        Finalize Workspace
                                    </>
                                )}
                            </button>
                        </div>
                    )}

                    {step === 3 && (
                        <div className="text-center animate-fadeIn">
                            <div className="w-24 h-24 bg-emerald-50 rounded-full flex items-center justify-center mx-auto mb-8 shadow-inner">
                                <svg className="w-12 h-12 text-emerald-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
                            </div>
                            <h2 className="text-3xl font-bold text-slate-800 mb-4 uppercase tracking-tighter">Access Active</h2>
                            <p className="text-slate-500 text-sm font-medium leading-relaxed mb-10 max-w-xs mx-auto">Your identity has been verified. Welcome to the team.</p>
                            <button 
                                onClick={() => onComplete({ ...user, name: fullName, preferences: prefs })} 
                                className="w-full py-4 bg-slate-900 hover:bg-black text-white font-bold rounded-2xl shadow-2xl transition-all transform hover:scale-105 active:scale-95 uppercase tracking-widest text-xs"
                            >
                                Launch Dashboard
                            </button>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

export default OnboardingWizard;

import React, { useState } from 'react';
import { User, SystemSettings, UserPreferences } from '../../types';

interface ProfileModalProps {
    user: User;
    settings: SystemSettings;
    appScriptUrl: string;
    onClose: () => void;
    showToast: (msg: string, type: 'success' | 'error' | 'info' | 'warning') => void;
    onUpdateSuccess: (newUser: User) => void;
    onLogout: () => void;
}

const ProfileModal: React.FC<ProfileModalProps> = ({ 
    user, 
    settings, 
    appScriptUrl, 
    onClose, 
    showToast, 
    onUpdateSuccess, 
    onLogout
}) => {
    const nameParts = (user.name || '').split(' ');
    const firstName = nameParts[0] || '';
    const lastName = nameParts.slice(1).join(' ') || '';

    // Password State
    const [password, setPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');
    const [isUpdatingPassword, setIsUpdatingPassword] = useState(false);

    // Preferences State
    const [prefs, setPrefs] = useState<UserPreferences>(user.preferences || {
        emailNotifications: true,
        notifyGeneral: true,
        notifyPetroleum: true,
        notifyPetroleumV2: true,
        notifyAcid: true
    });
    const [isUpdatingPrefs, setIsUpdatingPrefs] = useState(false);

    const handlePasswordChange = async () => {
        if (!password) {
            showToast("Please enter a new password.", "warning");
            return;
        }
        if (password !== confirmPassword) {
            showToast("Passwords do not match.", "error");
            return;
        }

        setIsUpdatingPassword(true);
        try {
            const response = await fetch(appScriptUrl, {
                method: 'POST',
                body: JSON.stringify({
                    action: 'update_user',
                    originalUsername: user.username,
                    password: password
                })
            });
            const result = await response.json();

            if (result.status === 'success') {
                showToast("Security updated!", 'success');
                setPassword('');
                setConfirmPassword('');
            } else {
                showToast(result.message || "Failed to update.", 'error');
            }
        } catch (e) {
            showToast("Sync failed.", 'error');
        } finally {
            setIsUpdatingPassword(false);
        }
    };

    const handleUpdatePrefs = async (newPrefs: UserPreferences) => {
        setPrefs(newPrefs);
        setIsUpdatingPrefs(true);
        try {
            const response = await fetch(appScriptUrl, {
                method: 'POST',
                body: JSON.stringify({
                    action: 'update_user',
                    originalUsername: user.username,
                    preferences: newPrefs
                })
            });
            const result = await response.json();
            if (result.status === 'success') {
                onUpdateSuccess({ ...user, preferences: newPrefs });
                showToast("Preferences synced.", 'success');
            }
        } catch (e) {
            showToast("Sync failed.", 'error');
        } finally {
            setIsUpdatingPrefs(false);
        }
    };

    const togglePref = (key: keyof UserPreferences) => {
        const next = { ...prefs, [key]: !prefs[key] };
        handleUpdatePrefs(next);
    };

    return (
        <div className="fixed inset-0 z-[100] bg-white flex flex-col animate-fadeIn overflow-y-auto">
            {/* Header */}
            <div className="sticky top-0 bg-white border-b border-gray-100 px-4 py-3 flex items-center shrink-0 z-10 shadow-sm">
                <button 
                    onClick={onClose}
                    className="p-2 text-blue-500 hover:bg-blue-50 rounded-full transition-all"
                >
                    <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path strokeLinecap="round" strokeLinejoin="round" d="M15 19l-7-7 7-7"></path></svg>
                </button>
                <h1 className="flex-1 text-center font-bold text-slate-800 text-sm uppercase tracking-widest">My Workspace</h1>
                <div className="w-10"></div>
            </div>

            <div className="max-w-2xl mx-auto w-full px-6 py-10 space-y-12 pb-24">

                {/* 1. YOUR DETAILS */}
                <section className="space-y-4">
                    <h3 className="text-lg font-bold text-slate-800 border-b border-gray-100 pb-2 uppercase tracking-tight">Identity Profile</h3>
                    <div className="space-y-3">
                        <div className="flex justify-between items-center text-sm py-1">
                            <span className="font-semibold text-slate-600">Organization</span>
                            <span className="text-slate-400 font-medium">{settings.companyName || 'Alistair Group'}</span>
                        </div>
                        <div className="flex justify-between items-center text-sm py-1">
                            <span className="font-semibold text-slate-600">First Name</span>
                            <span className="text-slate-400 font-medium">{firstName}</span>
                        </div>
                        <div className="flex justify-between items-center text-sm py-1">
                            <span className="font-semibold text-slate-600">Last Name</span>
                            <span className="text-slate-400 font-medium">{lastName}</span>
                        </div>
                        <div className="flex justify-between items-center text-sm py-1">
                            <span className="font-semibold text-slate-600">Login ID</span>
                            <span className="text-slate-400 font-medium">{user.username}</span>
                        </div>
                    </div>
                </section>

                {/* 2. CHANGE PASSWORD */}
                <section className="space-y-4">
                    <h3 className="text-lg font-bold text-slate-800 border-b border-gray-100 pb-2 uppercase tracking-tight">Security Access</h3>
                    <div className="space-y-4">
                        <input 
                            type="password" 
                            placeholder="Set New Password"
                            className="w-full p-3.5 border border-gray-200 rounded-xl text-sm bg-slate-50 focus:bg-white focus:ring-2 focus:ring-blue-100 outline-none transition-all font-semibold"
                            value={password}
                            onChange={(e) => setPassword(e.target.value)}
                        />
                        <input 
                            type="password" 
                            placeholder="Confirm Password"
                            className="w-full p-3.5 border border-gray-200 rounded-xl text-sm bg-slate-50 focus:bg-white focus:ring-2 focus:ring-blue-100 outline-none transition-all font-semibold"
                            value={confirmPassword}
                            onChange={(e) => setConfirmPassword(e.target.value)}
                        />
                        <button 
                            onClick={handlePasswordChange}
                            disabled={isUpdatingPassword}
                            className="w-full py-4 bg-slate-900 hover:bg-black text-white font-bold rounded-xl shadow-lg transition-all active:scale-95 flex items-center justify-center gap-2 text-xs uppercase tracking-widest"
                        >
                            {isUpdatingPassword ? (
                                <>
                                    <svg className="animate-spin h-5 w-5 text-white" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                                    Verifying...
                                </>
                            ) : 'Update Security'}
                        </button>
                    </div>
                </section>

                {/* 3. EMAIL NOTIFICATIONS */}
                <section className="space-y-4">
                    <div className="flex items-center justify-between border-b border-gray-100 pb-2">
                        <h3 className="text-lg font-bold text-slate-800 uppercase tracking-tight">Alert Preferences</h3>
                        {isUpdatingPrefs && <svg className="animate-spin h-4 w-4 text-blue-500" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>}
                    </div>

                    <div className="space-y-2">
                        <label className="flex items-center justify-between p-4 rounded-2xl bg-slate-50 border border-slate-100 cursor-pointer group">
                            <div>
                                <p className="text-sm font-bold text-slate-800">Master Email Alert</p>
                                <p className="text-[10px] text-slate-400 font-semibold uppercase tracking-wider">Automated system triggers</p>
                            </div>
                            <input type="checkbox" className="w-5 h-5 rounded border-gray-300 text-blue-600 focus:ring-blue-500" checked={prefs.emailNotifications} onChange={() => togglePref('emailNotifications')} />
                        </label>

                        <div className={`grid grid-cols-1 md:grid-cols-2 gap-3 pt-2 transition-opacity duration-300 ${!prefs.emailNotifications && 'opacity-40 pointer-events-none'}`}>
                            {[
                                { key: 'notifyGeneral', label: 'General Fleet' },
                                { key: 'notifyPetroleum', label: 'Petroleum V1' },
                                { key: 'notifyPetroleumV2', label: 'Petroleum V2' },
                                { key: 'notifyAcid', label: 'Acid Tankers' }
                            ].map((item) => (
                                <label key={item.key} className="flex items-center justify-between px-4 py-3.5 rounded-xl border border-gray-100 bg-white hover:bg-gray-50 cursor-pointer transition-colors shadow-sm">
                                    <span className="text-[11px] font-bold text-slate-500 uppercase tracking-widest">{item.label}</span>
                                    <input 
                                        type="checkbox" 
                                        className="w-4 h-4 rounded border-gray-300 text-blue-600" 
                                        checked={prefs[item.key as keyof UserPreferences] as boolean} 
                                        onChange={() => togglePref(item.key as keyof UserPreferences)} 
                                    />
                                </label>
                            ))}
                        </div>
                    </div>
                </section>

                {/* 5. LOGOUT */}
                <section className="pt-8">
                    <button 
                        onClick={onLogout}
                        className="w-full py-4 bg-white border-2 border-red-500 text-red-500 hover:bg-red-50 font-bold rounded-xl transition-all flex items-center justify-center gap-3 uppercase tracking-[0.2em] active:scale-95 text-xs"
                    >
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path strokeLinecap="round" strokeLinejoin="round" d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H5a3 3-0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1"></path></svg>
                        Sign Out
                    </button>
                </section>
            </div>
        </div>
    );
};

export default ProfileModal;

