import React, { useState, useEffect } from 'react';
import { InspectionData, InspectionStatus, InspectionItemConfig, ValidationLists, SystemSettings } from '../types';
import { INSPECTION_ITEMS, INSPECTION_CATEGORIES, PETROLEUM_INSPECTION_ITEMS, PETROLEUM_CATEGORIES, ACID_INSPECTION_ITEMS, ACID_CATEGORIES, PETROLEUM_V2_ITEMS, PETROLEUM_V2_CATEGORIES, SECTIONS } from '../constants';
import CameraCapture from '../components/CameraCapture';
import SignaturePad from '../components/SignaturePad';
import StatusButton from '../components/ui/StatusButton';
import Input from '../components/ui/Input';
import AutocompleteInput from '../components/ui/AutocompleteInput';
import PrintableGeneralReport from '../components/reports/PrintableGeneralReport';
import PrintablePetroleumReport from '../components/reports/PrintablePetroleumReport';
import PrintablePetroleumV2Report from '../components/reports/PrintablePetroleumV2Report';
import PrintableAcidReport from '../components/reports/PrintableAcidReport';

interface InspectionFormViewProps {
    initialData: InspectionData;
    activeModule: string;
    validationLists: ValidationLists;
    settings: SystemSettings;
    onSaveDraft: (data: InspectionData) => void;
    onSubmit: (data: InspectionData) => void;
    onExit: () => void;
    submissionStatus: 'idle' | 'submitting' | 'success' | 'offline_saved';
    onViewReport: (data: InspectionData) => void;
}

const InspectionFormView: React.FC<InspectionFormViewProps> = ({ 
    initialData, activeModule, validationLists, settings, onSaveDraft, onSubmit, onExit, submissionStatus, onViewReport 
}) => {
    const [formData, setFormData] = useState<InspectionData & any>(initialData);
    const [currentSection, setCurrentSection] = useState(0);
    const [errors, setErrors] = useState<Record<string, boolean>>({});

    const updateField = (field: string, value: any) => {
        setFormData((prev: any) => ({ ...prev, [field]: value }));
        if (errors[field]) {
            setErrors(prev => {
                const next = {...prev};
                delete next[field];
                return next;
            });
        }
    };

    const getItemsForStep = (stepIndex: number): InspectionItemConfig[] => {
        let categories: string[] = [];
        let sourceItems: InspectionItemConfig[] = [];

        if (activeModule === 'general') sourceItems = INSPECTION_ITEMS;
        else if (activeModule === 'petroleum') sourceItems = PETROLEUM_INSPECTION_ITEMS;
        else if (activeModule === 'petroleum_v2') sourceItems = PETROLEUM_V2_ITEMS;
        else if (activeModule === 'acid') sourceItems = ACID_INSPECTION_ITEMS;

        if (activeModule === 'general') {
            if (stepIndex === 2) categories = [INSPECTION_CATEGORIES.PPE, INSPECTION_CATEGORIES.DOCUMENTATION];
            if (stepIndex === 3) categories = [INSPECTION_CATEGORIES.VEHICLE_EXTERIOR, INSPECTION_CATEGORIES.LIGHTS_ELECTRICAL];
            if (stepIndex === 4) categories = [INSPECTION_CATEGORIES.MECHANICAL, INSPECTION_CATEGORIES.TRAILER];
        } else if (activeModule === 'petroleum') {
            if (stepIndex === 2) categories = [PETROLEUM_CATEGORIES.TRUCK_EQUIPMENT];
            if (stepIndex === 3) categories = [PETROLEUM_CATEGORIES.TYRES, PETROLEUM_CATEGORIES.PPE_ID];
            if (stepIndex === 4) categories = [PETROLEUM_CATEGORIES.DOCUMENTS, PETROLEUM_CATEGORIES.ONBOARD];
        } else if (activeModule === 'petroleum_v2') {
            if (stepIndex === 2) categories = [PETROLEUM_V2_CATEGORIES.PRIME_MOVER];
            if (stepIndex === 3) categories = [PETROLEUM_V2_CATEGORIES.TRAILER_TANKS];
            if (stepIndex === 4) categories = [PETROLEUM_V2_CATEGORIES.DRIVER, PETROLEUM_V2_CATEGORIES.SAFETY_SIGNS, PETROLEUM_V2_CATEGORIES.DOCUMENTS];
        } else if (activeModule === 'acid') {
            if (stepIndex === 2) categories = [ACID_CATEGORIES.PPE];
            if (stepIndex === 3) categories = [ACID_CATEGORIES.VEHICLE];
            if (stepIndex === 4) categories = [ACID_CATEGORIES.SPILL_KIT, ACID_CATEGORIES.DOCUMENTATION];
        }

        return sourceItems.filter(item => categories.includes(item.category));
    };

    const validateSection = (sectionIndex: number): boolean => {
        const newErrors: Record<string, boolean> = {};

        if (sectionIndex === 0) {
            if (!formData.truckNo) newErrors.truckNo = true;
            if (!formData.trailerNo) newErrors.trailerNo = true;
            if (!formData.driverName) newErrors.driverName = true;
            if (!formData.location) newErrors.location = true;
            if (!formData.odometer) newErrors.odometer = true;
            if (activeModule !== 'general' && !formData.jobCard) newErrors.jobCard = true;
        }

        if (sectionIndex >= 2 && sectionIndex <= 4) {
            const requiredItems = getItemsForStep(sectionIndex);

            requiredItems.forEach(item => {
                const val = formData[item.id];
                if (!val) {
                    newErrors[item.id] = true;
                }
            });
        }

        if (sectionIndex === 5) {
             if (!formData.remarks || formData.remarks.trim() === '') newErrors.remarks = true;
             if (!formData.rate || formData.rate === 0) newErrors.rate = true;
             if (!formData.inspectorSignature) newErrors.inspectorSignature = true;
             if (!formData.driverSignature) newErrors.driverSignature = true;
        }

        if (Object.keys(newErrors).length > 0) {
            setErrors(newErrors);
            window.scrollTo({ top: 0, behavior: 'smooth' }); 
            return false;
        }

        setErrors({});
        return true;
    };

    const validateFullForm = (): boolean => {
        for (let i = 0; i <= 5; i++) {
            if (!validateSection(i)) {
                setCurrentSection(i); 
                return false;
            }
        }
        return true;
    };

    const handleNext = () => {
        if (!validateSection(currentSection)) return;
        window.scrollTo({ top: 0, behavior: 'smooth' });
        setCurrentSection(prev => Math.min(prev + 1, SECTIONS.length - 1));
    };

    const handleBack = () => {
        if (currentSection === 0) {
            onExit();
        } else {
            window.scrollTo({ top: 0, behavior: 'smooth' });
            setCurrentSection(prev => Math.max(prev - 1, 0));
        }
    };

    const handleSubmitInspection = () => {
        if (validateFullForm()) {
            onSubmit(formData);
        }
    };

    const renderDetailsSection = () => (
      <div className="space-y-4 sm:space-y-6 animate-fadeIn">
        {formData.requestId && (
            <div className="bg-gradient-to-r from-indigo-500 to-blue-600 p-4 rounded-xl shadow-lg flex flex-col sm:flex-row sm:items-center justify-between text-white border border-indigo-400 gap-3">
                <div className="flex items-center gap-3">
                    <div className="p-2 bg-white/20 rounded-lg backdrop-blur-sm">
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-3 7h3m-3 4h3m-6-4h.01M9 16h.01"></path></svg>
                    </div>
                    <div>
                        <p className="text-[10px] font-bold uppercase tracking-widest text-indigo-100">Assignment</p>
                        <p className="text-sm font-bold truncate max-w-[200px] sm:max-w-none">Order #{formData.requestId}</p>
                    </div>
                </div>
                <span className="text-[10px] bg-white text-indigo-600 px-2.5 py-1 rounded-full font-black shadow-sm uppercase tracking-widest self-start sm:self-center">
                    Priority Request
                </span>
            </div>
        )}

        <div className="bg-white p-5 sm:p-8 rounded-2xl shadow-sm border border-gray-100">
          <h2 className="text-lg sm:text-xl font-bold text-gray-800 mb-6 flex items-center gap-2">
            <span className="bg-blue-100 text-blue-700 p-2 rounded-lg">
               <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 6H5a2 2 0 00-2 2v9a2 2 0 002 2h14a2 2 0 002-2V8a2 2 0 00-2-2h-5m-4 0V5a2 2 0 114 0v1m-4 0c0 .667.333 1 1 1v1m2-2c-.667 0-1 .333-1 1v1"></path></svg>
            </span>
            Vehicle Context
          </h2>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4 sm:gap-8">
            <AutocompleteInput 
              label="Truck Reg No *" 
              value={formData.truckNo} 
              onChange={v => updateField('truckNo', v)} 
              options={validationLists.trucks}
              placeholder="e.g. AHB 1502"
              isRegNo={true}
              error={errors.truckNo}
            />
            <AutocompleteInput 
              label="Trailer Reg No *" 
              value={formData.trailerNo} 
              onChange={v => updateField('trailerNo', v)} 
              options={validationLists.trailers}
              placeholder="e.g. T-900"
              isRegNo={true}
              error={errors.trailerNo}
            />

            <Input 
              label="Job Card Reference" 
              value={formData.jobCard || ''} 
              onChange={v => updateField('jobCard', v)} 
              error={errors.jobCard}
            />

            <AutocompleteInput 
              label="Lead Inspector" 
              value={formData.inspectedBy} 
              onChange={v => updateField('inspectedBy', v)} 
              options={validationLists.inspectors}
              placeholder="Auto-filled"
              isTitleCase={true}
              readOnly={true}
            />

            <AutocompleteInput 
              label="Assigned Driver *" 
              value={formData.driverName} 
              onChange={v => updateField('driverName', v)} 
              options={validationLists.drivers}
              placeholder="Full Name"
              isTitleCase={true}
              error={errors.driverName}
            />
            <AutocompleteInput 
              label="Operation Hub *" 
              value={formData.location} 
              onChange={v => updateField('location', v)} 
              options={validationLists.locations}
              placeholder="City/Base"
              isTitleCase={true}
              error={errors.location}
            />

            <Input 
              label="Current Odometer (km) *" 
              type="number" 
              value={formData.odometer} 
              onChange={v => updateField('odometer', v)} 
              error={errors.odometer}
            />
          </div>
        </div>
      </div>
    );

    const renderPhotosSection = () => (
      <div className="space-y-6 animate-fadeIn">
         <div className="bg-white p-5 sm:p-8 rounded-2xl shadow-sm border border-gray-100">
          <h2 className="text-xl font-bold text-gray-800 mb-2 flex items-center gap-2">
            <span className="bg-blue-100 text-blue-700 p-2 rounded-lg">
               <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z"></path><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 13a3 3 0 11-6 0 3 3 0 016 0z"></path></svg>
            </span>
            Documentary Evidence
          </h2>
          <p className="text-gray-400 text-xs font-medium mb-6 uppercase tracking-wider">Visual inspection records</p>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 sm:gap-8">
            <CameraCapture label="Horse: Front" existingImage={formData.photoFront} onCapture={img => updateField('photoFront', img)} />
            <CameraCapture label="Horse: Driver Side" existingImage={formData.photoLS} onCapture={img => updateField('photoLS', img)} />
            <CameraCapture label="Horse: Passenger Side" existingImage={formData.photoRS} onCapture={img => updateField('photoRS', img)} />
            <CameraCapture label="Trailer: Rear" existingImage={formData.photoBack} onCapture={img => updateField('photoBack', img)} />
          </div>
        </div>
      </div>
    );

    const renderInspectionSection = (categoriesToShow: string[]) => {
        const itemsToRender = getItemsForStep(currentSection).filter(i => categoriesToShow.includes(i.category));

        const grouping: Record<string, InspectionItemConfig[]> = {};
        categoriesToShow.forEach(cat => {
            grouping[cat] = itemsToRender.filter(i => i.category === cat);
        });

        return (
          <div className="space-y-6 sm:space-y-10 animate-fadeIn">
            {categoriesToShow.map(cat => (
              <div key={cat} className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
                <div className="bg-slate-50 px-6 py-4 border-b border-gray-100 flex justify-between items-center">
                  <h3 className="text-sm sm:text-base font-bold text-slate-700 uppercase tracking-widest">{cat}</h3>
                  <span className="text-[9px] bg-red-50 text-red-500 font-black px-2 py-1 rounded border border-red-100 uppercase tracking-widest">Mandatory</span>
                </div>
                <div className="divide-y divide-gray-50">
                  {grouping[cat].map(item => (
                    <div key={item.id} className={`p-5 sm:p-8 transition-colors ${errors[item.id] ? 'bg-red-50/50' : 'hover:bg-slate-50/30'}`}>
                      <div className="flex justify-between items-start mb-4">
                          <span className={`font-bold text-sm sm:text-base leading-tight ${errors[item.id] ? 'text-red-700' : 'text-slate-800'}`}>
                              {item.label}
                          </span>
                      </div>
                      <div className="grid grid-cols-4 gap-2 sm:gap-4 max-w-lg">
                         <StatusButton label="OK" status={InspectionStatus.GOOD} current={formData[item.id]} onClick={() => updateField(item.id, InspectionStatus.GOOD)} colorClass="green" />
                         <StatusButton label="Fail" status={InspectionStatus.BAD} current={formData[item.id]} onClick={() => updateField(item.id, InspectionStatus.BAD)} colorClass="red" />
                         <StatusButton label="Alert" status={InspectionStatus.ATTENTION} current={formData[item.id]} onClick={() => updateField(item.id, InspectionStatus.ATTENTION)} colorClass="yellow" />
                         <StatusButton label="N/A" status={InspectionStatus.NIL} current={formData[item.id]} onClick={() => updateField(item.id, InspectionStatus.NIL)} colorClass="gray" />
                      </div>
                      {errors[item.id] && <p className="mt-3 text-[10px] text-red-500 font-black uppercase tracking-widest flex items-center gap-1"><span className="w-1 h-1 rounded-full bg-red-500"></span> Selection Required</p>}
                    </div>
                  ))}
                </div>
              </div>
            ))}
          </div>
        );
    };

    const renderSignaturesSection = () => (
      <div className="space-y-6 animate-fadeIn">
        <div className="bg-white p-5 sm:p-8 rounded-2xl shadow-sm border border-gray-100">
          <h2 className="text-xl font-bold text-gray-800 mb-6 uppercase tracking-tight">Final Authorization</h2>

          <div className="mb-8">
            <label className={`block text-[10px] font-black uppercase mb-2 tracking-widest ${errors.remarks ? 'text-red-600' : 'text-slate-400'}`}>Observations & Findings *</label>
            <textarea 
              className={`w-full p-4 border rounded-xl h-32 outline-none transition-all font-semibold text-sm
                 ${errors.remarks 
                   ? 'border-red-300 ring-2 ring-red-100 bg-red-50 placeholder-red-300' 
                   : 'border-gray-200 focus:ring-2 focus:ring-blue-100 bg-slate-50'
                 }
              `} 
              placeholder="Describe vehicle condition..."
              value={formData.remarks}
              onChange={(e) => updateField('remarks', e.target.value)}
            />
          </div>

          <div className="mb-10">
              <CameraCapture label="Defect Photo (Highly Recommended)" existingImage={formData.photoDamage} onCapture={img => updateField('photoDamage', img)} />
          </div>

          <div className="mb-10">
             <label className={`block text-[10px] font-black uppercase mb-4 tracking-widest ${errors.rate ? 'text-red-600' : 'text-slate-400'}`}>Vehicle Safety Rating *</label>
             <div className={`flex gap-2 sm:gap-4 flex-wrap p-2 rounded-2xl transition-colors ${errors.rate ? 'bg-red-50' : 'bg-slate-50'}`}>
               {[1, 2, 3, 4, 5].map(num => (
                 <button
                  key={num}
                  type="button"
                  onClick={() => updateField('rate', num)}
                  className={`w-12 h-12 rounded-xl font-black text-lg transition-all ${
                    formData.rate === num ? 'bg-slate-900 text-white shadow-xl scale-110' : 'bg-white text-slate-400 border border-slate-200 hover:border-slate-400'
                  }`}
                 >
                   {num}
                 </button>
               ))}
               <div className="flex-1 flex items-center px-4">
                   <span className="text-[10px] font-bold text-slate-400 italic">1 = Dangerous, 5 = Pristine</span>
               </div>
             </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8 pt-8 border-t border-slate-100">
             <div className={errors.inspectorSignature ? 'p-4 bg-red-50 rounded-2xl border-2 border-red-100' : ''}>
                 <SignaturePad label="Inspector Sign-off" existingSignature={formData.inspectorSignature} onSave={sig => updateField('inspectorSignature', sig)} />
                 {errors.inspectorSignature && <p className="text-[10px] text-red-600 font-black mt-2 uppercase tracking-widest">Mandatory Signature</p>}
             </div>
             <div className={errors.driverSignature ? 'p-4 bg-red-50 rounded-2xl border-2 border-red-100' : ''}>
                 <SignaturePad label="Driver Acknowledgement" existingSignature={formData.driverSignature} onSave={sig => updateField('driverSignature', sig)} />
                 {errors.driverSignature && <p className="text-[10px] text-red-600 font-black mt-2 uppercase tracking-widest">Mandatory Signature</p>}
             </div>
          </div>
        </div>
      </div>
    );

    const renderSummarySection = () => (
      <div className="space-y-6 animate-fadeIn pb-12">
        <div className="bg-white p-6 sm:p-10 rounded-2xl shadow-lg border border-gray-100 text-center">
          <div className="w-16 h-16 bg-emerald-100 rounded-full flex items-center justify-center mx-auto mb-6">
              <svg className="w-8 h-8 text-emerald-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
          </div>
          <h2 className="text-2xl font-bold text-slate-800 mb-2">Checklist Verified</h2>
          <p className="text-slate-500 font-medium text-sm">Draft generated successfully. Review formal document below.</p>
          <button 
              onClick={() => onViewReport(formData)}
              className="mt-6 px-8 py-3 bg-slate-900 text-white rounded-xl font-bold text-xs uppercase tracking-widest hover:bg-black transition-all shadow-xl active:scale-95"
          >
              Fullscreen Preview
          </button>
        </div>

        <div className="bg-white border border-gray-200 rounded-2xl overflow-hidden shadow-sm">
          <div className="bg-slate-50 px-6 py-4 border-b border-gray-100 flex justify-between items-center">
              <h3 className="font-bold text-xs text-slate-500 uppercase tracking-[0.2em]">Document Layout</h3>
          </div>
          <div className="p-4 sm:p-8 overflow-x-auto bg-slate-200/50 flex justify-center">
               <div className="bg-white shadow-2xl origin-top transform scale-[0.4] sm:scale-[0.6] md:scale-[0.85] lg:scale-100 transition-all duration-500">
                   {activeModule === 'petroleum' ? (
                       <PrintablePetroleumReport data={formData} settings={settings} />
                   ) : activeModule === 'petroleum_v2' ? (
                       <PrintablePetroleumV2Report data={formData} settings={settings} />
                   ) : activeModule === 'acid' ? (
                       <PrintableAcidReport data={formData} settings={settings} />
                   ) : (
                       <PrintableGeneralReport data={formData} settings={settings} />
                   )}
               </div>
          </div>
        </div>

        <div className="mt-8 bg-emerald-950 rounded-3xl p-6 sm:p-10 text-white shadow-2xl relative overflow-hidden group">
            <div className="absolute inset-0 bg-emerald-900/40 transform -skew-y-6 translate-y-32 group-hover:translate-y-0 transition-transform duration-1000"></div>
            <div className="relative z-10 flex flex-col md:flex-row items-center justify-between gap-8">
                <div className="text-center md:text-left">
                    <h3 className="text-2xl sm:text-3xl font-black mb-2 text-white uppercase tracking-tight">Final Submission</h3>
                    <p className="text-emerald-400 text-xs sm:text-sm font-medium max-w-md opacity-80 uppercase tracking-widest">
                        Syncing with official fleet databases.
                    </p>

                    {!navigator.onLine && (
                         <div className="mt-6 inline-flex items-center gap-2 bg-amber-500/20 text-amber-300 px-4 py-1.5 rounded-full text-[10px] font-black border border-amber-500/30 uppercase tracking-widest animate-pulse">
                             <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M18.364 5.636a9 9 0 010 12.728m0 0l-2.829-2.829m2.829 2.829L21 21M15.536 8.464a5 5 0 010 7.072m0 0l-2.829-2.829m-4.243 2.829a4.978 4.978 0 01-1.414-2.83m-1.414 5.658a9 9 0 01-2.167-9.238m7.824 2.167a1 1 0 111.414 1.414m-1.414-1.414L3 3m8.293 8.293l1.414 1.414"></path></svg>
                             Offline: Queuing for later
                         </div>
                    )}
                </div>
                <button 
                    onClick={handleSubmitInspection}
                    disabled={submissionStatus !== 'idle'}
                    className={`w-full md:w-auto px-10 py-5 text-white rounded-2xl font-black text-lg shadow-2xl transition-all flex items-center justify-center gap-3 transform hover:scale-105 active:scale-95 border-2 border-white/20 uppercase tracking-[0.2em]
                       ${submissionStatus !== 'idle' ? 'bg-slate-700 cursor-wait' : 'bg-emerald-600 hover:bg-emerald-500'}
                    `}
                >
                    {submissionStatus === 'submitting' ? 'Processing...' : submissionStatus === 'offline_saved' ? 'In Queue' : 'Sync Records'}
                    {submissionStatus === 'idle' && <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>}
                </button>
            </div>
        </div>
      </div>
    );

    return (
        <div className="flex flex-col min-h-screen bg-slate-50/50">
             <div className="bg-white border-b border-gray-200 sticky top-14 md:top-16 z-30 shadow-sm">
                <div className="overflow-x-auto scrollbar-hide">
                    <div className="flex px-4 py-4 min-w-max mx-auto justify-start md:justify-center">
                    {SECTIONS.map((section, idx) => {
                        const isActive = idx === currentSection;
                        const isCompleted = idx < currentSection;
                        return (
                        <div key={section.id} className="flex items-center">
                            <div className="flex flex-col items-center gap-1.5 transition-all">
                                <div className={`
                                    w-9 h-9 rounded-xl flex items-center justify-center text-xs font-black transition-all duration-500
                                    ${isActive ? 'bg-slate-900 text-white shadow-xl scale-110' : isCompleted ? 'bg-emerald-100 text-emerald-600 border border-emerald-200' : 'bg-slate-100 text-slate-300 border border-transparent'}
                                `}>
                                    {isCompleted ? '✓' : idx + 1}
                                </div>
                                <span className={`text-[9px] uppercase font-black tracking-widest ${isActive ? 'text-slate-900' : 'text-slate-300'}`}>
                                    {section.title}
                                </span>
                            </div>
                            {idx < SECTIONS.length - 1 && (
                            <div className={`h-0.5 w-6 sm:w-10 md:w-16 mx-1 sm:mx-3 transition-colors duration-500 ${isCompleted ? 'bg-emerald-400' : 'bg-slate-200'}`} />
                            )}
                        </div>
