import React, { useState } from 'react';
import { User, UserPreferences } from '../../types';

interface OnboardingWizardProps {
    user: User;
    appScriptUrl: string;
    onComplete: (updatedUser: User) => void;
}

const OnboardingWizard: React.FC<OnboardingWizardProps> = ({ user, appScriptUrl, onComplete }) => {
    const [step, setStep] = useState(0); // 0: Name, 1: Password, 2: Notifications, 3: Success
    const [isLoading, setIsLoading] = useState(false);

    // Identity
    const [fullName, setFullName] = useState('');
    const [newPassword, setNewPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');
    const [error, setError] = useState('');

    // Notifications
    const [prefs, setPrefs] = useState<UserPreferences>({
        emailNotifications: true,
        notifyGeneral: true,
        notifyPetroleum: true,
        notifyPetroleumV2: true,
        notifyAcid: true
    });

    const nextStep = () => {
        setError('');
        setStep(prev => prev + 1);
    };

    const handleProfileSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (step === 0 && !fullName.trim()) { setError("Full Name is required."); return; }
        if (step === 1) {
            if (newPassword.length < 4) { setError("Password too short."); return; }
            if (newPassword !== confirmPassword) { setError("Passwords do not match."); return; }
        }
        nextStep();
    };

    const handleFinalize = async () => {
        setIsLoading(true);
        try {
            const payload = {
                action: 'update_user',
                originalUsername: user.username,
                name: fullName,
                password: newPassword,
                preferences: { ...prefs, hasCompletedTour: false }
            };

            const response = await fetch(appScriptUrl, {
                method: 'POST',
                body: JSON.stringify(payload)
            });
            const result = await response.json();

            if (result.status === 'success') {
                setStep(3);
            } else {
                setError(result.message || "Failed to save profile.");
            }
        } catch (err) {
            setError("Connection lost. Please try again.");
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className="fixed inset-0 z-[200] bg-slate-900 flex items-center justify-center p-0 sm:p-4 animate-fadeIn">
            <div className="w-full h-full sm:h-auto sm:max-w-4xl bg-white sm:rounded-3xl shadow-2xl overflow-hidden flex flex-col md:flex-row min-h-[100vh] sm:min-h-[600px]">

                {/* Left Progress Bar / Sidebar */}
                <div className="md:w-5/12 bg-emerald-950 p-6 sm:p-10 flex flex-col justify-between text-white relative shrink-0">
                    <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')] opacity-10"></div>
                    <div className="relative z-10 flex md:block items-center justify-between">
                        <div>
                            <div className="w-10 h-10 sm:w-12 sm:h-12 bg-emerald-500 rounded-xl sm:rounded-2xl flex items-center justify-center mb-0 sm:mb-8 shadow-lg shadow-emerald-500/20">
                                <svg className="w-5 h-5 sm:w-6 sm:h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7"></path></svg>
                            </div>
                            <h1 className="hidden md:block text-3xl font-black mb-2 uppercase tracking-tight leading-none">Security<br/>Onboarding</h1>
                        </div>
                        <p className="text-emerald-400 text-[10px] font-bold uppercase tracking-widest opacity-60">System v4.0.2</p>
                    </div>

                    <div className="relative z-10 space-y-4 sm:space-y-6 hidden sm:block mt-8 md:mt-0">
                        {[
                            { s: 0, l: 'Your Identity' },
                            { s: 1, l: 'Secure Access' },
                            { s: 2, l: 'Communication' }
                        ].map(item => (
                            <div key={item.s} className={`flex items-center gap-4 transition-all duration-500 ${step >= item.s ? 'opacity-100 translate-x-0' : 'opacity-20 -translate-x-2'}`}>
                                <div className={`w-8 h-8 sm:w-10 sm:h-10 rounded-full flex items-center justify-center border-2 ${step > item.s ? 'bg-emerald-500 border-emerald-500 text-white' : step === item.s ? 'border-emerald-400 text-emerald-400' : 'border-emerald-800 text-emerald-800'} font-bold text-xs sm:text-sm transition-colors`}>
                                    {step > item.s ? '✓' : item.s + 1}
                                </div>
                                <span className="font-bold text-[10px] sm:text-[11px] uppercase tracking-[0.2em]">{item.l}</span>
                            </div>
                        ))}
                    </div>

                    <div className="md:hidden relative z-10 flex gap-2 mt-4">
                        {[0, 1, 2].map(i => (
                            <div key={i} className={`flex-1 h-1 rounded-full transition-all duration-500 ${step >= i ? 'bg-emerald-400' : 'bg-emerald-900'}`} />
                        ))}
                    </div>
                </div>

                {/* Right Form Content */}
                <div className="flex-1 p-6 sm:p-10 md:p-14 bg-white flex flex-col justify-center relative overflow-y-auto">
                    {step === 0 && (
                        <div className="animate-fadeIn">
                            <h2 className="text-2xl sm:text-3xl font-bold text-slate-800 mb-2 uppercase tracking-tight leading-tight">Identity Verification</h2>
                            <p className="text-slate-400 text-xs sm:text-sm mb-8 font-medium leading-relaxed uppercase tracking-wider">Provide your official legal name</p>
                            <form onSubmit={handleProfileSubmit} className="space-y-6">
                                <div>
                                    <label className="block text-[10px] font-black uppercase text-slate-400 mb-2 tracking-widest">Legal Full Name</label>
                                    <input 
                                        type="text" 
                                        autoFocus 
                                        required
                                        className="w-full p-4 sm:p-5 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-emerald-500 outline-none transition font-bold text-slate-800" 
                                        value={fullName} 
                                        onChange={e => setFullName(e.target.value.replace(/\b\w/g, c => c.toUpperCase()))} 
                                        placeholder="e.g. John Doe" 
                                    />
                                </div>
                                <button type="submit" className="w-full py-4 sm:py-5 bg-slate-900 hover:bg-black text-white font-black rounded-2xl shadow-2xl transition-all active:scale-95 flex items-center justify-center gap-3 uppercase tracking-[0.2em] text-[11px]">
                                    Next: Security
                                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M14 5l7 7m0 0l-7 7m7-7H3"></path></svg>
                                </button>
                            </form>
                        </div>
                    )}

                    {step === 1 && (
                        <div className="animate-fadeIn">
                            <h2 className="text-2xl sm:text-3xl font-bold text-slate-800 mb-2 uppercase tracking-tight leading-tight">Access Key</h2>
                            <p className="text-slate-400 text-xs sm:text-sm mb-8 font-medium leading-relaxed uppercase tracking-wider">Establish private credentials</p>
                            <form onSubmit={handleProfileSubmit} className="space-y-4 sm:space-y-6">
                                <div className="space-y-4">
                                    <input type="password" autoFocus required className="w-full p-4 sm:p-5 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-emerald-500 outline-none font-bold text-slate-800" value={newPassword} onChange={e => setNewPassword(e.target.value)} placeholder="Setup Password" />
                                    <input type="password" required className="w-full p-4 sm:p-5 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-emerald-500 outline-none font-bold text-slate-800" value={confirmPassword} onChange={e => setConfirmPassword(e.target.value)} placeholder="Confirm Password" />
                                </div>
                                {error && <div className="text-red-600 text-[10px] font-black bg-red-50 p-4 rounded-xl border border-red-100 uppercase tracking-widest">{error}</div>}
                                <button type="submit" className="w-full py-4 sm:py-5 bg-slate-900 hover:bg-black text-white font-black rounded-2xl shadow-2xl transition-all active:scale-95 flex items-center justify-center gap-3 uppercase tracking-[0.2em] text-[11px]">
                                    Next: Preferences
                                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M14 5l7 7m0 0l-7 7m7-7H3"></path></svg>
                                </button>
                            </form>
                        </div>
                    )}

                    {step === 2 && (
                        <div className="animate-fadeIn">
                            <h2 className="text-2xl sm:text-3xl font-bold text-slate-800 mb-2 uppercase tracking-tight leading-tight">Auto Alerts</h2>
                            <p className="text-slate-400 text-xs sm:text-sm mb-8 font-medium leading-relaxed uppercase tracking-wider">Configure communication sync</p>

                            <div className="space-y-3 mb-8">
                                <label className={`flex items-center justify-between p-4 sm:p-5 rounded-2xl border-2 transition-all cursor-pointer ${prefs.emailNotifications ? 'bg-emerald-50 border-emerald-500' : 'bg-white border-slate-100'}`}>
                                    <div className="min-w-0 pr-4">
                                        <p className="text-xs sm:text-sm font-black text-slate-800 uppercase tracking-tight">Enable All Alerts</p>
                                        <p className="text-[9px] text-emerald-600 font-black uppercase tracking-widest truncate">System Recommended</p>
                                    </div>
                                    <input type="checkbox" className="w-6 h-6 rounded-lg border-gray-300 text-emerald-600 focus:ring-emerald-500 shrink-0" checked={prefs.emailNotifications} onChange={() => setPrefs(p => ({...p, emailNotifications: !p.emailNotifications}))} />
                                </label>

                                <div className={`grid grid-cols-1 sm:grid-cols-2 gap-3 transition-all duration-500 ${!prefs.emailNotifications && 'opacity-20 pointer-events-none scale-[0.98]'}`}>
                                    {[
                                        { k: 'notifyGeneral', l: 'General Fleet' },
                                        { k: 'notifyPetroleum', l: 'Fuel Ops V1' },
                                        { k: 'notifyPetroleumV2', l: 'Fuel Ops V2' },
                                        { k: 'notifyAcid', l: 'Chemicals' }
                                    ].map(m => (
                                        <label key={m.k} className="flex items-center justify-between p-4 bg-slate-50 rounded-2xl border border-slate-100 cursor-pointer hover:bg-slate-100 transition-colors">
                                            <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest truncate pr-2">{m.l}</span>
                                            <input type="checkbox" className="w-5 h-5 rounded-lg text-emerald-600 shrink-0" checked={prefs[m.k as keyof UserPreferences] as boolean} onChange={() => setPrefs(p => ({...p, [m.k]: !p[m.k as keyof UserPreferences]}))} />
                                        </label>
                                    ))}
                                </div>
                            </div>

                            {error && <div className="text-red-600 text-[10px] font-black mb-4 uppercase tracking-widest">{error}</div>}

                            <button onClick={handleFinalize} disabled={isLoading} className="w-full py-4 sm:py-5 bg-emerald-600 hover:bg-emerald-700 text-white font-black rounded-2xl shadow-2xl transition-all active:scale-95 flex items-center justify-center gap-3 uppercase tracking-[0.2em] text-[11px]">
                                {isLoading ? (
                                    <svg className="animate-spin h-5 w-5 text-white" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                                ) : (
                                    <>
                                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M5 13l4 4L19 7"></path></svg>
                                        Finalize Profile
                                    </>
                                )}
                            </button>
                        </div>
                    )}

                    {step === 3 && (
                        <div className="text-center animate-fadeIn py-6">
                            <div className="w-20 h-20 sm:w-24 sm:h-24 bg-emerald-50 rounded-full flex items-center justify-center mx-auto mb-8 shadow-inner border border-emerald-100">
                                <svg className="w-10 h-10 sm:w-12 sm:h-12 text-emerald-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
                            </div>
                            <h2 className="text-2xl sm:text-3xl font-black text-slate-800 mb-4 uppercase tracking-tighter leading-tight">Account Sync Complete</h2>
                            <p className="text-slate-400 text-sm font-bold leading-relaxed mb-10 max-w-xs mx-auto uppercase tracking-widest opacity-60">Authentication keys generated</p>
                            <button 
                                onClick={() => onComplete({ ...user, name: fullName, preferences: prefs })} 
                                className="w-full py-5 bg-slate-900 hover:bg-black text-white font-black rounded-3xl shadow-2xl transition-all transform hover:scale-[1.02] active:scale-95 uppercase tracking-[0.3em] text-xs"
                            >
                                Enter Workspace
                            </button>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

