import React, { useEffect, useState } from 'react';
import { User } from '../types';

interface RequestTrackingViewProps {
    appScriptUrl: string;
    currentUser: User | null;
    showToast: (msg: string, type: 'success' | 'error' | 'info') => void;
    onRequestNew?: () => void;
}

interface RequestItem {
    id: string;
    requester: string;
    truck: string;
    trailer: string;
    type: string;
    reason: string;
    priority: string;
    assignedTo: string;
    status: string;
    timestamp: string;
}

const RequestTrackingView: React.FC<RequestTrackingViewProps> = ({ appScriptUrl, currentUser, showToast, onRequestNew }) => {
    const [requests, setRequests] = useState<RequestItem[]>([]);
    const [isLoading, setIsLoading] = useState(false);

    useEffect(() => {
        fetchRequests();
    }, [currentUser, appScriptUrl]);

    const fetchRequests = async () => {
        if (!appScriptUrl || !currentUser) return;
        setIsLoading(true);
        try {
            const response = await fetch(`${appScriptUrl}?t=${new Date().getTime()}`);
            const json = await response.json();

            const reqSheet = json['Inspection_Requests'];
            if (reqSheet && Array.isArray(reqSheet) && reqSheet.length > 1) {
                const myRequests = reqSheet.slice(1)
                    .map((row: any[]) => ({
                        id: row[0],
                        requester: row[1],
                        truck: row[3],
                        trailer: row[4],
                        type: row[5],
                        reason: row[6],
                        priority: row[7],
                        assignedTo: row[8],
                        status: row[9] || 'Pending',
                        timestamp: row[10]
                    }))
                    .filter((req: RequestItem) => {
                        if (currentUser.role === 'Admin' || currentUser.role === 'SuperAdmin') return true;
                        return String(req.requester).toLowerCase() === String(currentUser.name).toLowerCase();
                    })
                    .sort((a: RequestItem, b: RequestItem) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());

                setRequests(myRequests);
            } else {
                setRequests([]);
            }
        } catch (error) {
            console.error("Failed to fetch requests", error);
            showToast("Failed to load requests.", 'error');
        } finally {
            setIsLoading(false);
        }
    };

    const pendingCount = requests.filter(r => r.status === 'Pending').length;
    const completedCount = requests.filter(r => r.status === 'Completed').length;
    const completionRate = requests.length > 0 ? Math.round((completedCount / requests.length) * 100) : 0;

    return (
        <div className="max-w-6xl mx-auto space-y-6 sm:space-y-8 animate-fadeIn px-2 sm:px-0">
            {/* Header */}
            <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-6">
                <div>
                    <h2 className="text-2xl sm:text-3xl font-black text-gray-800 flex items-center gap-3">
                        <div className="p-2 bg-indigo-100 text-indigo-700 rounded-xl shrink-0">
                            <svg className="w-6 h-6 sm:w-8 sm:h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-6 9l2 2 4-4"></path></svg>
                        </div>
                        Fleet Orders
                    </h2>
                    <p className="text-gray-400 font-bold uppercase tracking-widest text-[10px] mt-1">Inspection Pipeline Monitoring</p>
                </div>
                <div className="flex gap-2 sm:gap-3 w-full md:w-auto">
                    {onRequestNew && (
                        <button 
                            onClick={onRequestNew}
                            className="flex-1 md:flex-none px-6 py-3 bg-indigo-600 hover:bg-indigo-700 text-white font-black rounded-xl shadow-lg transition-all active:scale-95 flex items-center justify-center gap-2 text-[10px] uppercase tracking-widest"
                        >
                            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 4v16m8-8H4"></path></svg>
                            New Request
                        </button>
                    )}
                    <button 
                        onClick={fetchRequests} 
                        className="flex-1 md:flex-none px-4 py-3 bg-white border border-gray-200 rounded-xl text-[10px] font-black text-gray-500 hover:bg-gray-50 flex items-center justify-center gap-2 transition shadow-sm uppercase tracking-widest"
                    >
                        <svg className={`w-4 h-4 ${isLoading ? 'animate-spin' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15"></path></svg>
                        Sync
                    </button>
                </div>
            </div>

            {/* Stats Cards */}
            <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 sm:gap-6">
                <div className="bg-white p-5 sm:p-6 rounded-2xl shadow-sm border border-gray-100 flex items-center justify-between">
                    <div>
                        <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">Queue</p>
                        <h3 className="text-3xl font-black text-amber-500 leading-none">{pendingCount}</h3>
                    </div>
                    <div className="w-10 h-10 rounded-xl bg-amber-50 flex items-center justify-center text-amber-500 border border-amber-100">
                        <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
                    </div>
                </div>
                <div className="bg-white p-5 sm:p-6 rounded-2xl shadow-sm border border-gray-100 flex items-center justify-between">
                    <div>
                        <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">Success</p>
                        <h3 className="text-3xl font-black text-emerald-600 leading-none">{completedCount}</h3>
                    </div>
                    <div className="w-10 h-10 rounded-xl bg-emerald-50 flex items-center justify-center text-emerald-600 border border-emerald-100">
                        <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7"></path></svg>
                    </div>
                </div>
                <div className="bg-white p-5 sm:p-6 rounded-2xl shadow-sm border border-gray-100 flex items-center justify-between">
                    <div>
                        <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">Fulfillment</p>
                        <h3 className="text-3xl font-black text-indigo-600 leading-none">{completionRate}%</h3>
                    </div>
                    <div className="w-10 h-10 rounded-xl bg-indigo-50 flex items-center justify-center text-indigo-600 border border-indigo-100">
                        <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z"></path></svg>
                    </div>
                </div>
            </div>

            {/* Request List */}
            <div className="bg-white rounded-3xl shadow-sm border border-gray-100 overflow-hidden">
                {isLoading ? (
                    <div className="p-16 text-center text-gray-400 flex flex-col items-center">
                        <div className="w-8 h-8 border-4 border-slate-100 border-t-indigo-600 rounded-full animate-spin mb-4"></div>
                        <p className="text-[10px] font-black uppercase tracking-widest">Pipeline Refreshing...</p>
                    </div>
                ) : requests.length === 0 ? (
                    <div className="p-16 text-center">
                        <div className="w-16 h-16 bg-gray-50 rounded-full flex items-center justify-center mx-auto mb-4 text-gray-200">
                            <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2"></path></svg>
                        </div>
                        <h3 className="text-slate-800 font-bold mb-1">Queue Empty</h3>
                        <p className="text-xs text-slate-400 font-medium">No pending inspection orders found.</p>
                    </div>
                ) : (
                    <div className="overflow-x-auto scrollbar-thin scrollbar-thumb-slate-200">
                        <table className="w-full text-left text-sm whitespace-nowrap min-w-[800px]">
                            <thead className="bg-slate-50/50 text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] border-b border-slate-100">
                                <tr>
                                    <th className="px-8 py-5">Status</th>
                                    <th className="px-8 py-5">Vehicle Detail</th>
                                    <th className="px-8 py-5">Workflow & Class</th>
                                    <th className="px-8 py-5">Assigned Resource</th>
                                    <th className="px-8 py-5 text-right">Timestamp</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-slate-50">
                                {requests.map((req) => (
                                    <tr key={req.id} className="hover:bg-slate-50/30 transition-colors group">
                                        <td className="px-8 py-5">
                                            {req.status === 'Completed' ? (
                                                <span className="inline-flex items-center gap-1.5 px-3 py-1.5 rounded-xl text-[10px] font-black uppercase tracking-widest bg-emerald-50 text-emerald-600 border border-emerald-100">
                                                    <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7"></path></svg>
                                                    Closed
                                                </span>
                                            ) : (
                                                <span className="inline-flex items-center gap-1.5 px-3 py-1.5 rounded-xl text-[10px] font-black uppercase tracking-widest bg-amber-50 text-amber-600 border border-amber-100 animate-pulse">
                                                    <div className="w-1.5 h-1.5 rounded-full bg-amber-500 shadow-[0_0_8px_rgba(245,158,11,0.4)]"></div>
                                                    Open
                                                </span>
                                            )}
                                        </td>
                                        <td className="px-8 py-5">
                                            <div className="font-bold text-slate-800">{req.truck}</div>
                                            <div className="text-[10px] text-slate-400 font-bold uppercase tracking-wider">{req.trailer || 'Stand-alone Horse'}</div>
                                        </td>
                                        <td className="px-8 py-5">
                                            <div className="text-[11px] font-black text-slate-600 uppercase tracking-widest">{req.type}</div>
                                            <div className={`text-[9px] font-black uppercase mt-1 tracking-widest ${
                                                req.priority === 'Critical' || req.priority === 'Urgent' ? 'text-red-500' : 'text-slate-300'
                                            }`}>
                                                {req.priority} Priority
                                            </div>
                                        </td>
                                        <td className="px-8 py-5">
                                            {req.assignedTo && req.assignedTo !== 'Unassigned' ? (
                                                <div className="flex items-center gap-2">
                                                    <div className="w-7 h-7 rounded-lg bg-slate-100 flex items-center justify-center text-[10px] font-black text-slate-500 border border-slate-200">
                                                        {req.assignedTo.charAt(0).toUpperCase()}
                                                    </div>
                                                    <span className="text-slate-600 font-bold text-xs">{req.assignedTo}</span>
                                                </div>
                                            ) : (
                                                <span className="text-slate-300 italic text-[10px] font-black uppercase tracking-widest">Pending Dispatch</span>
                                            )}
                                        </td>
                                        <td className="px-8 py-5 text-right font-mono text-[11px] text-slate-400">
                                            {new Date(req.timestamp).toLocaleDateString()}
                                            <div className="text-[9px] font-bold uppercase tracking-tighter opacity-50">{new Date(req.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</div>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                )}
            </div>
        </div>
    );
};

