import React, { useState, useEffect } from 'react';
import { User, ValidationLists, SystemSettings } from '../types';
import AutocompleteInput from '../components/ui/AutocompleteInput';

interface UserManagementViewProps {
    currentUser: User;
    appScriptUrl: string;
    showToast: (msg: string, type: 'success' | 'error' | 'info' | 'warning') => void;
    validationLists: ValidationLists;
    settings?: SystemSettings;
}

const UserManagementView: React.FC<UserManagementViewProps> = ({ currentUser, appScriptUrl, showToast, validationLists, settings }) => {
    const [users, setUsers] = useState<(User & {password?: string})[]>([]);
    const [isLoading, setIsLoading] = useState(false);
    const [viewMode, setViewMode] = useState<'list' | 'form'>('list');
    const [isEditing, setIsEditing] = useState(false);
    const [originalUsername, setOriginalUsername] = useState('');

    const [formData, setFormData] = useState({
        name: '', username: '', password: '', role: 'Inspector' as any, position: ''
    });
    const [isSubmitting, setIsSubmitting] = useState(false);

    const isSuperAdmin = currentUser.role === 'SuperAdmin';

    useEffect(() => { fetchUsers(); }, []);

    const fetchUsers = async () => {
        if (!appScriptUrl) return;
        setIsLoading(true);
        try {
            const response = await fetch(appScriptUrl, { method: 'POST', body: JSON.stringify({ action: 'get_users' }) });
            const result = await response.json();
            if (result.status === 'success' && Array.isArray(result.users)) {
                let fetchedUsers = result.users;
                if (!isSuperAdmin) fetchedUsers = fetchedUsers.filter((u: User) => u.role !== 'SuperAdmin');
                setUsers(fetchedUsers);
            }
        } catch (e) { showToast("Failed to load users", 'error'); } finally { setIsLoading(false); }
    };

    const handleDelete = async (username: string) => {
        if (!window.confirm(`Remove user "${username}"?`)) return;
        setIsLoading(true);
        try {
            const response = await fetch(appScriptUrl, { method: 'POST', body: JSON.stringify({ action: 'delete_user', username }) });
            const result = await response.json();
            if (result.status === 'success') {
                showToast("User removed successfully", 'success');
                fetchUsers();
            } else { showToast(result.message || "Delete failed", 'error'); }
        } catch (e) { showToast("Connection failed", 'error'); } finally { setIsLoading(false); }
    };

    const handleEdit = (user: User) => {
        setFormData({ name: user.name || '', username: user.username, role: user.role as any, position: user.position || '', password: '' });
        setOriginalUsername(user.username);
        setIsEditing(true);
        setViewMode('form');
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!formData.username) { showToast("Login Email is required.", 'error'); return; }

        setIsSubmitting(true);
        try {
            const payload: any = { 
                action: isEditing ? 'update_user' : 'register_user', 
                ...formData,
                preferences: {
                    ... (isEditing ? {} : { mustChangePassword: true })
                }
            };

            if (isEditing) payload.originalUsername = originalUsername;

            const response = await fetch(appScriptUrl, { method: 'POST', body: JSON.stringify(payload) });
            const result = await response.json();

            if (result.status === 'success') {
                showToast(isEditing ? "Staff details updated" : "Invite sent to new staff member", 'success');
                setViewMode('list');
                fetchUsers();
            } else { 
                showToast(result.message || "Operation failed", 'error'); 
            }
        } catch (e) { 
            showToast("Connection failed", 'error'); 
        } finally { 
            setIsSubmitting(false); 
        }
    };

    if (viewMode === 'form') {
        return (
            <div className="max-w-lg mx-auto animate-fadeIn py-4 px-4">
                <button onClick={() => setViewMode('list')} className="mb-4 text-xs font-semibold text-gray-400 hover:text-gray-800 flex items-center gap-2 transition-colors group">
                    <svg className="w-4 h-4 group-hover:-translate-x-1 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M15 19l-7-7 7-7"></path></svg>
                    Back to Directory
                </button>
                <div className="bg-white rounded-3xl shadow-xl border border-gray-200 overflow-hidden p-6 sm:p-10">
                    <h2 className="text-2xl font-bold text-slate-800 mb-2 uppercase tracking-tight">{isEditing ? 'Edit Profile' : 'Invite Staff'}</h2>
                    <p className="text-slate-400 text-xs font-medium mb-8 uppercase tracking-wider">Configure workspace permissions</p>

                    <form onSubmit={handleSubmit} className="space-y-5">
                        <div className="space-y-4">
                            <div>
                                <label className="block text-[10px] font-bold uppercase text-slate-400 mb-2 tracking-widest">Login Identity (Email) *</label>
                                <input 
                                    type="email" 
                                    required 
                                    className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition font-semibold" 
                                    value={formData.username} 
                                    onChange={e => setFormData({...formData, username: e.target.value})} 
                                    placeholder="e.g. staff@company.com" 
                                />
                            </div>

                            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-[10px] font-bold uppercase text-slate-400 mb-2 tracking-widest">System Role</label>
                                    <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl text-sm font-semibold focus:ring-2 focus:ring-blue-500 outline-none h-[58px]" value={formData.role} onChange={e => setFormData({...formData, role: e.target.value as any})}>
                                        <option value="Inspector">Inspector</option>
                                        <option value="Operations">Operations</option>
                                        <option value="Maintenance">Maintenance</option>
                                        <option value="Admin">Admin</option>
                                        {isSuperAdmin && <option value="SuperAdmin">SuperAdmin</option>}
                                    </select>
                                </div>
                                <AutocompleteInput 
                                    label="Job Title" 
                                    value={formData.position} 
                                    onChange={v => setFormData({...formData, position: v})} 
                                    options={validationLists.positions} 
                                    isTitleCase={true} 
                                    placeholder="Optional"
                                />
                            </div>
                        </div>

                        {!isEditing && (
                            <div className="p-4 bg-blue-50 border border-blue-100 rounded-xl flex items-start gap-3">
                                <svg className="w-5 h-5 text-blue-500 shrink-0 mt-0.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
                                <p className="text-[10px] text-blue-800 font-medium leading-relaxed uppercase tracking-wider">
                                    <strong>Invite-Only:</strong> User will set their own password on first login.
                                </p>
                            </div>
                        )}

                        {isEditing && (
                            <div className="pt-4 border-t border-slate-100">
                                <AutocompleteInput label="Full Name" value={formData.name} onChange={v => setFormData({...formData, name: v})} options={validationLists.inspectors} isTitleCase={true} />
                            </div>
                        )}

                        <button type="submit" disabled={isSubmitting} className="w-full py-4 bg-slate-900 hover:bg-black text-white font-bold rounded-2xl shadow-xl transition-all active:scale-95 flex items-center justify-center gap-3 mt-4 uppercase tracking-widest text-xs">
                            {isSubmitting ? (
                                <svg className="animate-spin h-5 w-5 text-blue-400" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                            ) : null}
