    gray: isSelected ? 'bg-slate-700 text-white border-slate-700' : 'bg-white text-slate-500 border-slate-200 hover:border-slate-400',
  };

  return (
    <button onClick={onClick} className={`relative py-2 px-1 rounded-lg border font-bold text-[9px] transition-all flex flex-col items-center gap-0.5 ${colors[colorClass]} ${isSelected ? 'shadow-sm z-10' : 'shadow-none'}`}>
