          <div className="mb-10">
             <label className="block text-[10px] font-bold uppercase mb-4 text-slate-400">Rating (1-5) *</label>
             <div className="flex gap-2">
               {[1, 2, 3, 4, 5].map(num => (
                 <button key={num} type="button" onClick={() => updateField('rate', num)} className={`w-10 h-10 rounded-lg font-bold text-sm transition-all ${formData.rate === num ? 'bg-slate-900 text-white shadow-sm' : 'bg-slate-100 text-slate-400 hover:bg-slate-200'}`}>{num}</button>
               ))}
             </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8 pt-8 border-t border-slate-100">
             <SignaturePad label="Inspector Signature" existingSignature={formData.inspectorSignature} onSave={sig => updateField('inspectorSignature', sig)} />
             <SignaturePad label="Driver Signature" existingSignature={formData.driverSignature} onSave={sig => updateField('driverSignature', sig)} />
          </div>
        </div>
      </div>
    );

    return (
        <div className="flex flex-col min-h-screen bg-slate-50/30">
             <div className="bg-white border-b border-slate-100 sticky top-14 z-30 shadow-sm">
                <div className="max-w-5xl mx-auto flex px-4 py-3 justify-between items-center">
                    {SECTIONS.map((section, idx) => {
                        const isActive = idx === currentSection;
                        const isCompleted = idx < currentSection;
                        return (
                        <div key={section.id} className="flex items-center flex-1">
                            <div className="flex flex-col items-center transition-all w-full">
                                <div className={`
                                    w-7 h-7 rounded-lg flex items-center justify-center text-[11px] font-bold transition-all duration-300
                                    ${isActive ? 'bg-slate-900 text-white' : isCompleted ? 'bg-emerald-100 text-emerald-700' : 'bg-slate-100 text-slate-300'}
                                `}>
                                    {isCompleted ? '✓' : idx + 1}
                                </div>
                            </div>
                            {idx < SECTIONS.length - 1 && <div className={`h-px flex-1 ${isCompleted ? 'bg-emerald-400' : 'bg-slate-100'}`} />}
                        </div>
                        );
                    })}
                </div>
                <div className="sm:hidden flex justify-center py-1.5 bg-slate-900 text-white text-[9px] font-black uppercase tracking-widest">
                    Step {currentSection + 1}: {SECTIONS[currentSection].label}
                </div>
            </div>

            <div className="flex-1 p-4 md:p-8 max-w-4xl mx-auto w-full pb-24">
                {currentSection === 0 && renderDetailsSection()}
                {currentSection === 1 && renderPhotosSection()}

                {activeModule === 'general' && currentSection === 2 && renderInspectionSection([INSPECTION_CATEGORIES.PPE, INSPECTION_CATEGORIES.DOCUMENTATION])}
                {activeModule === 'general' && currentSection === 3 && renderInspectionSection([INSPECTION_CATEGORIES.VEHICLE_EXTERIOR, INSPECTION_CATEGORIES.LIGHTS_ELECTRICAL])}
                {activeModule === 'general' && currentSection === 4 && renderInspectionSection([INSPECTION_CATEGORIES.MECHANICAL, INSPECTION_CATEGORIES.TRAILER])}

                {activeModule === 'petroleum' && currentSection === 2 && renderInspectionSection([PETROLEUM_CATEGORIES.TRUCK_EQUIPMENT])}
                {activeModule === 'petroleum' && currentSection === 3 && renderInspectionSection([PETROLEUM_CATEGORIES.TYRES, PETROLEUM_CATEGORIES.PPE_ID])}
                {activeModule === 'petroleum' && currentSection === 4 && renderInspectionSection([PETROLEUM_CATEGORIES.DOCUMENTS, PETROLEUM_CATEGORIES.ONBOARD])}

                {activeModule === 'petroleum_v2' && currentSection === 2 && renderInspectionSection([PETROLEUM_V2_CATEGORIES.PRIME_MOVER])}
                {activeModule === 'petroleum_v2' && currentSection === 3 && renderInspectionSection([PETROLEUM_V2_CATEGORIES.TRAILER_TANKS])}
                {activeModule === 'petroleum_v2' && currentSection === 4 && renderInspectionSection([PETROLEUM_V2_CATEGORIES.DRIVER, PETROLEUM_V2_CATEGORIES.SAFETY_SIGNS, PETROLEUM_V2_CATEGORIES.DOCUMENTS])}

                {activeModule === 'acid' && currentSection === 2 && renderInspectionSection([ACID_CATEGORIES.PPE])}
                {activeModule === 'acid' && currentSection === 3 && renderInspectionSection([ACID_CATEGORIES.VEHICLE])}
                {activeModule === 'acid' && currentSection === 4 && renderInspectionSection([ACID_CATEGORIES.SPILL_KIT, ACID_CATEGORIES.DOCUMENTATION])}

                {currentSection === 5 && renderSignaturesSection()}
                {currentSection === 6 && (
                    <div className="text-center py-12">
                        <h2 className="text-lg font-bold text-slate-800">Verification Ready</h2>
                        <p className="text-slate-500 text-xs mt-1 mb-8">Confirm all data is accurate before synchronizing.</p>
                        <button onClick={() => onSubmit(formData)} className="px-10 py-4 bg-emerald-600 text-white rounded-xl font-bold uppercase tracking-widest text-xs shadow-lg hover:bg-emerald-700 transition-all">Sync Records</button>
                    </div>
                )}
            </div>

            <footer className="bg-white border-t border-slate-100 p-4 sticky bottom-0 z-30 flex justify-center shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.05)]">
              <div className="max-w-4xl w-full flex justify-between gap-4">
                <button onClick={handleBack} className="px-6 py-2 rounded-lg border border-slate-200 font-bold text-slate-500 text-xs uppercase tracking-tight">{currentSection === 0 ? 'Exit' : 'Back'}</button>
                {currentSection < SECTIONS.length - 1 && (
                    <button onClick={handleNext} className="px-10 py-2.5 rounded-lg bg-slate-900 text-white font-bold text-xs uppercase tracking-widest">Next Phase</button>
                )}
              </div>
            </footer>
        </div>
    );
};

