import React, { useState, useRef, useEffect } from 'react';

interface AutocompleteInputProps {
  label: string;
  value: string;
  onChange: (value: string) => void;
  options: string[];
  placeholder?: string;
  isRegNo?: boolean; 
  isTitleCase?: boolean; 
  readOnly?: boolean; 
  error?: boolean;
}

const AutocompleteInput: React.FC<AutocompleteInputProps> = ({ 
  label, value, onChange, options = [], placeholder, isRegNo, isTitleCase, readOnly, error
}) => {
  const [isOpen, setIsOpen] = useState(false);
  const [highlightedIndex, setHighlightedIndex] = useState(-1);
  const wrapperRef = useRef<HTMLDivElement>(null);

  const filteredOptions = options.filter(opt => 
    opt != null && String(opt).toLowerCase().includes((value || '').toLowerCase())
  );

  useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (wrapperRef.current && !wrapperRef.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    }
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (readOnly) return;
    let newVal = e.target.value;
    if (isRegNo) newVal = newVal.toUpperCase().replace(/[^A-Z0-9 ]/g, '');
    if (isTitleCase && !isRegNo) newVal = newVal.replace(/\b\w/g, c => c.toUpperCase());
    onChange(newVal);
    setIsOpen(true);
  };

  return (
    <div className="relative" ref={wrapperRef}>
      <label className={`block text-[10px] font-bold uppercase mb-1.5 tracking-tight ${error ? 'text-red-600' : 'text-slate-400'}`}>
          {label}
      </label>
      <div className="relative">
        <input
          type="text"
          value={value}
          onChange={handleChange}
          onFocus={() => !readOnly && setIsOpen(true)}
          placeholder={placeholder}
          readOnly={readOnly}
          className={`w-full p-2.5 text-xs border rounded-lg transition-all font-semibold 
             ${readOnly 
               ? 'bg-slate-100 border-slate-200 text-slate-400 cursor-not-allowed' 
               : error
                 ? 'bg-red-50 border-red-200 focus:ring-1 focus:ring-red-200'
                 : 'bg-slate-50/50 border-slate-200 focus:ring-1 focus:ring-slate-400 focus:bg-white text-slate-800'
             }
          `}
        />
      </div>

      {!readOnly && isOpen && (value.length > 0 || filteredOptions.length > 0) && (
        <ul className="absolute z-50 w-full mt-1 bg-white border border-slate-200 rounded-lg shadow-lg max-h-40 overflow-y-auto">
          {filteredOptions.map((opt, idx) => (
            <li
              key={idx}
              onClick={() => { onChange(opt); setIsOpen(false); }}
              className="px-3 py-2 text-[11px] cursor-pointer hover:bg-slate-50 border-b border-slate-50 last:border-none font-bold text-slate-600"
            >
              {opt}
            </li>
          ))}
        </ul>
      )}
    </div>
  );
};

