  placeholder?: string;
  error?: boolean;
}

const Input: React.FC<InputProps> = ({label, value, onChange, type='text', placeholder, error}) => (
  <div>
    <label className={`block text-[10px] font-black uppercase mb-1.5 tracking-widest ${error ? 'text-red-600' : 'text-slate-400'}`}>
      {label}
    </label>
    <input 
      type={type} 
      value={value} 
      onChange={e => onChange(e.target.value)}
      placeholder={placeholder}
      className={`w-full p-2.5 text-[12px] border rounded-lg focus:ring-1 focus:outline-none transition-all font-bold placeholder-slate-300
        ${error 
          ? 'bg-red-50 border-red-200 focus:ring-red-100 text-red-900' 
          : 'bg-slate-50/50 border-slate-200 focus:ring-slate-400 focus:bg-white text-slate-800'
        }
      `} 
    />
  </div>
);

export default Input;

import React from 'react';
import { InspectionStatus } from '../../types';

const StatusButton: React.FC<{label: string, status: InspectionStatus, current: any, onClick: () => void, colorClass: 'green' | 'red' | 'yellow' | 'gray'}> = ({label, status, current, onClick, colorClass}) => {
  const isSelected = status === current;
  const colors = {
    green: isSelected ? 'bg-emerald-600 text-white border-emerald-600' : 'bg-white text-emerald-700 border-slate-200 hover:border-emerald-200',
    red: isSelected ? 'bg-red-600 text-white border-red-600' : 'bg-white text-red-700 border-slate-200 hover:border-red-200',
    yellow: isSelected ? 'bg-amber-500 text-white border-amber-500' : 'bg-white text-amber-600 border-slate-200 hover:border-amber-200',
    gray: isSelected ? 'bg-slate-700 text-white border-slate-700' : 'bg-white text-slate-500 border-slate-200 hover:border-slate-400',
  };

  return (
    <button onClick={onClick} className={`relative py-1.5 px-1 rounded-lg border font-black text-[9px] transition-all flex flex-col items-center gap-0.5 ${colors[colorClass]} ${isSelected ? 'shadow-sm z-10' : 'shadow-none opacity-60'}`}>
      <span className="text-xs leading-none">
        {status === InspectionStatus.GOOD && '✓'}
        {status === InspectionStatus.BAD && '✕'}
        {status === InspectionStatus.ATTENTION && '!'}
        {status === InspectionStatus.NIL && 'Ø'}
      </span>
      <span className="uppercase tracking-tighter">{label}</span>
    </button>
  );
};

export default StatusButton;

