                             className="px-3 py-1 bg-slate-900 hover:bg-black text-white text-[9px] font-medium rounded transition-all flex items-center gap-1.5 uppercase tracking-widest"
                           >
                               <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M12 4v16m8-8H4"></path></svg>
                               Start
                           </button>
                       )}
                       <button 
                         onClick={fetchHistory}
                         className="px-3 py-1 bg-white border border-slate-200 text-slate-500 text-[9px] font-medium rounded hover:bg-slate-50 transition flex items-center gap-1.5 uppercase tracking-widest"
                       >
                           <svg className={`w-3 h-3 ${isLoadingHistory ? 'animate-spin' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15"></path></svg>
                           Refresh
                       </button>
                   </div>
               </div>

               <div className="flex gap-2">
                   <div className="bg-slate-50 rounded p-2 text-center min-w-[70px] border border-slate-100">
                       <div className="text-base font-medium text-slate-700 leading-none">{stats.total}</div>
                       <div className="text-[7px] text-slate-400 uppercase font-medium tracking-widest mt-1">Total</div>
                   </div>
                   <div className="bg-slate-50 rounded p-2 text-center min-w-[70px] border border-slate-100">
                       <div className="text-base font-medium text-slate-700 leading-none">{stats.passRate}%</div>
                       <div className="text-[7px] text-slate-400 uppercase font-medium tracking-widest mt-1">Score</div>
                   </div>
               </div>
          </div>

          {/* Simple Faint Table */}
          <div className="bg-white rounded border border-slate-100 overflow-hidden shadow-sm">
              <div className="px-4 py-2 border-b border-slate-50 flex justify-between items-center bg-slate-50/30">
                  <h3 className="text-[8px] font-medium text-slate-400 uppercase tracking-[0.3em]">Inspection History</h3>
                  <input 
                      type="text" 
                      placeholder="Search..." 
                      value={searchTerm}
                      onChange={(e) => setSearchTerm(e.target.value)}
                      className="w-32 px-2 py-0.5 bg-white border border-slate-100 rounded text-[9px] outline-none font-normal"
                  />
              </div>

              {isLoadingHistory ? (
                  <div className="py-8 text-center">
                      <div className="w-4 h-4 border-2 border-slate-200 border-t-slate-500 rounded-full animate-spin mx-auto mb-2"></div>
                      <p className="text-[8px] text-slate-400 uppercase tracking-widest">Syncing</p>
                  </div>
              ) : displayList.length === 0 ? (
                  <div className="py-8 text-center text-[9px] text-slate-300 uppercase tracking-widest">No Records</div>
              ) : (
                  <div className="w-full text-[10px] text-slate-500">
                      {/* Responsive Table Headers (Hidden on Mobile) */}
                      <div className="hidden sm:grid grid-cols-12 px-4 py-2 border-b border-slate-50 font-medium text-slate-400 uppercase tracking-tighter bg-slate-50/10">
                          <div className="col-span-1">Rate</div>
                          <div className="col-span-3">Vehicle / Unit</div>
                          <div className="col-span-3">Date</div>
                          <div className="col-span-3">Inspector</div>
                          <div className="col-span-2 text-right">Action</div>
                      </div>

                      <div className="divide-y divide-slate-50">
                          {displayList.map((item, i) => (
                              <div key={i} className="sm:grid sm:grid-cols-12 flex flex-col sm:items-center px-4 py-2 hover:bg-slate-50/30 transition-colors gap-1 sm:gap-0">
                                  {/* Mobile Rating Display */}
                                  <div className="flex sm:block items-center justify-between col-span-1">
                                      <span className={`inline-flex items-center justify-center w-5 h-5 rounded text-[8px] font-medium text-white
                                          ${Number(item.rate) >= 4 ? 'bg-emerald-400' : Number(item.rate) === 3 ? 'bg-amber-400' : 'bg-rose-400'}
                                      `}>
                                          {item.rate}
                                      </span>
                                      <div className="sm:hidden flex flex-col items-end">
                                          <span className="text-[9px] font-medium text-slate-800">{item.truckNo}</span>
                                          {item.trailerNo && <span className="text-[7px] text-slate-400">{item.trailerNo}</span>}
                                      </div>
                                  </div>

                                  {/* Vehicle / Trailer */}
                                  <div className="hidden sm:flex flex-col col-span-3 truncate pr-2">
                                      <span className="font-medium text-slate-700">{item.truckNo}</span>
                                      {item.trailerNo && <span className="text-[8px] text-slate-400 leading-none">{item.trailerNo}</span>}
                                  </div>

                                  {/* Date */}
                                  <div className="col-span-3 text-slate-400 font-normal truncate">
                                      <span className="sm:hidden font-medium text-slate-500 mr-2 uppercase text-[8px]">Date:</span>
                                      {new Date(item.timestamp).toLocaleDateString()}
                                  </div>

                                  {/* Inspector */}
                                  <div className="col-span-3 text-slate-400 font-normal truncate">
                                      <span className="sm:hidden font-medium text-slate-500 mr-2 uppercase text-[8px]">By:</span>
                                      {item.inspectedBy}
                                  </div>

                                  {/* View Button */}
                                  <div className="col-span-2 text-right mt-2 sm:mt-0">
                                      <button 
                                        onClick={() => onViewReport(item)}
                                        className="inline-flex items-center gap-1 px-2 py-1 text-[9px] font-medium text-slate-500 hover:text-slate-900 hover:bg-slate-100 rounded transition-all uppercase tracking-widest group"
                                      >
                                          <svg className="w-3 h-3 opacity-40 group-hover:opacity-100" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z"></path><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z"></path></svg>
                                          View Report
                                      </button>
                                  </div>
                              </div>
                          ))}
                      </div>
                  </div>
              )}
          </div>
      </div>
      </SubscriptionLock>
    );
};

export default DashboardTemplate;

