/**
 * 3_CoreOperations.gs
 * High-performance data handling.
 */
const DataHandlers = {
  handleDataSubmission: function(ss, body) {
    const sheetName = body.sheet;
    const rowData = body.row;
    let sheet = ss.getSheetByName(sheetName);

    // Auto-create sheets if they don't exist
    if (!sheet) {
      sheet = ss.insertSheet(sheetName);
      if (body.headers) {
        sheet.appendRow(body.headers);
        sheet.getRange(1, 1, 1, body.headers.length).setFontWeight("bold");
        sheet.setFrozenRows(1);
      }
    }

    // Force all data to String to prevent formula injection or formatting errors
    const safeRow = rowData.map(val => (val === null || val === undefined) ? "" : String(val));
    sheet.appendRow(safeRow);

    // Update the searchable validation lists (Trucks, Drivers, etc)
    Validation.updateFromRow(ss, body);

    return ResponseBuilder.success({ sheet: sheetName });
  },

  handleGetRequest: function(ss) {
    const sheets = ss.getSheets();
    const result = {};

    sheets.forEach(sheet => {
      const name = sheet.getName();
      // SECURITY: Block sensitive sheets from being queried by public GET
      if (['Users', 'System_Logs', 'Subscription_Data'].includes(name)) return;

      const lastRow = sheet.getLastRow();
      const lastCol = sheet.getLastColumn();

      if (name === 'Validation_Data') {
         // Specialized formatting for autocomplete lists
         if (lastRow > 1) {
            const range = sheet.getRange(2, 1, lastRow - 1, lastCol);
            const values = range.getValues();
            const headers = sheet.getRange(1, 1, 1, lastCol).getValues()[0];
            const cols = {};
            headers.forEach((h, idx) => {
              cols[h] = [...new Set(values.map(r => r[idx]).filter(v => v !== ""))];
            });
            result[name] = cols;
         }
      } else {
         // PERFORMANCE: Only return the last 200 records to keep the frontend snappy
         if (lastRow > 0) {
            const limit = 200;
            const startRow = Math.max(2, lastRow - limit + 1);
            const count = lastRow - startRow + 1;
            const headers = sheet.getRange(1, 1, 1, lastCol).getValues()[0];
            let rows = [];
            if (count > 0) {
              rows = sheet.getRange(startRow, 1, count, lastCol).getValues();
            }
            rows.unshift(headers);
            result[name] = rows;
         }
      }
    });
    return ContentService.createTextOutput(JSON.stringify(result)).setMimeType(ContentService.MimeType.JSON);
  }
};
`;

