 * Handles routing and concurrency locking for multi-user safety.
 */
function doPost(e) {
  const lock = LockService.getScriptLock();
  // Wait up to 30 seconds for other processes to finish before writing
  const hasLock = lock.tryLock(30000); 
  if (!hasLock) return ResponseBuilder.error("Server busy. Please try again in a few seconds.");

  try {
    const ss = SpreadsheetApp.getActiveSpreadsheet();
    const body = e.postData ? JSON.parse(e.postData.contents) : {};
    return routeRequest(ss, body);
  } catch (err) {
    return ResponseBuilder.error("System Error: " + err.toString());
  } finally {
    lock.releaseLock();
  }
}

function doGet(e) {
