const PDFGenerator = {
  create: function(data, moduleName, companyName) {
    var headers = data.headers;
    var row = data.row;

    var html = "<style>body{font-family: sans-serif; color: #333;} .header{background: #0f172a; color: white; padding: 20px; text-align: center;} table{width: 100%; border-collapse: collapse; margin-top: 20px;} th, td{border: 1px solid #ddd; padding: 10px; text-align: left;} th{background: #f8fafc;} .fail{color: #ef4444; font-weight: bold;} .pass{color: #10b981; font-weight: bold;}</style>";
    html += "<div class='header'><h1>" + companyName + "</h1><p>" + moduleName + " Inspection Report</p></div>";

    html += "<h2>General Information</h2><table>";
    // First 8 items are usually metadata
    for (var i = 1; i < 10; i++) {
        if (headers[i] && row[i]) {
            html += "<tr><th>" + headers[i] + "</th><td>" + row[i] + "</td></tr>";
        }
    }
    html += "</table>";

    html += "<h2>Inspection Checklist Results</h2><table><thead><tr><th>Item</th><th>Status</th></tr></thead><tbody>";
    for (var j = 18; j < headers.length; j++) {
        if (headers[j]) {
            var val = String(row[j] || "N/A");
            var statusClass = val === "Bad" ? "fail" : (val === "Good" ? "pass" : "");
            html += "<tr><td>" + headers[j] + "</td><td class='" + statusClass + "'>" + val + "</td></tr>";
        }
    }
    html += "</tbody></table>";

    html += "<p style='margin-top: 40px; font-size: 10px; color: #999; text-align: center;'>Generated by SafetyCheck Pro Digital Compliance System</p>";

    return html;
  }
};
`;

