          ".sig-section { margin-top: 50px; width: 100%; overflow: hidden; }" +
          ".sig-block { width: 45%; float: left; text-align: center; }" +
          ".sig-line { border-top: 1px solid #000; margin-top: 5px; padding-top: 5px; font-size: 11px; font-weight: bold; text-transform: uppercase; color: #333; }" +
          "</style></head><body>" +

          "<div class='logo-container'>" +
             (data.companyLogo ? "<img src='" + data.companyLogo + "' style='height: 70px;' />" : "<h2>" + data.companyName + "</h2>") +
          "</div>" +

          "<table class='header-table'>" +
              "<tr>" +
                  "<td style='width: 33%;'>Doc. No. MNT-F-015</td>" +
                  "<td style='width: 33%;'>Revision No.: 01</td>" +
                  "<td style='width: 33%;'>Date/Time: " + dateStr + "</td>" +
              "</tr>" +
              "<tr>" +
                  "<td colspan='3' class='title-row'>GENERAL VEHICLE CHECKLIST</td>" +
              "</tr>" +
          "</table>" +

          "<table class='details-table'>" +
              "<tr>" +
                  "<td style='width: 50%;' class='col-border'><span class='label'>REG NO:</span> <span class='val'>" + data.truckNo + "</span></td>" +
                  "<td style='width: 50%;'><span class='label'>TRAILER/UNIT:</span> <span class='val'>" + (data.trailerNo || 'N/A') + "</span></td>" +
              "</tr>" +
              "<tr>" +
                  "<td style='width: 50%;' class='col-border'><span class='label'>DRIVER NAME:</span> <span class='val'>" + data.driverName + "</span></td>" +
                  "<td style='width: 50%;'><span class='label'>INSPECTED BY:</span> <span class='val'>" + data.inspectedBy + "</span></td>" +
              "</tr>" +
              "<tr>" +
                  "<td style='width: 50%; border-bottom: none;' class='col-border'><span class='label'>LOCATION:</span> <span class='val'>" + data.location + "</span></td>" +
                  "<td style='width: 50%; border-bottom: none;'><span class='label'>ODOMETER:</span> <span class='val'>" + data.odometer + " km</span></td>" +
              "</tr>" +
          "</table>" +

          "<div class='cols-wrapper'>" +
              "<div class='col-left'>" + renderTable(leftItems) + "</div>" +
              "<div class='col-right'>" + renderTable(rightItems) + "</div>" +
          "</div>" +

          "<div class='sig-section'>" +
              "<div class='sig-block'>" +
                  (data.signatures.driver ? "<img src='" + data.signatures.driver + "' style='height: 50px; margin-bottom: -15px;' />" : "<div style='height: 50px;'></div>") +
                  "<div class='sig-line'>DRIVER SIGNATURE</div>" +
              "</div>" +
              "<div class='sig-block' style='float: right;'>" +
                  (data.signatures.inspector ? "<img src='" + data.signatures.inspector + "' style='height: 50px; margin-bottom: -15px;' />" : "<div style='height: 50px;'></div>") +
                  "<div class='sig-line'>INSPECTOR SIGNATURE</div>" +
              "</div>" +
          "</div>" +

          "</body></html>";
  },

  createGenericReport: function(data) {
    var itemsHtml = "";
    if (data.items && data.items.length > 0) {
        var currentCategory = "";
        data.items.forEach(function(item) {
            if (item.category !== currentCategory) {
                currentCategory = item.category;
                itemsHtml += "<tr style='background-color:#f8fafc;'><td colspan='2' style='padding:10px 8px; font-weight:700; color:#1e293b; border-bottom:1px solid #e2e8f0; font-size:11px; text-transform:uppercase; letter-spacing:0.5px;'>" + currentCategory + "</td></tr>";
            }

            var statusColor = "#475569";
            var statusBg = "transparent";

            if (item.status === 'Bad' || item.status === 'Non-Compliant') { statusColor = "#b91c1c"; statusBg = "#fef2f2"; }
            if (item.status === 'Needs Attention') { statusColor = "#b45309"; statusBg = "#fffbeb"; }
            if (item.status === 'Good' || item.status === 'Yes' || item.status === 'Compliant') { statusColor = "#0f766e"; }

            itemsHtml += "<tr>" + 
                "<td style='padding:8px; border-bottom:1px solid #f1f5f9; color:#334155;'>" + item.label + "</td>" +
                "<td style='padding:8px; border-bottom:1px solid #f1f5f9; font-weight:600; color:" + statusColor + "; background-color:" + statusBg + "; text-align:right; white-space:nowrap;'>" + item.status + "</td>" +
                "</tr>";
        });
    }

    var logoHtml = data.companyLogo ? "<img src='" + data.companyLogo + "' style='max-height:50px; max-width:180px;' />" : "<h1 style='margin:0; font-size:18px; color:#0f172a;'>" + (data.companyName || 'SafetyCheck Pro') + "</h1>";

    return "<html><head><style>" +
        "body { font-family: 'Helvetica Neue', Helvetica, Arial, sans-serif; font-size: 12px; color: #333; margin: 0; padding: 30px; }" +
        "table { width: 100%; border-collapse: collapse; margin-bottom: 20px; }" +
        ".header { display: flex; justify-content: space-between; align-items: center; border-bottom: 2px solid #0f172a; padding-bottom: 15px; margin-bottom: 20px; }" +
        ".meta-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 10px; margin-bottom: 25px; background: #f8fafc; padding: 15px; border-radius: 6px; border: 1px solid #e2e8f0; }" +
        ".meta-item { margin-bottom: 5px; }" +
        ".label { font-weight: 700; color: #64748b; font-size: 10px; text-transform: uppercase; display: block; margin-bottom: 2px; }" +
        ".val { font-weight: 600; font-size: 13px; color: #0f172a; }" +
        ".section-title { font-size: 13px; font-weight: 700; margin-top: 25px; margin-bottom: 10px; color: #0f172a; border-bottom: 1px solid #cbd5e1; padding-bottom: 5px; text-transform:uppercase; }" +
        ".score-box { text-align: right; }" +
        ".score { font-size: 24px; font-weight: 800; color: #0f172a; }" +
        "</style></head><body>" +

        "<table style='width:100%; border-bottom:2px solid #0f172a; padding-bottom:15px; margin-bottom:20px;'><tr>" +
            "<td style='vertical-align:middle;'>" + logoHtml + "</td>" +
            "<td style='text-align:right; vertical-align:middle;'>" +
                "<h2 style='margin:0; font-size:16px; color:#0f172a; text-transform:uppercase;'>" + data.title + "</h2>" +
                "<p style='margin:5px 0 0; color:#64748b; font-size:11px;'>Generated: " + new Date(data.timestamp).toLocaleString() + "</p>" +
            "</td>" +
        "</tr></table>" +

        "<table style='width:100%; background:#f8fafc; border:1px solid #e2e8f0; border-radius:6px; margin-bottom:20px;'>" +
            "<tr>" +
                "<td style='padding:15px; vertical-align:top; width:50%;'>" +
                    "<div class='label'>Vehicle Registration</div><div class='val'>" + data.truckNo + "</div>" +
                    "<div style='margin-top:10px;'><div class='label'>Trailer / Unit</div><div class='val'>" + data.trailerNo + "</div></div>" +
                    "<div style='margin-top:10px;'><div class='label'>Odometer</div><div class='val'>" + data.odometer + " km</div></div>" +
                "</td>" +
                "<td style='padding:15px; vertical-align:top; width:50%;'>" +
                    "<div class='label'>Location</div><div class='val'>" + data.location + "</div>" +
                    "<div style='margin-top:10px;'><div class='label'>Inspector</div><div class='val'>" + data.inspectedBy + "</div></div>" +
                    "<div style='margin-top:10px;'><div class='label'>Driver</div><div class='val'>" + data.driverName + "</div></div>" +
                "</td>" +
            "</tr>" +
        "</table>" +

        "<div class='section-title'>Inspection Checklist</div>" +
        "<table>" +
            itemsHtml +
        "</table>" +

        "<div class='section-title'>Inspector Remarks & Rating</div>" +
        "<div style='background:#fff; border:1px solid #e2e8f0; padding:15px; border-radius:4px; margin-bottom:20px;'>" +
            "<div class='label'>Remarks</div>" +
            "<p style='margin:5px 0 15px; font-size:13px; line-height:1.5;'>" + (data.remarks || 'No remarks provided.') + "</p>" +
            "<div style='border-top:1px solid #f1f5f9; padding-top:10px; display:flex; align-items:center; justify-content:space-between;'>" +
                "<strong>Overall Safety Rating:</strong>" +
                "<span style='font-size:16px; font-weight:bold; background:#0f172a; color:white; padding:4px 12px; border-radius:12px;'>" + data.rate + " / 5</span>" +
            "</div>" +
        "</div>" +

        "<table style='margin-top:30px; width:100%; border:0;'>" +
            "<tr>" +
                "<td style='text-align:center; padding:20px; border:0; width:50%; vertical-align:bottom;'>" + 
                    (data.signatures.inspector ? "<img src='" + data.signatures.inspector + "' style='height:40px; margin-bottom:5px;' /><br/>" : "<br/><br/>") + 
                    "<div style='border-top:1px solid #cbd5e1; width:80%; margin:0 auto; padding-top:5px; font-size:10px; color:#64748b; text-transform:uppercase;'>Inspector Signature</div>" +
                "</td>" +
                "<td style='text-align:center; padding:20px; border:0; width:50%; vertical-align:bottom;'>" + 
                    (data.signatures.driver ? "<img src='" + data.signatures.driver + "' style='height:40px; margin-bottom:5px;' /><br/>" : "<br/><br/>") + 
                    "<div style='border-top:1px solid #cbd5e1; width:80%; margin:0 auto; padding-top:5px; font-size:10px; color:#64748b; text-transform:uppercase;'>Driver Signature</div>" +
                "</td>" +
            "</tr>" +
        "</table>" +

        "<div style='text-align:center; font-size:10px; color:#94a3b8; margin-top:40px; border-top:1px solid #f1f5f9; padding-top:15px;'>" +
            "Generated by SafetyCheck Pro • " + new Date().getFullYear() +
        "</div>" +
        "</body></html>";
  }
};

