                  .setName(truckNo.replace(/\\s/g, '_') + '_' + moduleName + '_Report.pdf');

              blobs.push(pdfBlob);
              Logger.log(ss, "PDF_GENERATED", "Success: " + pdfBlob.getBytes().length + " bytes");
          } catch (e) {
              Logger.log(ss, "PDF_ERROR", e.toString());
          }
      } else {
          Logger.log(ss, "PDF_MISSING", "No reportData provided");
      }

      var subject = "Inspection Report: " + truckNo + " [" + statusText + "]";
      var senderName = "Alerts"; 
      var senderEmail = "notification@sallychanza.com";

      var emailOptions = {
          htmlBody: htmlBody,
          name: senderName, 
          attachments: blobs,
          bcc: recipients.slice(1).join(","),
          replyTo: senderEmail,
          from: senderEmail
      };

      try {
          GmailApp.sendEmail(recipients[0], subject, "HTML Required", emailOptions);
          Logger.log(ss, "EMAIL_SENT", "Method: GmailApp Alias");
      } catch (e1) {
          Logger.log(ss, "EMAIL_FAILURE", "Alias failed: " + e1.toString() + ". Please verify alias in Gmail Settings.");
      }

    } catch (err) {
        Logger.log(ss, "GLOBAL_EMAIL_ERROR", err.toString());
    }
  }
};

const PDFGenerator = {
  create: function(data) {
