          itemsHtml += "<tr><td style='border:1px solid black; text-align:center; padding:2px;'>" + no + "</td><td style='border:1px solid black; padding:2px 5px;'>" + text + "</td><td style='border:1px solid black; text-align:center;'>" + c + "</td><td style='border:1px solid black; text-align:center;'>" + nc + "</td><td style='border:1px solid black; text-align:center;'>" + ni + "</td><td style='border:1px solid black; text-align:center;'>" + na + "</td><td style='border:1px solid black; padding:2px 5px;'>" + (nc ? "NON-COMPLIANT" : "") + "</td></tr>";
