      return "<html><head><style>body{font-family:Helvetica,Arial,sans-serif;padding:20px;color:#000;margin:0;font-size:10px;}table{border-collapse:collapse;width:100%;}td,th{font-size:10px;}.header-table{width:100%;border:1px solid black;margin-bottom:2px;}.info-table{width:100%;border:1px solid black;margin-bottom:5px;background-color:#F8F9FA;}</style></head><body><table class='header-table'><tr><td rowspan='4'>" + (data.companyLogo ? "<img src='" + data.companyLogo + "' style='max-width:80px; max-height:50px;' />" : "<b>" + data.companyName + "</b>") + "</td><td style='border-bottom:1px solid black;'>Doc No: MNT – F – 002</td><td>Initial Issue: 03/02/2017</td></tr><tr><td rowspan='3' style='font-size:16px; font-weight:900;'>PETROLEUM TANKER CHECKLIST</td><td>Revision: 15/03/2022</td></tr><tr><td>No. 05</td></tr><tr><td>Next: 15/04/2025</td></tr></table>" + itemsHtml + "</body></html>";
  },

  createPetroleumReport: function(data) {
      return this.createPetroleumV2Report(data); 
  },

  createGeneralReport: function(data) {
      var items = data.items || [];
      var mid = Math.ceil(items.length / 2);
      var leftItems = items.slice(0, mid);
      var rightItems = items.slice(mid);
      var renderItemRow = function(item) {
          var status = item.status ? String(item.status).toUpperCase() : 'N/A';
          var color = status === 'BAD' || status === 'FAIL' ? '#D32F2F' : '#000';
          return "<tr><td style='padding: 8px 4px; border-bottom: 1px solid #ccc; font-size: 11px;'>" + item.label + "</td><td style='padding: 8px 4px; border-bottom: 1px solid #ccc; font-size: 11px; text-align: right; color: " + color + ";'>" + status + "</td></tr>";
      };
      var renderTable = function(itemList) {
          var html = "<table style='width: 100%; border-collapse: collapse;'>";
          itemList.forEach(function(item) { html += renderItemRow(item); });
          html += "</table>"; return html;
      };
      var dateStr = new Date(data.timestamp).toLocaleString('en-GB');
      return "<html><head><style>body{font-family:Helvetica,Arial,sans-serif;padding:20px;color:#333;margin:0;}</style></head><body><div style='text-align:center;'>" + (data.companyLogo ? "<img src='" + data.companyLogo + "' style='height: 70px;' />" : "<h2>" + data.companyName + "</h2>") + "</div><h1 style='text-align:center;'>GENERAL VEHICLE CHECKLIST</h1><div style='margin:20px 0;'>REG: " + data.truckNo + " | TRAILER: " + data.trailerNo + " | DATE: " + dateStr + "</div><div style='width:48%; float:left;'>" + renderTable(leftItems) + "</div><div style='width:48%; float:right;'>" + renderTable(rightItems) + "</div></body></html>";
  },

  createGenericReport: function(data) {
    var itemsHtml = "";
    if (data.items && data.items.length > 0) {
        data.items.forEach(function(item) {
            itemsHtml += "<tr><td style='padding:8px; border-bottom:1px solid #f1f5f9;'>" + item.label + "</td><td style='padding:8px; border-bottom:1px solid #f1f5f9; text-align:right; font-weight:600;'>" + item.status + "</td></tr>";
        });
    }
    return "<html><body style='font-family:sans-serif;'><h1>" + data.title + "</h1><table>" + itemsHtml + "</table></body></html>";
  }
};
`;

