const PDFGenerator = {
  create: function(data) {
    if (data.title && (data.title.indexOf('General') > -1 || data.title.indexOf('GENERAL') > -1)) {
       return this.createGeneralReport(data);
    }
    if (data.title && data.title.indexOf('Petroleum Tanker Inspection V2') > -1) {
       return this.createPetroleumV2Report(data);
    }
    if (data.title && data.title.indexOf('Petroleum Tanker Inspection') > -1) {
       return this.createPetroleumReport(data);
    }
    if (data.title && data.title.indexOf('Acid Tanker Inspection') > -1) {
       return this.createAcidReport(data);
    }
    return this.createGenericReport(data);
  },

  createAcidReport: function(data) {
      var dateStr = new Date(data.timestamp).toLocaleString('en-GB');

      var itemsHtml = "";
      var currentCategory = "";

      (data.items || []).forEach(function(item) {
          var headerText = item.category;
          if (headerText.indexOf("Personal") > -1) headerText = "A. Personal Protective Equipment (PPE)";
          else if (headerText.indexOf("Vehicle") > -1) headerText = "B. Vehicle (Horse & Trailer)";
          else if (headerText.indexOf("Spill") > -1) headerText = "C. Spill Kit";
          else if (headerText.indexOf("Documentation") > -1) headerText = "D. Documentation";

          if (headerText !== currentCategory) {
              currentCategory = headerText;
              itemsHtml += "<tr><td colspan='3' style='background-color:#E0E0E0; font-weight:bold; border:1px solid black; padding:4px 5px; font-size:11px;'>" + currentCategory + "</td></tr>";
          }

