        ".section-title { font-size: 13px; font-weight: 700; margin-top: 25px; margin-bottom: 10px; color: #0f172a; border-bottom: 1px solid #cbd5e1; padding-bottom: 5px; text-transform:uppercase; }" +
        ".score-box { text-align: right; }" +
        ".score { font-size: 24px; font-weight: 800; color: #0f172a; }" +
        "</style></head><body>" +

        "<table style='width:100%; border-bottom:2px solid #0f172a; padding-bottom:15px; margin-bottom:20px;'><tr>" +
            "<td style='vertical-align:middle;'>" + logoHtml + "</td>" +
            "<td style='text-align:right; vertical-align:middle;'>" +
                "<h2 style='margin:0; font-size:16px; color:#0f172a; text-transform:uppercase;'>" + data.title + "</h2>" +
                "<p style='margin:5px 0 0; color:#64748b; font-size:11px;'>Generated: " + new Date(data.timestamp).toLocaleString() + "</p>" +
            "</td>" +
        "</tr></table>" +

        "<table style='width:100%; background:#f8fafc; border:1px solid #e2e8f0; border-radius:6px; margin-bottom:20px;'>" +
            "<tr>" +
                "<td style='padding:15px; vertical-align:top; width:50%;'>" +
                    "<div class='label'>Vehicle Registration</div><div class='val'>" + data.truckNo + "</div>" +
                    "<div style='margin-top:10px;'><div class='label'>Trailer / Unit</div><div class='val'>" + data.trailerNo + "</div></div>" +
                    "<div style='margin-top:10px;'><div class='label'>Odometer</div><div class='val'>" + data.odometer + " km</div></div>" +
                "</td>" +
                "<td style='padding:15px; vertical-align:top; width:50%;'>" +
                    "<div class='label'>Location</div><div class='val'>" + data.location + "</div>" +
                    "<div style='margin-top:10px;'><div class='label'>Inspector</div><div class='val'>" + data.inspectedBy + "</div></div>" +
                    "<div style='margin-top:10px;'><div class='label'>Driver</div><div class='val'>" + data.driverName + "</div></div>" +
                "</td>" +
            "</tr>" +
        "</table>" +

        "<div class='section-title'>Inspection Checklist</div>" +
        "<table>" +
            itemsHtml +
        "</table>" +

        "<div class='section-title'>Inspector Remarks & Rating</div>" +
        "<div style='background:#fff; border:1px solid #e2e8f0; padding:15px; border-radius:4px; margin-bottom:20px;'>" +
            "<div class='label'>Remarks</div>" +
            "<p style='margin:5px 0 15px; font-size:13px; line-height:1.5;'>" + (data.remarks || 'No remarks provided.') + "</p>" +
            "<div style='border-top:1px solid #f1f5f9; padding-top:10px; display:flex; align-items:center; justify-content:space-between;'>" +
                "<strong>Overall Safety Rating:</strong>" +
                "<span style='font-size:16px; font-weight:bold; background:#0f172a; color:white; padding:4px 12px; border-radius:12px;'>" + data.rate + " / 5</span>" +
            "</div>" +
        "</div>" +

        "<table style='margin-top:30px; width:100%; border:0;'>" +
            "<tr>" +
                "<td style='text-align:center; padding:20px; border:0; width:50%; vertical-align:bottom;'>" + 
                    (data.signatures.inspector ? "<img src='" + data.signatures.inspector + "' style='height:40px; margin-bottom:5px;' /><br/>" : "<br/><br/>") + 
                    "<div style='border-top:1px solid #cbd5e1; width:80%; margin:0 auto; padding-top:5px; font-size:10px; color:#64748b; text-transform:uppercase;'>Inspector Signature</div>" +
                "</td>" +
                "<td style='text-align:center; padding:20px; border:0; width:50%; vertical-align:bottom;'>" + 
                    (data.signatures.driver ? "<img src='" + data.signatures.driver + "' style='height:40px; margin-bottom:5px;' /><br/>" : "<br/><br/>") + 
                    "<div style='border-top:1px solid #cbd5e1; width:80%; margin:0 auto; padding-top:5px; font-size:10px; color:#64748b; text-transform:uppercase;'>Driver Signature</div>" +
                "</td>" +
            "</tr>" +
        "</table>" +

        "<div style='text-align:center; font-size:10px; color:#94a3b8; margin-top:40px; border-top:1px solid #f1f5f9; padding-top:15px;'>" +
            "Generated by SafetyCheck Pro • " + new Date().getFullYear() +
        "</div>" +
        "</body></html>";
  }
};`;

export const BACKEND_FILES: Record<string, string> = {
    '1_Controller.gs': CODE_CONTROLLER,
    '2_AuthAndAdmin.gs': CODE_AUTH,
    '3_CoreOperations.gs': CODE_CORE_OPS,
    '4_SupportModule.gs': CODE_SUPPORT,
    '5_LibAndUtils.gs': CODE_LIB
};

export const BACKEND_SCRIPT_TEMPLATE = Object.values(BACKEND_FILES).join('\n\n');

import React, { useState, useEffect } from 'react';
import { SystemSettings, User } from '../types';
import { BACKEND_FILES } from '../constants';

interface SettingsViewProps {
    settings: SystemSettings;
    setSettings: React.Dispatch<React.SetStateAction<SystemSettings>>;
    appScriptUrl: string;
    setAppScriptUrl: (url: string) => void;
    handleSaveSettings: () => void;
    isSavingSettings: boolean;
    showToast: (msg: string, type: 'success' | 'error' | 'info' | 'warning') => void;
    user?: User | null;
}

const SettingsView: React.FC<SettingsViewProps> = ({ 
    settings, setSettings, appScriptUrl, setAppScriptUrl, handleSaveSettings, isSavingSettings, showToast, user 
}) => {
    const [logoError, setLogoError] = useState(false);
    const [selectedFile, setSelectedFile] = useState<string>('1_Controller.gs');
    const [copyStatus, setCopyStatus] = useState<string | null>(null);

    useEffect(() => { setLogoError(false); }, [settings.companyLogo]);

    const isSuperAdmin = user?.role === 'SuperAdmin';
    const canEditCompanySettings = isSuperAdmin || user?.role === 'Admin';

    const handleCopyCode = () => {
        const code = BACKEND_FILES[selectedFile];
        if (code) {
            navigator.clipboard.writeText(code).then(() => {
                setCopyStatus(selectedFile);
                showToast(`${selectedFile} copied to clipboard`, 'success');
                setTimeout(() => setCopyStatus(null), 3000);
            });
        }
    };

    return (
        <div className="max-w-4xl mx-auto animate-fadeIn space-y-8 pb-12">
             <h2 className="text-2xl font-bold text-gray-800 flex items-center gap-3">System Management</h2>

             {/* Company Profile Section */}
             <div className={`bg-white p-8 rounded-xl shadow-sm border border-gray-100 space-y-6 ${!canEditCompanySettings ? 'opacity-80 pointer-events-none' : ''}`}>
                <div className="flex justify-between items-center">
                    <h3 className="text-lg font-bold text-gray-800">Company Profile</h3>
                    {!canEditCompanySettings && (
                        <span className="text-[10px] font-bold text-amber-600 bg-amber-50 px-2 py-1 rounded border border-amber-100">READ ONLY</span>
                    )}
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div>
                        <label className="block text-[10px] font-bold text-gray-400 uppercase mb-2 tracking-widest">Organization Name</label>
                        <input type="text" placeholder="Company Name" value={settings.companyName} onChange={(e) => setSettings(s => ({...s, companyName: e.target.value}))} className="w-full p-3 bg-gray-50 border border-gray-300 rounded-lg font-bold text-gray-700 focus:ring-2 focus:ring-blue-100 outline-none transition-all" />
                    </div>
                    <div>
                        <label className="block text-[10px] font-bold text-gray-400 uppercase mb-2 tracking-widest">Administrative Email</label>
                        <input type="email" placeholder="Manager Email" value={settings.managerEmail} onChange={(e) => setSettings(s => ({...s, managerEmail: e.target.value}))} className="w-full p-3 bg-gray-50 border border-gray-300 rounded-lg font-bold text-gray-700 focus:ring-2 focus:ring-blue-100 outline-none transition-all" />
                    </div>
                </div>

                <div className="flex justify-end pt-2 border-t border-gray-100">
                     <button onClick={handleSaveSettings} disabled={isSavingSettings} className="px-8 py-3 bg-slate-900 hover:bg-black text-white rounded-xl font-bold shadow-lg flex items-center justify-center gap-2 transition-all active:scale-95 disabled:opacity-50 uppercase tracking-widest text-xs">
                        {isSavingSettings ? (
                            <svg className="animate-spin h-4 w-4 text-white" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                        ) : null}
                        {isSavingSettings ? 'Synchronizing...' : 'Save Configuration'}
                     </button>
                </div>
             </div>

             {/* Backend Code Modules Section */}
             {isSuperAdmin && (
                 <div className="bg-white p-8 rounded-xl shadow-sm border border-gray-100 space-y-6">
                    <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
                        <div>
                            <h3 className="text-lg font-bold text-gray-800">Backend Code Modules</h3>
                            <p className="text-xs text-gray-500 font-medium mt-1">Select and copy modules to your Google Apps Script editor.</p>
                        </div>
                        <div className="flex gap-2">
                             <select 
                                value={selectedFile} 
                                onChange={(e) => setSelectedFile(e.target.value)}
                                className="p-2.5 bg-gray-50 border border-gray-300 rounded-lg text-xs font-bold text-slate-700 outline-none focus:ring-2 focus:ring-blue-100"
                             >
                                {Object.keys(BACKEND_FILES).map(file => (
                                    <option key={file} value={file}>{file}</option>
                                ))}
                             </select>
                             <button 
                                onClick={handleCopyCode}
                                className="px-4 py-2 bg-indigo-600 hover:bg-indigo-700 text-white rounded-lg font-bold text-xs flex items-center gap-2 transition-all active:scale-95 shadow-md shadow-indigo-100"
                             >
                                {copyStatus === selectedFile ? (
                                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7"></path></svg>
                                ) : (
                                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M8 5H6a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2v-1M8 5a2 2 0 002 2h2a2 2 0 002-2M8 5a2 2 0 012-2h2a2 2 0 012 2m0 0h2a2 2 0 012 2v3m2 4H10m0 0l3-3m-3 3l3 3"></path></svg>
                                )}
                                {copyStatus === selectedFile ? 'Copied!' : 'Copy Module'}
                             </button>
                        </div>
                    </div>

                    <div className="relative group">
                        <textarea 
                            readOnly 
                            value={BACKEND_FILES[selectedFile] || ''} 
                            className="w-full h-80 p-6 bg-slate-50 border border-slate-200 rounded-xl font-mono text-[11px] leading-relaxed text-slate-600 focus:ring-0 outline-none scrollbar-hide resize-none"
                        />
                        <div className="absolute top-4 right-4 text-[9px] font-black text-slate-300 uppercase tracking-widest pointer-events-none group-hover:opacity-0 transition-opacity">
                            Read Only Editor
                        </div>
                        <div className="absolute inset-0 bg-gradient-to-t from-slate-50/50 to-transparent pointer-events-none h-12 bottom-0 top-auto"></div>
                    </div>

                    <div className="bg-blue-50 border border-blue-100 rounded-xl p-4 flex items-start gap-4">
                        <div className="w-8 h-8 bg-blue-100 rounded-lg flex items-center justify-center text-blue-600 shrink-0">
                            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
                        </div>
                        <div className="space-y-1">
                            <h4 className="text-xs font-bold text-blue-900 uppercase tracking-wide">Restore Instructions</h4>
                            <p className="text-[11px] text-blue-700 leading-relaxed font-medium">
                                To update your backend, copy each module and paste it into the corresponding file in your <a href="https://script.google.com" target="_blank" className="underline font-black hover:text-blue-900">Google Apps Script Project</a>. 
                                <br/>Ensure you <strong>Save</strong> and <strong>Deploy</strong> as a "New Version" after pasting all modules.
                            </p>
                        </div>
                    </div>
                 </div>
             )}

             {/* Server Connection Section */}
             {isSuperAdmin && (
                 <div className="bg-white p-8 rounded-xl shadow-sm border border-gray-100">
                    <h3 className="text-lg font-bold text-gray-800 mb-6 flex items-center gap-2">
                        <svg className="w-5 h-5 text-indigo-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M8 9l3 3-3 3m5 0h3M5 20h14a2 2 0 002-2V6a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z"></path></svg>
                        API Server Endpoint
                    </h3>
                    <div className="space-y-4">
                        <div className="relative">
                            <input 
                                type="text" 
                                value={appScriptUrl} 
                                onChange={(e) => setAppScriptUrl(e.target.value)} 
                                placeholder="https://script.google.com/macros/s/.../exec" 
                                className="w-full p-3.5 bg-gray-50 border border-gray-300 rounded-lg font-mono text-xs text-gray-600 focus:bg-white focus:ring-2 focus:ring-blue-100 outline-none transition-all" 
                            />
                            <div className="absolute right-3 top-1/2 -translate-y-1/2 flex items-center gap-2">
                                {appScriptUrl.startsWith('https://script.google.com') ? (
                                    <span className="text-[9px] font-black text-emerald-500 bg-emerald-50 px-1.5 py-0.5 rounded border border-emerald-100">VALID</span>
                                ) : (
                                    <span className="text-[9px] font-black text-red-500 bg-red-50 px-1.5 py-0.5 rounded border border-red-100">INVALID</span>
                                )}
                            </div>
                        </div>
                        <div className="flex justify-end pt-2">
                             <button onClick={handleSaveSettings} disabled={isSavingSettings} className="px-6 py-2.5 bg-indigo-600 hover:bg-indigo-700 text-white rounded-lg font-bold text-xs transition-all active:scale-95 shadow-lg shadow-indigo-100 flex items-center gap-2">
                                {isSavingSettings ? (
                                    <svg className="animate-spin h-3.5 w-3.5 text-white" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                                ) : null}
                                Update Core Link
                             </button>
                        </div>
                    </div>
                 </div>
             )}
        </div>
    );
}

export default SettingsView;
